window.SPECS = {"setup":{"module":"setup","display":"Configuração & Admin","functionalities":[{"group":"Gestão de Empresas","objetivo":"Cadastrar e administrar as empresas (entidades legais) do ERP, com criação automática de estruturas contábeis e operacionais básicas para cada nova empresa.","acoes":[{"nome":"setup-company","desc":"Cria uma nova empresa e auto-provisiona ano fiscal, centro de custo padrão e armazém padrão."},{"nome":"update-company","desc":"Atualiza campos da empresa (moeda, país, contas-padrão de AR/AP/receita/despesa, banco/caixa, inventário perpétuo, congelamento contábil)."},{"nome":"get-company","desc":"Retorna um registro de empresa (a primeira se nenhum id for passado)."},{"nome":"list-companies","desc":"Lista empresas paginadas, ordenadas por nome, com total_count."},{"nome":"set-advance-account","desc":"Configura a sub-conta de adiantamento (advance_from_customer/advance_to_supplier) usada no roteamento de pagamentos antecipados."}],"entradas":"setup-company: --name (obrigatório), --abbr, --currency, --country, --fiscal-year-start-month, --industry. update-company: --company-id + campos atualizáveis (default_*_account_id, --perpetual-inventory, --enable-negative-stock, --accounts-frozen-till-date). set-advance-account: --company-id, --account-id, --type (customer|supplier).","saidas":"setup-company retorna company_id, abbr, fiscal_year_id, cost_center_id, warehouse_id e (se --industry) onboard_profile/profile_modules/region_module. update-company retorna updated_fields. list-companies retorna companies[], total_count, has_more.","regras":"abbr derivada das iniciais do nome se não informada (fallback 3 primeiras letras). Ano fiscal calculado a partir do fiscal_year_start_month (jan->ano calendário; outro mês->12 meses). update-company rejeita contas-padrão que sejam grupo (is_group=1), exige conta folha. set-advance-account exige conta folha e root_type correto (liability p/ customer, asset p/ supplier). update-company sem campos retorna erro.","efeitos":"INSERT em company; setup-company também INSERT em fiscal_year, cost_center, warehouse e UPDATE company (default_cost_center_id/default_warehouse_id) — criações secundárias são não-fatais (best-effort). Grava audit_log (create/update). Nenhuma postagem em gl_entry ou stock_ledger_entry.","precondicoes":"Banco inicializado (initialize-database). Para update-company com contas-padrão, as contas (account) já devem existir e ser folha. set-advance-account exige empresa e conta existentes."},{"group":"Moedas e Câmbio","objetivo":"Manter o cadastro de moedas e as taxas de câmbio entre pares de moedas, com busca histórica e atualização automática via API externa.","acoes":[{"nome":"add-currency","desc":"Cadastra uma moeda (code, name, symbol, decimal_places, enabled)."},{"nome":"list-currencies","desc":"Lista moedas paginadas; --enabled-only filtra apenas habilitadas."},{"nome":"add-exchange-rate","desc":"Registra uma taxa de câmbio manual para um par/data."},{"nome":"get-exchange-rate","desc":"Retorna a taxa vigente de um par na data (ou a mais recente anterior)."},{"nome":"list-exchange-rates","desc":"Lista taxas com filtros por par e intervalo de datas."},{"nome":"fetch-exchange-rates","desc":"Busca taxas atuais na frankfurter.dev (base USD) e faz upsert com source='api'."}],"entradas":"add-currency: --code (obrigatório), --name, --symbol, --decimal-places, --enabled. add-exchange-rate: --from-currency, --to-currency, --rate (obrigatórios), --effective-date, --source. get/list-exchange-rates: --from-currency, --to-currency, --from-date, --to-date.","saidas":"add-currency: code, name. add-exchange-rate: exchange_rate_id, effective_date. get-exchange-rate: rate, effective_date, source. list-*: listas paginadas com total_count/has_more. fetch-exchange-rates: rates_updated, source, base, date.","regras":"code armazenado em maiúsculas; decimal_places default 2. Códigos de moeda duplicados são rejeitados. effective_date default = hoje (UTC); source default 'manual'. get-exchange-rate seleciona a taxa com effective_date <= data, ordenada desc (mais recente). fetch-exchange-rates fixa from='USD', effective_date=hoje e faz update se já existir o par+data, senão insert.","efeitos":"INSERT em currency e exchange_rate; fetch-exchange-rates faz INSERT/UPDATE em exchange_rate. Grava audit_log (create/fetch). fetch-exchange-rates realiza chamada HTTP externa (api.frankfurter.dev). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado. fetch-exchange-rates requer conexão à internet. add-exchange-rate funciona com quaisquer códigos (não valida FK contra currency)."},{"group":"Condições de Pagamento","objetivo":"Cadastrar condições/prazos de pagamento (dias para vencimento, descontos por antecipação) reutilizáveis em faturas de venda e compra.","acoes":[{"nome":"add-payment-terms","desc":"Cria uma condição de pagamento com prazo, percentual e dias de desconto."},{"nome":"list-payment-terms","desc":"Lista condições paginadas, ordenadas por due_days e nome."}],"entradas":"add-payment-terms: --name (obrigatório), --due-days (default 30), --discount-percentage, --discount-days, --description. list-payment-terms: --limit, --offset.","saidas":"add-payment-terms: payment_terms_id, name. list-payment-terms: terms[], total_count, limit, offset, has_more.","regras":"Nome duplicado é rejeitado (IntegrityError). due_days default 30 quando não informado; demais campos opcionais. Somente cadastro/listagem (sem ciclo rascunho/submit).","efeitos":"INSERT em payment_terms. Grava audit_log (create). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado."},{"group":"Unidades de Medida","objetivo":"Manter unidades de medida (UoM) e fatores de conversão entre elas, opcionalmente específicos por item, para uso em estoque, vendas e compras.","acoes":[{"nome":"add-uom","desc":"Cria uma unidade de medida; --must-be-whole-number força quantidades inteiras."},{"nome":"list-uoms","desc":"Lista UoMs paginadas, ordenadas por nome."},{"nome":"add-uom-conversion","desc":"Registra um fator de conversão entre duas UoMs, opcionalmente vinculado a um item."}],"entradas":"add-uom: --name (obrigatório), --must-be-whole-number. add-uom-conversion: --from-uom, --to-uom, --conversion-factor (obrigatórios), --item-id.","saidas":"add-uom: uom_id, name. add-uom-conversion: uom_conversion_id. list-uoms: uoms[], total_count, has_more.","regras":"Nome de UoM duplicado é rejeitado. add-uom-conversion exige os três campos; falha de integridade (duplicidade/dados inválidos) retorna erro. --item-id opcional permite conversão específica do item.","efeitos":"INSERT em uom e uom_conversion. Grava audit_log (create). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado. As UoMs referenciadas na conversão devem existir como cadastro (não há FK forte verificada no código)."},{"group":"Usuários e Acessos (RBAC)","objetivo":"Gerenciar contas de usuário do ERP, seu vínculo a empresas, senha de login web e atribuição/revogação de papéis para controle de acesso.","acoes":[{"nome":"add-user","desc":"Cria um usuário (username via --name), e-mail e nome completo, opcionalmente vinculado a uma empresa."},{"nome":"update-user","desc":"Atualiza username/e-mail/nome/status e anexa empresa à lista company_ids."},{"nome":"list-users","desc":"Lista usuários paginados, ordenados por username."},{"nome":"get-user","desc":"Retorna um usuário com seus papéis (join user_role/role/company)."},{"nome":"set-password","desc":"Define a senha de login web do usuário (hash armazenado)."},{"nome":"assign-role","desc":"Atribui um papel a um usuário, opcionalmente com escopo de empresa."},{"nome":"revoke-role","desc":"Remove a atribuição de um papel de um usuário (NULL-safe por empresa)."}],"entradas":"add-user: --name (username), --email, --full-name, --company-id. update-user: --user-id + campos + --user-status (active|disabled|locked). set-password: --user-id, --password (>=8). assign/revoke-role: --user-id, --role-name, --company-id (NULL=global).","saidas":"add-user/update-user: user_id, updated_fields. get-user: registro do usuário + roles[]. set-password: mensagem de sucesso. assign-role: user_role_id, role_name, company_id. revoke-role: revoked, user_id.","regras":"username único (rejeita duplicado). Formato de e-mail validado por regex. user-status restrito a active/disabled/locked. company_ids é JSON-array (append sem duplicar). set-password exige >=8 caracteres e grava password_hash. assign-role usa comparação NULL-safe (company_id IS ?) e rejeita atribuição já existente; revoke-role erra se não houver atribuição.","efeitos":"INSERT/UPDATE em erp_user; INSERT/DELETE em user_role; set-password faz UPDATE de password_hash (via passwords.hash_password). Grava audit_log (add-user/update-user/set-password/assign-role/revoke-role). Nenhuma postagem em gl_entry/SLE. O RBAC é opt-in: a criação de usuários ativa a checagem de permissões no sistema.","precondicoes":"Banco inicializado. assign-role exige usuário e papel existentes (papéis-sistema vêm seeded). set-password exige usuário existente. company_id opcional deve referenciar empresa válida."},{"group":"Papéis e Permissões","objetivo":"Definir papéis (roles) e a matriz de permissões skill/ação que governa o que cada papel pode executar, incluindo o carregamento das permissões padrão.","acoes":[{"nome":"add-role","desc":"Cria um papel customizado (is_system=0) com nome e descrição."},{"nome":"list-roles","desc":"Lista papéis com contagem de usuários, papéis-sistema primeiro."},{"nome":"seed-permissions","desc":"Popula role_permission com a matriz padrão por papel (idempotente)."}],"entradas":"add-role: --name (obrigatório), --description. list-roles: sem parâmetros. seed-permissions: sem parâmetros.","saidas":"add-role: role_id, name. list-roles: roles[] (com user_count), count. seed-permissions: permissions_seeded (total na tabela).","regras":"Nome de papel duplicado é rejeitado. Resolução de permissão: sem erp_user => permite tudo (RBAC inativo); papel 'System Manager' => permite tudo (padrão '*','*'); senão casa skill+action_pattern (wildcards fnmatch como list-*, submit-*, *); sem regra => nega. seed-permissions usa INSERT OR IGNORE por papel/skill/pattern, sendo idempotente.","efeitos":"INSERT em role; seed-permissions faz INSERT OR IGNORE em role_permission. add-role grava audit_log (add-role). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado. seed-permissions depende dos papéis já existirem (papéis-sistema seeded no init_db) — pula papéis ausentes."},{"group":"Integração Telegram","objetivo":"Vincular contas de usuário do ERP a IDs numéricos do Telegram e verificar permissões de ações executadas via bot do Telegram.","acoes":[{"nome":"link-telegram-user","desc":"Vincula um ID numérico do Telegram a um usuário do ERP."},{"nome":"unlink-telegram-user","desc":"Remove o vínculo de Telegram do usuário."},{"nome":"check-telegram-permission","desc":"Verifica se o usuário Telegram tem permissão para uma skill/ação."}],"entradas":"link: --user-id, --telegram-user-id (obrigatórios). unlink: --telegram-user-id. check: --telegram-user-id, --skill, --check-action (obrigatórios).","saidas":"link/unlink: user_id, telegram_user_id, linked/unlinked. check: allowed (bool), user_id, skill, action; se não vinculado retorna allowed=false com reason='not_linked'.","regras":"Um telegram_user_id não pode estar vinculado a outro usuário (rejeita conflito). unlink erra se não houver usuário vinculado. check resolve telegram_user_id->erp_user (apenas status='active') e aplica check_permission; se não vinculado, nega sem erro.","efeitos":"UPDATE em erp_user (campo telegram_user_id set/clear). Grava audit_log (link/unlink). check-telegram-permission é somente leitura. Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado. link exige usuário existente. check pressupõe RBAC povoado (papéis/permissões seeded) para resultado significativo; com RBAC inativo permite tudo."},{"group":"Credenciais de Integração","objetivo":"Armazenar e gerenciar de forma criptografada as credenciais (API keys) de integrações externas, substituindo a passagem de --api-key em linha de comando.","acoes":[{"nome":"set-credential","desc":"Grava uma credencial de integração no arquivo criptografado (valor via --value, --from-stdin ou --from-env)."},{"nome":"get-credential","desc":"Informa se uma credencial existe e um preview redigido; nunca retorna o valor."},{"nome":"list-credentials","desc":"Lista apenas os nomes de integração com credencial armazenada."},{"nome":"delete-credential","desc":"Remove uma credencial armazenada."},{"nome":"migrate-credentials","desc":"Migra credenciais em texto puro de tabelas de add-ons (ex.: stripe_account.api_key) para o store criptografado; --dry-run pré-visualiza."}],"entradas":"set-credential: --integration + (--value | --from-stdin | --from-env VAR). get/delete-credential: --integration. migrate-credentials: --dry-run.","saidas":"set: mensagem, integration, credentials_file. get: integration, exists, redacted_preview. list: integrations[]. delete: deleted (bool). migrate: dry_run, moved[], skipped[].","regras":"O valor nunca é aceito via --api-key e nunca é retornado por get/list. set-credential sobrescreve entrada existente. migrate-credentials pula integrações já no store e, fora de dry-run, anula a coluna de origem após mover. get-credential exige valor com >=12 chars para mostrar preview.","efeitos":"Grava/lê o arquivo criptografado ~/.config/erpclaw/credentials.json.enc (AES-256-GCM, mode 0600), criptografado com a master key da máquina. migrate-credentials faz UPDATE nas tabelas de add-on (ex.: stripe_account.api_key=NULL) e commit. NÃO grava em audit_log. Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado. Master key disponível/gerada automaticamente (~/.config/erpclaw/master.key). migrate-credentials requer as tabelas de add-on presentes (tolerado se ausentes)."},{"group":"Campos Personalizados (UDF)","objetivo":"Permitir que administradores estendam tabelas-núcleo com campos definidos pelo usuário (UDF), com validação de tipo, e armazenem/recuperem seus valores por linha.","acoes":[{"nome":"add-custom-field","desc":"Registra a definição de um campo personalizado em uma tabela-núcleo (tipo, label, required, default, options)."},{"nome":"list-custom-fields","desc":"Lista definições de campos personalizados, opcionalmente por --table."},{"nome":"remove-custom-field","desc":"Remove a definição e seus valores armazenados (hard delete, exige --confirm se houver valores)."},{"nome":"set-custom-field-value","desc":"Define um valor de campo personalizado em uma linha, com validação."},{"nome":"get-custom-field-values","desc":"Retorna os valores personalizados de uma linha (todos ou um campo)."}],"entradas":"add: --table, --field-name, --field-type (text|int|float|date|select|link|json), --label, --required, --default, --options, --skill-name. remove: --table, --field-name, --confirm. set-value: --table, --row-id, --field-name, --value. get-values: --table, --row-id, --field-name.","saidas":"add: custom_field_id, table, field_name, field_type. list: custom_fields[], count. remove: deleted_values. set-value: stored. get-values: custom_fields{}.","regras":"field-type restrito à lista válida. options: select -> JSON {values:[...]} a partir de lista por vírgula; link -> {table:...}; outros -> JSON bruto. Campo duplicado na mesma tabela é rejeitado. remove com valores existentes exige --confirm e checa owner_skill (rejeita por mismatch). set-value valida o valor (validate_custom_field_values) antes de gravar.","efeitos":"INSERT/DELETE em custom_field e INSERT/DELETE/UPSERT em custom_field_value (via lib custom_fields). add/remove gravam audit_log (create/delete); set-value não grava audit. Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado e tabelas custom_field/custom_field_value presentes. A tabela-alvo (--table) e a linha (--row-id) devem existir para set/get de valores."},{"group":"Registros de Tipos e Status","objetivo":"Administrar em runtime os registros que são fonte de verdade para tipos de conta, tipos de comprovante (voucher) e validar a completude desses registros frente aos dados vivos.","acoes":[{"nome":"add-account-type","desc":"Registra um novo account_type para que contas possam usá-lo."},{"nome":"list-account-types","desc":"Lista account_types ativos (ou todos com --include-inactive)."},{"nome":"deactivate-account-type","desc":"Soft-disable de account_type (bloqueado se alguma conta o usa)."},{"nome":"add-voucher-type","desc":"Registra um voucher_type para uma tabela-alvo (gl_entry|stock_ledger_entry|payment_allocation)."},{"nome":"list-voucher-types","desc":"Lista voucher_types, opcionalmente por --target-table."},{"nome":"deactivate-voucher-type","desc":"Soft-disable de voucher_type por tabela-alvo (bloqueado se linhas vivas o usam)."},{"nome":"validate-registry-completeness","desc":"Diagnóstico read-only: valores de tipo/status presentes em dados vivos mas não registrados+ativos."}],"entradas":"add-account-type: --account-type, --label, --skill-name. add-voucher-type: --voucher-type, --target-table (lista fixa), --label, --skill-name. deactivate-*: o respectivo tipo (+ --target-table). list-*: --include-inactive, --target-table.","saidas":"add-*: result='registered' + valores. list-*: listas + count. deactivate-*: result='deactivated'. validate-registry-completeness: complete (bool), unregistered_in_use{} por categoria.","regras":"Tipo já registrado é rejeitado. target_table de voucher restrita a gl_entry/stock_ledger_entry/payment_allocation. deactivate bloqueia se houver account/linha usando o tipo (conta COUNT na tabela alvo). validate cruza valores DISTINCT em account/gl_entry/payment_entry/payment_ledger_entry/asset contra os registros ativos; novos writes com valores não registrados+ativos seriam rejeitados.","efeitos":"INSERT/UPDATE em account_type_registry e voucher_type_registry (is_active). add/deactivate gravam audit_log (create/update). validate-registry-completeness é somente leitura. Nenhuma postagem em gl_entry/SLE (apenas leitura dessas tabelas para contagem).","precondicoes":"Banco inicializado com as tabelas de registro (M0). deactivate exige que nenhuma linha viva use o valor."},{"group":"Backup e Restauração","objetivo":"Criar, listar, verificar e restaurar backups da base SQLite, com suporte a criptografia AES-256, política de retenção e rollback de segurança na restauração.","acoes":[{"nome":"backup-database","desc":"Cria backup da base, opcionalmente criptografado (--encrypt --passphrase) com master key embutida."},{"nome":"list-backups","desc":"Lista arquivos de backup (.sqlite e .enc) com tamanho, data e flag de criptografia."},{"nome":"verify-backup","desc":"Valida um backup sem restaurar (SQLite válido, assinatura ERPClaw, integrity_check)."},{"nome":"restore-database","desc":"Restaura a base de um backup, com backup de segurança prévio e rollback em caso de falha."},{"nome":"cleanup-backups","desc":"Remove backups antigos por retenção (7 diários, 4 semanais, 12 mensais)."}],"entradas":"backup-database: --db-path, --backup-path, --encrypt, --passphrase. verify/restore: --backup-path, --passphrase (se .enc). cleanup-backups: sem parâmetros.","saidas":"backup: backup_path, size_bytes, encrypted, carries_master_key, timestamp. list: backups[], count, total_size_bytes. verify: valid, integrity, tables, schema_version, encrypted. restore: restored_from, safety_backup, integrity, was_encrypted. cleanup: kept, deleted, freed_bytes.","regras":"--encrypt exige --passphrase. Backups criptografados (ECRYPT02) embutem a master key envelopada para restauração cross-machine. verify exige schema_version e integrity_check='ok'. restore valida o backup, cria safety backup, copia sobre a base e reverifica; qualquer falha faz rollback para o safety backup. cleanup aplica retenção diária/semanal/mensal só a arquivos erpclaw_backup_*.sqlite.","efeitos":"Cria/copia/remove arquivos no diretório de backups (~/.openclaw/erpclaw/backups), com chmod 600. restore-database FECHA a conexão atual, SOBRESCREVE o arquivo data.sqlite e reaplica chmod nos arquivos da base (substituição total dos dados). cleanup/restore gravam audit_log (cleanup; backup/restore não gravam audit). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco existente para backup. restore/verify exigem arquivo de backup válido e --passphrase para criptografados. Permissões de escrita no diretório de backups e na base."},{"group":"Schema e Migrações","objetivo":"Inicializar/reinicializar o schema completo do banco e aplicar migrações de evolução de schema registradas em um ledger idempotente.","acoes":[{"nome":"initialize-database","desc":"Cria todas as tabelas, índices e constraints (CREATE IF NOT EXISTS); --force dropa e recria."},{"nome":"migrate","desc":"Executa migrações pendentes (migrations/NNN_*.py) registrando cada uma no ledger; --dry-run lista sem aplicar."},{"nome":"get-schema-version","desc":"Lê a versão de schema registrada para um módulo."}],"entradas":"initialize-database: --db-path, --force. migrate: --db-path, --dry-run. get-schema-version: --module (default 'erpclaw-setup').","saidas":"initialize-database: message, db_path, tables, indexes, skills_registered, journal_mode='WAL', foreign_keys='ON', reinitialized. migrate: resultado do runner (aplicadas/pendentes). get-schema-version: module, version, updated_at.","regras":"initialize-database é seguro em base existente (IF NOT EXISTS); --force exige remoção do arquivo antes de recriar. migrate é idempotente e dialect-aware, gravando no ledger erpclaw_schema_migration; falha de uma migração aborta com detalhe. Ambas gerenciam suas próprias conexões (não usam a conexão padrão do router).","efeitos":"initialize-database cria o symlink da lib compartilhada, executa o DDL completo e aplica chmod 600 (data.sqlite, -wal, -shm); com --force REMOVE o arquivo da base existente. migrate altera estrutura de tabelas (rebuilds) e insere linhas no ledger de migração. Nenhuma postagem em gl_entry/SLE; não grava audit_log.","precondicoes":"Diretório/permissões de escrita da base. Módulo init_schema e migration_runner co-localizados. get-schema-version exige a tabela schema_version povoada."},{"group":"Dados Padrão e Onboarding","objetivo":"Carregar dados-semente padrão (moedas, UoMs, condições de pagamento) e conduzir a configuração inicial via tutorial demo ou wizard interativo de onboarding.","acoes":[{"nome":"seed-defaults","desc":"Carrega seeds padrão de currency/uom/payment_terms a partir dos assets JSON (idempotente)."},{"nome":"tutorial","desc":"Cria a empresa demo 'Acme Corp' com plano de contas mínimo, centro de custo e ano fiscal (idempotente)."},{"nome":"onboarding-step","desc":"Wizard interativo state-machine (nome->moeda->mês fiscal->demo) que ao final cria empresa, seeds e plano de contas."}],"entradas":"seed-defaults: --company-id (default 1ª empresa). tutorial: sem parâmetros. onboarding-step: --answer (resposta do passo), --reset (reinicia do passo 1).","saidas":"seed-defaults: currencies_seeded, uoms_seeded, payment_terms_seeded. tutorial: company_id, accounts_created, fiscal_year, cost_center, next_steps[]. onboarding-step: step, completed, prompt, options, field e (no fim) results com steps_completed/steps_failed.","regras":"seed-defaults usa INSERT OR IGNORE (não duplica). tutorial é idempotente: se 'Acme Corp' existe, retorna dados existentes. onboarding valida moeda (lista fixa USD/EUR/GBP/CAD/INR/SGD/AED) e mês 1-12; persiste estado em arquivo JSON; no passo final dispara subprocessos (setup-company, seed-defaults, setup-chart-of-accounts via erpclaw-gl, seed-demo-data) registrando sucesso/falha por passo.","efeitos":"seed-defaults: INSERT OR IGNORE em currency/uom/payment_terms + audit_log (seed). tutorial: INSERT em company/account (plano de contas)/cost_center/fiscal_year + UPDATE contas-padrão + audit_log (create). onboarding: grava arquivo de estado ~/.openclaw/erpclaw/onboarding_state.json e executa db_query.py de outras skills via subprocess. Nenhuma postagem direta em gl_entry/SLE.","precondicoes":"Banco inicializado. seed-defaults exige uma empresa existente e os arquivos de assets (currencies.json, default_uom.json, default_payment_terms.json). onboarding com demo depende das skills erpclaw-gl/erpclaw presentes (passos faltantes são reportados como falhos, não fatais)."},{"group":"Config. Regionais/Avançadas","objetivo":"Definir configurações regionais por empresa (formato de data/número, template de imposto padrão) persistidas com upsert por chave.","acoes":[{"nome":"update-regional-settings","desc":"Define/atualiza configurações regionais da empresa (date_format, number_format, default_tax_template_id) via upsert chave/valor."}],"entradas":"--company-id (default 1ª empresa), --date-format, --number-format, --default-tax-template-id.","saidas":"updated: lista das chaves atualizadas.","regras":"Sem nenhuma configuração informada retorna erro. Cada par chave/valor é gravado por UPSERT em regional_settings com ON CONFLICT(company_id, key) atualizando value e updated_at. Default para a primeira empresa quando --company-id ausente.","efeitos":"INSERT/UPSERT em regional_settings. Grava audit_log (update). Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado e ao menos uma empresa existente. default_tax_template_id deve referenciar um template de imposto válido se usado por outras skills."},{"group":"Auditoria/Status/Chave-Mestra","objetivo":"Consultar a trilha de auditoria, reportar o status geral do sistema e gerenciar a chave-mestra de criptografia em cenários de restauração entre máquinas.","acoes":[{"nome":"get-audit-log","desc":"Consulta a trilha de auditoria com filtros por entidade, ação e período."},{"nome":"status","desc":"Reporta contagens de empresas, moedas habilitadas, UoMs, condições de pagamento e versões de schema."},{"nome":"import-master-key-from-backup","desc":"Extrai e instala a chave-mestra envelopada de um backup ECRYPT02 (restauração cross-machine)."}],"entradas":"get-audit-log: --entity-type, --entity-id, --audit-action, --from-date, --to-date, --limit (default 50). status: sem parâmetros. import-master-key-from-backup: --backup-path + passphrase (--passphrase | --passphrase-from-stdin | --passphrase-from-env VAR), --force.","saidas":"get-audit-log: entries[] (com old_values/new_values em JSON parseado), ordenadas desc por timestamp. status: companies, currencies, uoms, payment_terms, schema_versions{}. import-master-key: message, master_key_path, next.","regras":"get-audit-log e status são somente leitura. import-master-key exige backup formato ECRYPT02 que carregue a chave envelopada; desenvelopa com a passphrase (erra se não casar); recusa sobrescrever chave existente sem --force (overwrite invalida dados encriptados pela chave antiga).","efeitos":"get-audit-log e status: nenhum (somente leitura). import-master-key-from-backup: lê o header do backup e ESCREVE o arquivo ~/.config/erpclaw/master.key (mode 0600), opcionalmente removendo a chave existente com --force; não grava audit_log. Nenhuma postagem em gl_entry/SLE.","precondicoes":"Banco inicializado para status/audit. import-master-key exige arquivo de backup ECRYPT02 acessível com chave-mestra embutida (backups de fundação >= v4.1.3) e a passphrase usada no envelopamento."}]},"gl":{"module":"gl","display":"Contabilidade (Razão Geral / GL)","functionalities":[{"group":"Plano de Contas","objetivo":"Criar e manter o plano de contas (hierárquico, com tipos raiz e tipos de conta) de uma empresa, por template pronto ou conta a conta.","acoes":[{"nome":"setup-chart-of-accounts","desc":"Carrega um plano de contas a partir de um template JSON (ex.: us_gaap) em assets/charts/, criando as contas que ainda não existem."},{"nome":"add-account","desc":"Cria uma conta individual com tipo raiz, tipo de conta, pai, moeda e flag de grupo."},{"nome":"update-account","desc":"Atualiza campos editáveis da conta (name, account_number, parent_id, is_frozen)."},{"nome":"list-accounts","desc":"Lista contas da empresa com filtros (root_type, account_type, is_group, parent_id, search) e paginação."},{"nome":"get-account","desc":"Retorna uma conta com seu saldo calculado (débito/crédito totais e saldo conforme balance_direction) na data de corte."}],"entradas":"--company-id/--company, --template; ou --name, --root-type (asset|liability|equity|income|expense), --account-type, --account-number, --parent-id, --currency, --is-group; --account-id; filtros --root-type/--account-type/--parent-id/--search/--include-frozen/--limit/--offset; --as-of-date (get-account).","saidas":"setup: accounts_created, template, company_id. add: account_id, name, account_number. update: updated_fields. list: accounts[], total_count, has_more. get: account com balance, debit_total, credit_total.","regras":"root_type define balance_direction (liability/equity/income = credit_normal; demais debit_normal). account_type deve estar registrado e ativo em account_type_registry. Tipos LEAF_ONLY (receivable, payable, bank, cash, tax, cost_of_goods_sold, stock, depreciation, accumulated_depreciation, round_off) não podem ser grupo. depth derivado do pai. setup ignora contas já existentes (idempotente por account_number). update bloqueia troca de root_type/account_type quando há gl_entry não cancelado (checa has_entries).","efeitos":"Escrita em account (insert/update). Auditoria em audit_log via audit() para create/import/update. Nenhuma postagem em gl_entry. Commit ao final.","precondicoes":"Empresa existente (tabela company). Para template, arquivo assets/charts/<template>.json. Para account_type não nulo, tipo previamente registrado (account_type_registry / seed-registry-defaults). Pai existente quando --parent-id informado."},{"group":"Congelamento de Contas","objetivo":"Congelar/descongelar uma conta para impedir novas postagens nela, controle de bloqueio contábil em nível de conta.","acoes":[{"nome":"freeze-account","desc":"Marca a conta como congelada (is_frozen=1)."},{"nome":"unfreeze-account","desc":"Remove o congelamento da conta (is_frozen=0)."}],"entradas":"--account-id (obrigatório).","saidas":"status=updated, account_id, is_frozen (true/false).","regras":"Conta deve existir. Postar em conta congelada é bloqueado na validação de GL (Step 4): exige que o context_role da postagem seja igual a company.role_allowed_for_frozen_entries, senão a postagem falha. is_frozen também pode ser alterado via update-account.","efeitos":"Update em account.is_frozen e updated_at. Auditoria (freeze/unfreeze) em audit_log. Commit. Não cria nem cancela gl_entry; apenas restringe postagens futuras.","precondicoes":"Conta existente. Para que a exceção de postagem em conta congelada funcione, a empresa precisa ter role_allowed_for_frozen_entries configurado."},{"group":"Lançamentos no Razão","objetivo":"Registrar (postar), estornar e consultar lançamentos contábeis em gl_entry, com partida dobrada e cadeia de integridade.","acoes":[{"nome":"post-gl-entries","desc":"Posta um conjunto de lançamentos balanceados para um voucher (valida via checklist de 12+ passos e insere)."},{"nome":"reverse-gl-entries","desc":"Estorna todos os lançamentos ativos de um voucher criando entradas espelho (débito/crédito trocados) e marcando os originais como cancelados."},{"nome":"list-gl-entries","desc":"Lista lançamentos com filtros por conta, voucher, parte, intervalo de datas e is_cancelled, com nome da conta."}],"entradas":"post: --voucher-type, --voucher-id, --posting-date, --company-id, --entries (JSON array com account_id/debit/credit e opcionais party_type/party_id/cost_center_id/dimensions). reverse: --voucher-type, --voucher-id, --posting-date (default hoje). list: --account-id, --voucher-type, --voucher-id, --party-type/--party-id, --from-date/--to-date, --is-cancelled, --limit/--offset.","saidas":"post: gl_entry_ids, entries_created, warnings (ex.: orçamento). reverse: reversed_count, reversal_entry_ids. list: entries[] (com account_name), total_count, has_more.","regras":"voucher_type canonicalizado (snake_case) na fronteira. Validação obrigatória: partida dobrada (débito=crédito), conta não grupo/não desabilitada, afinidade conta-empresa, conta não congelada (ou role), parte obrigatória em receivable/payable, cost_center obrigatório em income/expense, lançamentos de abertura sem P&L, validação de cost center, ano fiscal aberto, data de congelamento, filtragem de linhas zero, checagem de orçamento, dimensões obrigatórias. Idempotência por (voucher_type, voucher_id, entry_set). Cancelamento é por estorno (não delete); reversal preserva entry_set, cost_center, dimensões.","efeitos":"INSERT em gl_entry (com gl_checksum SHA-256 encadeado por empresa, debit_base/credit_base calculados quando exchange_rate!=1, dimensions_json canônico). reverse: insere espelhos e faz UPDATE is_cancelled=1 nos originais. Auditoria (post/reverse). Commit. Não toca stock_ledger_entry nem payment_ledger_entry diretamente.","precondicoes":"Empresa, contas e (quando aplicável) cost centers/partes existentes. Ano fiscal aberto cobrindo a posting_date. voucher_type ativo em voucher_type_registry (target_table=gl_entry); party_type ativo em party_type_registry. Para reverse, lançamentos ativos do voucher."},{"group":"Saldos de Conta","objetivo":"Consultar o saldo de uma conta numa data de corte, opcionalmente filtrado por parte, respeitando a direção normal do saldo.","acoes":[{"nome":"get-account-balance","desc":"Calcula débito total, crédito total e saldo de uma conta até a data informada, com filtro opcional por parte."}],"entradas":"--account-id (obrigatório), --as-of-date (obrigatório), --party-type, --party-id (opcionais).","saidas":"balance, debit_total, credit_total, currency.","regras":"Soma apenas lançamentos com is_cancelled=0 e posting_date <= as_of_date. Saldo = débito-crédito quando balance_direction=debit_normal; crédito-débito quando credit_normal. Conta deve existir.","efeitos":"Nenhum (somente leitura).","precondicoes":"Conta existente; lançamentos em gl_entry para haver saldo."},{"group":"Anos Fiscais","objetivo":"Definir e listar os anos fiscais (períodos contábeis) de uma empresa, base para validação de período de postagem e fechamento.","acoes":[{"nome":"add-fiscal-year","desc":"Cria um ano fiscal com nome e intervalo de datas, validando que não haja sobreposição."},{"nome":"list-fiscal-years","desc":"Lista os anos fiscais da empresa (mais recente primeiro) com paginação."}],"entradas":"add: --name, --start-date, --end-date, --company-id. list: --company-id/--company, --limit, --offset.","saidas":"add: fiscal_year_id, name. list: fiscal_years[], total_count, has_more.","regras":"Datas não podem se sobrepor a um ano fiscal existente da mesma empresa (falha apontando o ano em conflito). is_closed começa em 0 (aberto). O ano fiscal aberto cobrindo a posting_date é exigido na validação de qualquer postagem (Step 9).","efeitos":"INSERT em fiscal_year. Auditoria (create). Commit. Sem postagens em gl_entry.","precondicoes":"Empresa existente."},{"group":"Fechamento de Período","objetivo":"Validar, fechar e reabrir o ano fiscal, transferindo o resultado líquido (P&L) para a conta de lucros acumulados via lançamentos de fechamento.","acoes":[{"nome":"validate-period-close","desc":"Calcula receita, despesa, resultado líquido do período e verifica se o balancete está balanceado (sem alterar nada)."},{"nome":"close-fiscal-year","desc":"Cria o período de fechamento (period_closing_voucher), zera contas de receita/despesa contra a conta de equity e marca o ano como fechado."},{"nome":"reopen-fiscal-year","desc":"Reabre o ano fiscal, cancela os lançamentos do PCV e marca o PCV como cancelled."}],"entradas":"validate/reopen: --fiscal-year-id. close: --fiscal-year-id, --closing-account-id (conta equity / lucros acumulados), --posting-date.","saidas":"validate: income_total, expense_total, net_income, trial_balance_balanced. close: pcv_id, net_pl_transferred, gl_entries_created, fiscal_year_closed. reopen: is_closed=false, pcv_reversed.","regras":"Ano não pode estar já fechado (close) nem aberto (reopen). Conta de fechamento deve ser root_type=equity e pertencer à MESMA empresa do ano fiscal (ADR-0016, hard-fail antes de qualquer postagem). net_pl = receita - despesa. _close_pl_accounts zera cada conta de income/expense (não grupo, com saldo) postando o par contra a conta de equity. Reabertura cancela lançamentos do voucher_type period_closing do PCV submitted.","efeitos":"close: INSERT em period_closing_voucher (status submitted) e múltiplos INSERT em gl_entry (voucher_type=period_closing, em USD), UPDATE fiscal_year.is_closed=1. reopen: UPDATE gl_entry.is_cancelled=1 dos lançamentos do PCV, UPDATE period_closing_voucher.status=cancelled, UPDATE fiscal_year.is_closed=0. Auditoria (close/reopen). validate: nenhum (somente leitura). Commit nas ações de escrita.","precondicoes":"Ano fiscal existente. Para close: conta equity da mesma empresa e posting_date. Contas de receita/despesa com lançamentos no período."},{"group":"Centros de Custo","objetivo":"Cadastrar e listar centros de custo hierárquicos da empresa, usados para rateio de resultado e checagem de orçamento.","acoes":[{"nome":"add-cost-center","desc":"Cria um centro de custo com nome, pai opcional e flag de grupo."},{"nome":"list-cost-centers","desc":"Lista centros de custo da empresa (filtro por parent_id) com paginação."}],"entradas":"add: --name, --company-id, --parent-id, --is-group. list: --company-id/--company, --parent-id, --limit, --offset.","saidas":"add: cost_center_id, name. list: cost_centers[], total_count, has_more.","regras":"Nome e empresa obrigatórios. Centros de custo grupo não podem receber postagem (Step 8 da validação de GL bloqueia). Contas de income/expense exigem cost_center_id na postagem (Step 6).","efeitos":"INSERT em cost_center. Auditoria (create). Commit. Sem postagens em gl_entry.","precondicoes":"Empresa existente; pai existente quando informado."},{"group":"Dimensões Contábeis","objetivo":"Registrar e gerenciar dimensões contábeis customizadas (M6) que enriquecem cada gl_entry via dimensions_json, com validação de obrigatoriedade e integridade FK.","acoes":[{"nome":"add-dimension","desc":"Registra uma nova dimensão (key, label, tipo text|uuid_fk|enum) no dimension_registry."},{"nome":"list-dimensions","desc":"Lista dimensões registradas (ativas por padrão; --include-inactive mostra todas)."},{"nome":"update-dimension","desc":"Atualiza metadados de uma dimensão por key (label, tipo, refers_to, allowed_values, obrigatoriedade, is_active); não renomeia a key."},{"nome":"deactivate-dimension","desc":"Desativa uma dimensão se ela não estiver referenciada por GL viva recente (janela --within-days, default 90 dias)."}],"entradas":"--key, --label, --type (text|uuid_fk|enum), --refers-to (tabela, p/ uuid_fk), --allowed-values (CSV, p/ enum), --required-on-account-types (CSV), --within-days, --include-inactive, --is-active.","saidas":"add: dimension_id, key, data_type. list: dimensions[], count. update: status=updated, key. deactivate: status=deactivated, key.","regras":"key não pode colidir com colunas reservadas (account_id, cost_center_id, project_id). uuid_fk exige --refers-to; enum exige --allowed-values. key é única (insert duplicado falha). Na postagem (Step 13), dimensão obrigatória ausente para o account_type da conta falha, e valor uuid_fk deve referenciar linha existente na tabela validada. deactivate bloqueia se houver gl_entry não cancelado citando a key na janela.","efeitos":"INSERT/UPDATE em dimension_registry (incl. is_active=0 no deactivate). Auditoria (create/update). Commit. As dimensões em si não postam GL, mas passam a ser validadas/exigidas em toda postagem.","precondicoes":"Tabela dimension_registry existente. Para uuid_fk, tabela referenciada (identificador válido) existente."},{"group":"Orçamentos","objetivo":"Definir orçamentos por conta e/ou centro de custo num ano fiscal e acompanhar o realizado x orçado, com ação ao exceder.","acoes":[{"nome":"add-budget","desc":"Cria um orçamento para uma conta e/ou centro de custo no ano fiscal, com action_if_exceeded (warn|stop)."},{"nome":"list-budgets","desc":"Lista orçamentos do ano fiscal e calcula realizado (soma de débitos do período) e variância por orçamento."}],"entradas":"add: --fiscal-year-id, --budget-amount, --account-id e/ou --cost-center-id, --action-if-exceeded (default warn). list: --fiscal-year-id, --company-id/--company, --limit, --offset.","saidas":"add: budget_id. list: budgets[] com actual_amount e variance, total_count, has_more.","regras":"Exige ao menos account_id ou cost_center_id. company_id derivado do ano fiscal. action_if_exceeded default warn. Na postagem (Step 12): se débito acumulado + atual ultrapassa budget_amount, gera warning (warn) ou bloqueia a postagem (stop). Realizado calculado por soma de débitos não cancelados no intervalo do ano fiscal.","efeitos":"add: INSERT em budget + auditoria (create) + commit. list: nenhum (somente leitura; calcula realizado on-the-fly). A aplicação efetiva (warn/stop) ocorre na validação de post-gl-entries.","precondicoes":"Ano fiscal existente; conta e/ou centro de custo existentes."},{"group":"Séries de Numeração","objetivo":"Semear e avançar séries de numeração sequencial por tipo de entidade e empresa (prefixo com ano).","acoes":[{"nome":"seed-naming-series","desc":"Cria séries (prefixo<ano>-) para cada tipo de entidade de ENTITY_PREFIXES que ainda não exista para a empresa."},{"nome":"next-series","desc":"Gera/avança o próximo nome da série para um tipo de entidade da empresa."}],"entradas":"seed: --company-id. next: --entity-type, --company-id.","saidas":"seed: series_created, total_types. next: series (nome gerado), entity_type.","regras":"seed é idempotente: só cria a série se não existir (entity_type+prefix+company). next usa get_next_name (incrementa current_value); falha com ValueError se o tipo não tiver série configurada. Prefixo inclui o ano UTC corrente.","efeitos":"seed: INSERT em naming_series (current_value=0). next: UPDATE do contador da série. Commit. Sem postagens em gl_entry.","precondicoes":"Empresa existente. Para next, série já semeada para o entity_type (seed-naming-series)."},{"group":"Importação","objetivo":"Importar plano de contas e saldos de abertura a partir de arquivos CSV, criando contas e postando o lançamento de abertura.","acoes":[{"nome":"import-chart-of-accounts","desc":"Importa contas de um CSV (name, root_type, account_number, account_type, parent_name, currency, is_group), pulando duplicadas por nome."},{"nome":"import-opening-balances","desc":"Importa saldos de abertura de um CSV (account_number, debit, credit, party_type, party_name) e posta um único lançamento de abertura."}],"entradas":"--csv-path, --company-id; import-opening-balances também exige --posting-date.","saidas":"chart: imported, skipped, total_rows. opening: gl_entries_created, voucher_id, rows_processed.","regras":"Path-safety: resolve symlink, exige extensão .csv e arquivo regular. CSV validado por validate_csv antes. chart: pula conta cujo nome já existe na empresa; resolve parent por parent_name; balance_direction derivado do root_type. opening: resolve conta por account_number (falha se não achar), resolve party (customer/supplier) por nome; posta como voucher_type=journal_entry com is_opening=True (não permite contas de P&L — Step 7).","efeitos":"chart: INSERT em account (depth=0). opening: INSERT em gl_entry via insert_gl_entries (lançamento de abertura, com checksum e validação completa). Commit. import-chart NÃO grava auditoria explícita; import-opening passa pelo motor de GL.","precondicoes":"Empresa existente; arquivo .csv válido. Para opening: contas (por account_number) e ano fiscal aberto cobrindo a posting_date; partes existentes se referenciadas."},{"group":"Integridade e Câmbio","objetivo":"Verificar integridade do razão (balanço e cadeia de hash) e revaluar saldos em moeda estrangeira ao câmbio de fim de período.","acoes":[{"nome":"check-gl-integrity","desc":"Confere se débitos=créditos da empresa e reconstrói a cadeia SHA-256 dos gl_entry para detectar adulteração (broken_links)."},{"nome":"revalue-foreign-balances","desc":"Revalua contas monetárias em moeda estrangeira (AR/AP/bank/cash) à taxa da data, postando o ganho/perda não realizado contra a conta de FX."}],"entradas":"check: --company-id/--company. revalue: --company-id, --as-of-date.","saidas":"check: balanced, total_debit, total_credit, difference, chain_intact, broken_links, total_entries. revalue: revaluations[] (por conta, com gain_loss e exchange_rate), total_gain_loss, accounts_processed.","regras":"check: balanceado quando |débito-crédito|<0.01; recomputa cada gl_checksum a partir de prev_hash (GENESIS) na ordem created_at/rowid; entradas sem checksum são puladas. revalue: usa company.default_currency e exchange_gain_loss_account_id (obrigatório); processa contas não grupo, não desabilitadas, com currency != base; ganho/perda = saldo base revaluado - saldo base atual; ignora saldo/variação zero; pula conta sem taxa de câmbio na data.","efeitos":"check: nenhum (somente leitura). revalue: INSERT em gl_entry (voucher_type=exchange_rate_revaluation) com o par conta vs FX gain/loss, em moeda base; usa default_cost_center_id da empresa na perna de FX. Commit no revalue. Não há auditoria explícita no revalue.","precondicoes":"Empresa existente. revalue: company.exchange_gain_loss_account_id configurado, contas em moeda estrangeira com saldo e taxa de câmbio disponível (get_exchange_rate) na as_of_date; ano fiscal aberto para postar."},{"group":"Status","objetivo":"Apresentar um resumo do estado contábil: contagem de empresas, contas, anos fiscais, lançamentos ativos e última data de postagem.","acoes":[{"nome":"status","desc":"Retorna métricas agregadas do GL; se houver uma única empresa (ou --company-id), filtra por ela, senão mostra estatísticas globais."}],"entradas":"--company-id (opcional; auto-detecta empresa única).","saidas":"companies, accounts, fiscal_years, gl_entries (não cancelados), latest_posting_date.","regras":"Conta apenas gl_entry com is_cancelled=0. Sem company_id e havendo mais de uma empresa, retorna números globais; com uma única empresa, filtra automaticamente.","efeitos":"Nenhum (somente leitura).","precondicoes":"Banco inicializado com a tabela company (dependência mínima do skill)."}]},"journals":{"module":"journals","display":"Lançamentos Contábeis","functionalities":[{"group":"Criação/edição","objetivo":"Criar e editar lançamentos contábeis manuais em rascunho, com linhas de débito/crédito balanceadas, antes de sua submissão ao razão (GL).","acoes":[{"nome":"add-journal-entry","desc":"Cria um novo lançamento contábil em status 'draft' com suas linhas."},{"nome":"update-journal-entry","desc":"Atualiza data, tipo, observação e/ou substitui as linhas de um lançamento ainda em rascunho."}],"entradas":"add: --company-id, --posting-date, --entry-type (default 'journal'), --lines (JSON array com account_id, debit, credit, party_type/party_id, cost_center_id, project_id, remark), --remark, --cwip-asset-id (opcional). update: --journal-entry-id e os campos a alterar (--posting-date, --entry-type, --remark, --lines).","saidas":"add: status 'created', journal_entry_id e naming_series. update: status 'updated', journal_entry_id e lista de updated_fields alterados.","regras":"Mínimo de 2 linhas; cada linha exige account_id e exatamente um lado (débito OU crédito) > 0, ambos >= 0; total de débitos deve igualar total de créditos (round_currency). entry-type deve estar em VALID_ENTRY_TYPES (journal, opening, closing, depreciation, write_off, exchange_rate_revaluation, inter_company, credit_note, debit_note). update só é permitido enquanto status='draft' (caso contrário erro pedindo cancelar antes); ao trocar linhas, recalcula total_debit/total_credit. Se --cwip-asset-id for informado, valida que o ativo está 'under_construction'.","efeitos":"Persiste em journal_entry (status 'draft') e journal_entry_line; update pode apagar e reinserir todas as linhas. Registra auditoria (add-journal-entry/update-journal-entry). NÃO posta no GL nesta etapa (somente rascunho).","precondicoes":"Empresa (company) deve existir; todas as contas (account) das linhas devem existir. Tabelas obrigatórias: company e account. Para CWIP, ativo em construção pré-existente."},{"group":"Consulta/listagem","objetivo":"Recuperar um lançamento individual com suas linhas ou listar/filtrar lançamentos de uma empresa com paginação.","acoes":[{"nome":"get-journal-entry","desc":"Retorna um lançamento e todas as suas linhas (com nome da conta)."},{"nome":"list-journal-entries","desc":"Lista lançamentos de uma empresa com filtros e paginação."}],"entradas":"get: --journal-entry-id. list: --company-id ou --company (nome); filtros opcionais --status, --entry-type, --from-date, --to-date, --account-id; paginação --limit (default 20) e --offset (default 0).","saidas":"get: cabeçalho (id, naming_series, posting_date, entry_type, status, total_debit, total_credit, remark, amended_from, company_id) e array de lines. list: entries[], total_count, limit, offset e has_more.","regras":"get falha se o lançamento não existir. list resolve a empresa por id ou nome (resolve_company_id) e sempre filtra por company_id; --account-id filtra via subconsulta nas linhas; ordena por posting_date desc e created_at desc.","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa existente (para list); lançamento existente (para get). Tabelas company e account presentes."},{"group":"Ciclo de vida","objetivo":"Conduzir o lançamento pelo fluxo rascunho -> submetido -> cancelado, efetivando ou revertendo as postagens no razão (GL).","acoes":[{"nome":"submit-journal-entry","desc":"Submete um rascunho: revalida, posta as entradas no GL e muda status para 'submitted'."},{"nome":"cancel-journal-entry","desc":"Cancela um submetido: reverte as entradas do GL e muda status para 'cancelled'."}],"entradas":"Ambas: --journal-entry-id.","saidas":"submit: status 'submitted', journal_entry_id, gl_entries_created (e, se CWIP, cwip_asset_id/cwip_accumulation_id). cancel: status 'cancelled', journal_entry_id, reversed=true.","regras":"submit exige status='draft'; revalida balanceamento das linhas e chama validate_gl_entries (que rejeita conta congelada, ano fiscal fechado e período congelado). cancel exige status='submitted'. Lançamentos 'opening' são tratados como is_opening na validação/postagem GL.","efeitos":"submit: INSERE linhas em gl_entry (voucher_type='journal_entry'), atualiza status para 'submitted'; se CWIP, grava acumulação contra a perna de débito CWIP e ajusta valor do ativo. cancel: insere entradas de reversão em gl_entry e, se CWIP, desfaz a acumulação e o valor contábil do ativo; muda status para 'cancelled'. Ambos registram auditoria. Não há SLE de estoque nem payment_ledger_entry.","precondicoes":"Lançamento existente no status correto; contas não congeladas; ano fiscal aberto e período não congelado para a data de postagem; tabela fiscal_year disponível para a validação de GL."},{"group":"Retificação","objetivo":"Corrigir um lançamento já submetido criando uma versão emendada vinculada, sem editar o documento original.","acoes":[{"nome":"amend-journal-entry","desc":"Cancela (reverte GL) o lançamento submetido e cria um novo rascunho ligado via amended_from."}],"entradas":"--journal-entry-id; opcionalmente --lines (novas linhas; senão copia as do original), --posting-date (senão herda) e --remark.","saidas":"status 'created', original_id, new_journal_entry_id e new_naming_series.","regras":"Exige status='submitted'. Reverte o GL do original e marca o original como 'amended'. As novas linhas são validadas pelas mesmas regras de balanceamento; o novo lançamento nasce em 'draft' (precisa ser submetido depois) e referencia o original em amended_from. Herda entry_type e company do original.","efeitos":"Insere entradas de reversão no gl_entry do original; muda status do original para 'amended'; cria novo registro em journal_entry (draft) e suas journal_entry_line. Registra auditoria (amend-journal-entry). O novo lançamento ainda NÃO posta no GL (somente ao ser submetido).","precondicoes":"Lançamento existente e submetido; ano fiscal/período aberto para reverter na data de postagem do original."},{"group":"Exclusão/duplicação","objetivo":"Excluir definitivamente rascunhos ou duplicar um lançamento existente como novo rascunho reaproveitando suas linhas.","acoes":[{"nome":"delete-journal-entry","desc":"Exclui fisicamente um lançamento em rascunho (linhas e cabeçalho)."},{"nome":"duplicate-journal-entry","desc":"Cria um novo rascunho copiando todas as linhas de um lançamento existente."}],"entradas":"delete: --journal-entry-id. duplicate: --journal-entry-id e --posting-date opcional (senão usa data atual UTC).","saidas":"delete: status 'deleted', deleted=true. duplicate: status 'created', new_journal_entry_id e naming_series.","regras":"delete só permite status='draft' (sugere cancelar antes se submetido). duplicate copia linhas (conta, débito, crédito, party, centro de custo, projeto, observação), revalida o balanceamento e cria sempre em 'draft' com novo naming_series; herda entry_type, remark e company do original.","efeitos":"delete: APAGA fisicamente journal_entry e journal_entry_line do lançamento; registra auditoria com o naming_series antigo. duplicate: insere novo journal_entry (draft) e linhas; registra auditoria. Nenhum afeta o GL.","precondicoes":"Lançamento existente; para delete, deve estar em rascunho; contas das linhas devem existir."},{"group":"Intercompany","objetivo":"Registrar uma transação entre duas empresas criando um par de lançamentos espelhados (recebível na origem, pagável no destino).","acoes":[{"nome":"create-intercompany-je","desc":"Cria lançamentos pareados entre empresa origem e destino, com contas intercompany e referência cruzada."}],"entradas":"--source-company-id, --target-company-id, --amount, --posting-date e --description opcional.","saidas":"source_je_id/source_naming, target_je_id/target_naming, amount e description.","regras":"Origem e destino devem ser diferentes; amount > 0; ambas as empresas devem existir e ter a MESMA moeda padrão (multimoeda não suportado na v2). Origem: DR Intercompany Receivable / CR conta de receita; Destino: DR conta de despesa (ou CMV) / CR Intercompany Payable. Cria automaticamente as contas 'Intercompany Receivable' (asset/receivable) e 'Intercompany Payable' (liability/payable) se não existirem; usa o primeiro centro de custo não-grupo de cada empresa para as linhas de P&L. entry_type fixo 'inter_company'.","efeitos":"Insere DOIS journal_entry (ambos em 'draft', tipo inter_company) e suas linhas; pode CRIAR contas intercompany (account); grava referência cruzada no campo remark de cada lado. Registra auditoria. NÃO posta no GL (ambos nascem em rascunho, exigindo submit individual).","precondicoes":"Duas empresas distintas existentes com mesma moeda; origem com conta de receita (não-grupo) e destino com conta de despesa/CMV (não-grupo)."},{"group":"Modelos recorrentes","objetivo":"Definir e manter modelos de lançamento que se repetem em uma periodicidade, servindo de base para geração automática.","acoes":[{"nome":"add-recurring-template","desc":"Cria um modelo recorrente ativo com frequência, datas, linhas e flag de auto-submit."},{"nome":"update-recurring-template","desc":"Altera campos de um modelo (nome, frequência, datas, tipo, linhas, auto-submit, status active/paused)."},{"nome":"delete-recurring-template","desc":"Exclui fisicamente um modelo recorrente."}],"entradas":"add: --company-id, --template-name, --frequency (default monthly), --start-date, --end-date opcional, --entry-type, --lines (JSON), --auto-submit, --remark. update: --template-id + campos a alterar (inclui --template-status active|paused). delete: --template-id.","saidas":"add: status 'created', template_id, naming_series e next_run_date (= start_date). update: status 'updated', template_id e updated_fields. delete: status 'deleted', deleted=true.","regras":"frequency deve estar em (daily, weekly, monthly, quarterly, annual); entry_type em VALID_ENTRY_TYPES; linhas validadas pelo mesmo balanceamento de débito/crédito. next_run_date inicia em start_date. update bloqueia modelos 'completed' e só aceita status 'active' ou 'paused'. Apesar do docstring mencionar soft delete, delete remove o registro fisicamente.","efeitos":"Persiste/atualiza/remove recurring_journal_template (linhas guardadas como JSON). Registra auditoria. Nenhum efeito direto no GL ou em journal_entry (apenas o modelo).","precondicoes":"Empresa existente (add); contas das linhas existentes; modelo existente e não 'completed' (update); modelo existente (delete)."},{"group":"Consulta de modelos","objetivo":"Consultar um modelo recorrente em detalhe ou listar os modelos de uma empresa.","acoes":[{"nome":"get-recurring-template","desc":"Retorna um modelo recorrente completo, com as linhas em JSON decodificado."},{"nome":"list-recurring-templates","desc":"Lista modelos recorrentes de uma empresa, opcionalmente filtrando por status, com paginação."}],"entradas":"get: --template-id. list: --company-id ou --company (nome), --template-status opcional, --limit (default 20), --offset (default 0).","saidas":"get: todos os campos do modelo (frequência, datas, next_run_date, last_generated_date, entry_type, auto_submit, status, lines). list: templates[], total_count, limit, offset, has_more.","regras":"get falha se o modelo não existir e tenta decodificar o JSON das linhas. list resolve empresa por id/nome e ordena por next_run_date ascendente.","efeitos":"Nenhum (somente leitura).","precondicoes":"Modelo existente (get); empresa existente (list)."},{"group":"Processamento de recorrências","objetivo":"Gerar automaticamente os lançamentos a partir dos modelos recorrentes vencidos de uma empresa em determinada data de corte.","acoes":[{"nome":"process-recurring","desc":"Varre modelos ativos com next_run_date <= data de corte, gera os lançamentos e avança o próximo agendamento."}],"entradas":"--company-id e --as-of-date opcional (default data atual UTC).","saidas":"generated (quantidade) e results[] com template_id, template_name, journal_entry_id, naming_series, posting_date, je_status, next_run_date e template_status por modelo processado.","regras":"Processa apenas modelos status='active' com next_run_date <= as_of_date (idempotente em relação à data). Para cada um: cria o lançamento com posting_date = next_run_date, calcula totais; se auto_submit=1, valida e posta no GL e marca 'submitted' (falha de auto-submit deixa o lançamento como 'draft', sem abortar o lote). Avança next_run_date conforme a frequência (com clamp de fim de mês); se ultrapassar end_date, marca o modelo como 'completed' e zera o próximo agendamento.","efeitos":"Insere journal_entry (draft ou submitted) e journal_entry_line para cada modelo vencido; quando auto_submit, INSERE entradas no gl_entry. Atualiza next_run_date, last_generated_date e status do modelo (active/completed). Registra auditoria (process-recurring). Sem SLE de estoque ou payment_ledger.","precondicoes":"Empresa existente; modelos ativos com linhas válidas; para auto-submit, contas não congeladas e ano fiscal/período aberto na data de postagem."},{"group":"Status","objetivo":"Apresentar um panorama agregado dos lançamentos e modelos recorrentes de uma empresa por status.","acoes":[{"nome":"status","desc":"Conta lançamentos por status (draft/submitted/cancelled/amended) e modelos recorrentes por status."}],"entradas":"--company-id ou --company (nome).","saidas":"total e contagens por status (draft, submitted, cancelled, amended) dos lançamentos, mais recurring_templates com contagens (active, paused, completed).","regras":"Resolve a empresa por id ou nome; agrupa journal_entry e recurring_journal_template por status filtrando por company_id.","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa existente; tabelas journal_entry e recurring_journal_template presentes."}]},"selling":{"module":"selling","display":"Vendas (Order-to-Cash)","functionalities":[{"group":"Clientes","objetivo":"Cadastrar e manter clientes (pessoa jurídica/física), seus termos de pagamento, limite e status de crédito, e consultar o saldo em aberto. Inclui importação em massa por CSV.","acoes":[{"nome":"add-customer","desc":"Cria cliente com status 'active'; valida empresa e termos de pagamento; arredonda credit_limit."},{"nome":"update-customer","desc":"Atualiza campos do cliente (nome, credit_limit, grupo, tipo, email, phone, termos); aceita id ou name."},{"nome":"get-customer","desc":"Retorna o cliente mais o total em aberto (sales_invoice com status submitted/overdue/partially_paid e outstanding>0) e a contagem de faturas."},{"nome":"list-customers","desc":"Lista paginada com filtros por empresa, grupo e busca textual (name/tax_id)."},{"nome":"import-customers","desc":"Importa clientes de CSV (colunas name, customer_type, territory, currency, email, phone); pula duplicados por (name, empresa); gera naming_series."}],"entradas":"--name, --company-id, --customer-type (company|individual), --customer-group, --payment-terms-id, --credit-limit, --tax-id, --exempt-from-sales-tax, --primary-address/contact, --email, --phone, --custom-fields; import: --csv-path; consultas: --customer-id, --search, --limit/--offset.","saidas":"customer_id e dados criados/atualizados; get inclui total_outstanding e outstanding_invoice_count; list inclui customers[], total_count, has_more; import retorna imported/skipped/total_rows.","regras":"customer_type deve ser company ou individual; valida existência de empresa e payment_terms; credit_limit arredondado a moeda. update aceita id OU name e exige ao menos um campo. import: exige .csv real, valida CSV e pula duplicado por (name, company_id).","efeitos":"INSERT/UPDATE em customer; campos custom via store_from_arg; registro de auditoria (audit) em add/update. import faz INSERT em lote. Nenhum lançamento GL/SLE/PLE.","precondicoes":"Empresa (company) deve existir; payment_terms_id, se informado, deve existir; tabelas company/account/item presentes (REQUIRED_TABLES)."},{"group":"Cotações","objetivo":"Criar e gerir cotações em rascunho, submetê-las (gerando naming series) e convertê-las em pedido de venda.","acoes":[{"nome":"add-quotation","desc":"Cria cotação em 'draft' com itens, calcula total/imposto/grand_total; sem aplicar pricing rule."},{"nome":"update-quotation","desc":"Atualiza cotação 'draft': valid_until e/ou substitui itens (delete+insert), recalcula totais."},{"nome":"get-quotation","desc":"Retorna cabeçalho da cotação e seus itens com item_name."},{"nome":"list-quotations","desc":"Lista paginada com filtros por empresa, cliente, status e intervalo de datas."},{"nome":"submit-quotation","desc":"Transição draft->open; gera naming_series via get_next_name."},{"nome":"convert-quotation-to-so","desc":"Cria sales_order 'draft' a partir da cotação (open ou draft); marca cotação como 'ordered' e grava converted_to."}],"entradas":"--customer-id, --posting-date, --items (JSON), --company-id, --tax-template-id, --valid-till; consultas/transições: --quotation-id, --delivery-date (na conversão).","saidas":"quotation_id com total_amount/tax_amount/grand_total; submit retorna naming_series e status 'open'; convert retorna sales_order_id e status 'ordered'.","regras":"Ciclo: draft -> open (submit) -> ordered (convert). update só em 'draft'; submit só de 'draft'; convert só de 'open'/'draft'. Itens validados por _calculate_line_items (qty>0, item existe); imposto por template (on_net_total, actual, on_previous_row_total/amount, on_item_quantity, add/deduct).","efeitos":"INSERT/UPDATE/DELETE em quotation e quotation_item; convert cria sales_order + sales_order_item; auditoria em todas as ações. Nenhum GL/SLE/PLE.","precondicoes":"Cliente ativo e empresa existentes; itens cadastrados; tax_template_id (se usado) configurado."},{"group":"Pedidos de Venda","objetivo":"Gerir o pedido de venda do rascunho à confirmação (com checagem de limite de crédito) e seu ciclo de vida (cancelar, fechar), incluindo acompanhamento de % entregue/faturado.","acoes":[{"nome":"add-sales-order","desc":"Cria SO 'draft' com itens; aplica pricing rule (apply_pricing=True) e calcula totais/imposto."},{"nome":"update-sales-order","desc":"Atualiza SO 'draft': delivery_date e/ou itens (recalcula com pricing)."},{"nome":"get-sales-order","desc":"Retorna SO com itens, notas de entrega não canceladas e faturas vinculadas."},{"nome":"list-sales-orders","desc":"Lista paginada com filtros por empresa, cliente, status e datas; mostra per_delivered/per_invoiced."},{"nome":"submit-sales-order","desc":"draft->confirmed; valida cliente ativo, itens com qty>0 e rate>0, e exposição de crédito vs credit_limit."},{"nome":"cancel-sales-order","desc":"Cancela SO se não houver DN/fatura ativa vinculada."},{"nome":"close-sales-order","desc":"Fecha SO parcialmente atendido (impede novos DN/faturas, preserva filhos); grava close_reason/closed_by."}],"entradas":"--customer-id, --posting-date, --items, --company-id, --tax-template-id, --delivery-date; transições: --sales-order-id, --reason, --closed-by.","saidas":"sales_order_id com totais; submit retorna naming_series e status 'confirmed'; cancel/close retornam novo status.","regras":"Ciclo: draft -> confirmed (submit) -> partially/fully_delivered, partially/fully_invoiced -> closed/cancelled. submit checa limite: exposição = AR em aberto + SOs 'confirmed' (exceto este) + grand_total deste <= credit_limit (se >0). cancel só sem DN/fatura ativa; close bloqueado para draft/cancelled/closed.","efeitos":"INSERT/UPDATE/DELETE em sales_order e sales_order_item; submit/cancel/close apenas mudam status e geram auditoria. Nenhum GL/SLE/PLE (postagens ocorrem em DN e fatura).","precondicoes":"Cliente ativo e empresa; itens válidos; pricing_rule e tax_template opcionais. Para submit, credit_limit configurado se quiser bloqueio."},{"group":"Emendas","objetivo":"Emendar um pedido de venda confirmado criando uma nova versão (linkada via amended_from) e cancelando a original, além de rastrear toda a cadeia de emendas.","acoes":[{"nome":"amend-sales-order","desc":"Cancela o SO original (só sem DN/fatura ativos) e cria novo SO 'draft' com amended_from; itens vêm de --items ou são copiados do original."},{"nome":"get-amendment-history","desc":"Reconstrói a cadeia de emendas (ancestrais via amended_from + descendentes) de um SO."}],"entradas":"--sales-order-id; opcional --items (JSON com mudanças); get: --sales-order-id.","saidas":"new_sales_order_id, amended_from, original_status='cancelled' e novos totais; history retorna amendment_chain[] e chain_length.","regras":"Bloqueia emenda se SO está draft/cancelled/closed ou se houver qualquer DN ou fatura não cancelada vinculada. Novo SO recalcula com pricing rule e imposto; mantém customer/order_date/tax_template da original.","efeitos":"UPDATE no SO original (status='cancelled') + INSERT de novo sales_order/sales_order_item; dois registros de auditoria (cancelamento e criação). Nenhum GL/SLE/PLE. get é somente leitura.","precondicoes":"SO existente em status confirmado/parcial (não draft/cancelled/closed) e sem documentos filhos ativos."},{"group":"Notas de Entrega","objetivo":"Emitir notas de entrega (totais ou parciais) a partir do pedido de venda e, na submissão, baixar estoque e lançar COGS; cancelar reverte os lançamentos.","acoes":[{"nome":"create-delivery-note","desc":"Cria DN 'draft' do SO (confirmed/partially_delivered); entrega total (itens não entregues) ou parcial por --items, validando qty <= remanescente."},{"nome":"get-delivery-note","desc":"Retorna DN com itens (item_name/item_code)."},{"nome":"list-delivery-notes","desc":"Lista paginada com filtros por empresa, cliente, status e datas."},{"nome":"submit-delivery-note","desc":"draft->submitted; gera SLE de saída (qty negativa) e GL de COGS via inventário perpétuo; atualiza delivered_qty e status do SO."},{"nome":"cancel-delivery-note","desc":"submitted->cancelled; reverte SLE e GL e devolve delivered_qty ao SO (se não houver fatura vinculada)."}],"entradas":"--sales-order-id, --posting-date, --items (parcial: item_id/sales_order_item_id, qty, warehouse_id, batch_id, serial_numbers), --warehouse-id (override); get/submit/cancel: --delivery-note-id.","saidas":"delivery_note_id, total_qty, item_count; submit retorna naming_series, sle_entries_created, gl_entries_created; cancel retorna contagem de reversões.","regras":"Ciclo: draft -> submitted -> cancelled. Itens de serviço são pulados no SLE. Exige warehouse (do item ou default da empresa) e o tipo deve ser 'stores' para despacho. Atualiza per_delivered do SO (fully/partially_delivered). cancel bloqueado se houver fatura ativa referenciando a DN.","efeitos":"submit: INSERT em stock_ledger_entry (saída), gl_entry de COGS (create_perpetual_inventory_gl), UPDATE serial_number para 'delivered', UPDATE delivered_qty/per_delivered/status do SO. cancel: reverse_sle_entries + reverse_gl_entries e devolução de delivered_qty (mínimo 0). Auditoria em ambas.","precondicoes":"SO confirmado/parcialmente entregue; armazém tipo 'stores' válido; ano fiscal aberto e cost center da empresa; conta COGS e conta de estoque configuradas."},{"group":"Faturas de Venda","objetivo":"Criar faturas de venda (a partir de SO, DN ou avulsa), submetê-las gerando receita/AR/imposto no GL e PLE (e SLE/COGS opcional quando update_stock), e cancelá-las revertendo tudo.","acoes":[{"nome":"create-sales-invoice","desc":"Cria fatura 'draft' do SO (itens não faturados), da DN (update_stock=0) ou avulsa; calcula imposto, due_date por payment_terms (ou +30 dias)."},{"nome":"update-sales-invoice","desc":"Atualiza fatura 'draft': due_date e/ou itens (recalcula totais e outstanding)."},{"nome":"get-sales-invoice","desc":"Retorna fatura com itens e payment_ledger_entry vinculados (sales_invoice e credit_note)."},{"nome":"list-sales-invoices","desc":"Lista paginada com filtros por empresa, cliente, status e datas; mostra outstanding e is_return."},{"nome":"submit-sales-invoice","desc":"draft->submitted; gera GL (DR AR / CR Receita / CR Imposto), PLE, e SLE+COGS se update_stock; atualiza invoiced_qty/status do SO."},{"nome":"cancel-sales-invoice","desc":"submitted/overdue/partially_paid -> cancelled; reverte GL, PLE (delinked) e SLE; zera outstanding e devolve invoiced_qty do SO."},{"nome":"update-invoice-outstanding","desc":"Hook chamado por erpclaw-payments para abater pagamento via lib payment_clearing (rejeita over-payment)."}],"entradas":"--customer-id, --company-id, --items, --tax-template-id, --posting-date, --due-date, --sales-order-id, --delivery-note-id, --payment-terms-id; transições: --sales-invoice-id; pagamento: --amount.","saidas":"sales_invoice_id com totais, outstanding e update_stock; submit retorna naming_series, gl/sle_entries_created; update-outstanding retorna novo outstanding_amount e status.","regras":"Ciclo: draft -> submitted -> partially_paid/overdue/paid/cancelled. update_stock=1 por padrão (perpétuo US), 0 quando vem de DN ou SO já entregue. submit valida cliente ativo e aplica política de crédito (_enforce_credit_policy: bloqueia suspended/on_hold e excede credit_limit). Origem SO fatura só itens com remaining>0. update só em draft. cancel só de submitted/overdue/partially_paid.","efeitos":"submit: gl_entry (receita/AR/imposto, party=customer), payment_ledger_entry, e quando update_stock SLE de saída + gl_entry de COGS (entry_set='cogs'); UPDATE invoiced_qty/per_invoiced/status do SO. cancel: reverse_gl/sle, PLE delinked=1, status cancelled, devolução invoiced_qty. update-outstanding: UPDATE outstanding/status via lib. Auditoria em todas.","precondicoes":"Cliente ativo; contas de recebível, receita e imposto da empresa; ano fiscal aberto, cost center; conta COGS/estoque e armazém se update_stock; payment_terms para due_date."},{"group":"Notas de Crédito/Estorno","objetivo":"Emitir notas de crédito (devolução) contra uma fatura submetida, gravadas como sales_invoice com is_return=1 e valores negativos, que revertem AR/receita ao serem submetidas.","acoes":[{"nome":"create-credit-note","desc":"Cria nota de crédito 'draft' (is_return=1, return_against=fatura) com itens validados contra a fatura original e quantidades/valores negativos."},{"nome":"list-credit-notes","desc":"Lista faturas com is_return=1, com nome da fatura original (return_against_name)."}],"entradas":"--against-invoice-id, --items (JSON: item_id, qty, rate opcional), --posting-date, --reason; list: --company-id, --customer-id, --status, datas.","saidas":"credit_note_id, against_invoice_id, grand_total (negativo) e is_return=true; list retorna credit_notes[] com totais.","regras":"Fatura original deve estar submitted/overdue/partially_paid/paid. Cada item deve existir na fatura original e qty de devolução <= qty original. Totais e imposto são negados. A submissão/cancelamento usa as MESMAS ações de fatura (submit/cancel-sales-invoice) com voucher_type 'credit_note' (DR/CR invertidos).","efeitos":"create: INSERT em sales_invoice (is_return=1) e sales_invoice_item com valores negativos; auditoria. Postagens reais (GL CR AR/DR Receita, PLE negativa, SLE de entrada/devolução) ocorrem no submit-sales-invoice. list é somente leitura.","precondicoes":"Fatura original existente e submetida (não draft/cancelled); itens correspondentes à fatura original; demais pré-condições de fatura para a submissão."},{"group":"Crédito e Cobrança (Dunning)","objetivo":"Gerir política de crédito do cliente (limite, hold/suspend) e executar ciclos de cobrança escalonada (dunning) sobre faturas vencidas, com ações de email/hold/call/suspend.","acoes":[{"nome":"check-credit-limit","desc":"Calcula crédito disponível: credit_limit - AR em aberto (faturas submitted, is_return=0); somente leitura."},{"nome":"place-customer-on-hold","desc":"Define customer.credit_status (active|on_hold|suspended); grava auditoria com valor anterior."},{"nome":"add-dunning-level","desc":"Configura nível de escalonamento (1-10): dias de atraso + ação (email|hold|call|suspend) + template."},{"nome":"run-dunning-cycle","desc":"Acha faturas vencidas, casa cada cliente ao maior nível aplicável, aplica ação; para 'email' enfileira envio via erpclaw-alerts pós-commit. Idempotente por (cliente, nível, dia)."},{"nome":"list-dunning-runs","desc":"Lista histórico de dunning_run por cliente/empresa."}],"entradas":"--customer-id, --credit-status, --reason; níveis: --company-id, --level, --days-overdue, --dunning-action, --template-id, --description; ciclo: --company-id, --run-date.","saidas":"check retorna credit_limit, outstanding_ar, available_credit, credit_status, limit_enforced; cycle retorna customers_processed, runs_created, actions{}, emails{sent,skipped}, run_ids.","regras":"credit_status: suspended/on_hold bloqueiam novas faturas (em submit-sales-invoice). Nível exige level 1-10, days_overdue>=0, ação válida. No ciclo, maior days_overdue<=days_late vence; pula se já existe run (cliente,nível) no dia; email sem template ou sem email do cliente é skip-with-note (não falha).","efeitos":"place-on-hold/run-cycle: UPDATE customer.credit_status (hold/suspend); add-level: INSERT dunning_level; run: INSERT dunning_run (status completed) e, pós-commit, subprocess para erpclaw-alerts send-email gravando generated_email_id. Auditoria em place/add. check/list somente leitura. Sem GL/SLE/PLE.","precondicoes":"Empresa existente; níveis de dunning configurados para o ciclo; faturas submetidas vencidas com outstanding>0; erpclaw-alerts instalado e template para envio de email."},{"group":"Parceiros de Venda","objetivo":"Cadastrar parceiros de venda (representantes) com taxa de comissão, para uso/listagem no domínio de vendas.","acoes":[{"nome":"add-sales-partner","desc":"Cria parceiro de venda com name e commission_rate (arredondada)."},{"nome":"list-sales-partners","desc":"Lista paginada de parceiros ordenada por nome."}],"entradas":"--name, --commission-rate; list: --limit, --offset.","saidas":"sales_partner_id, name, commission_rate; list retorna sales_partners[], total_count, has_more.","regras":"name e commission_rate obrigatórios; commission_rate convertida para decimal e arredondada. Falha de integridade (duplicado) gera erro amigável.","efeitos":"INSERT em sales_partner; auditoria em add. list somente leitura. Nenhum GL/SLE/PLE; nenhum cálculo automático de comissão no código.","precondicoes":"Nenhuma além das tabelas base (não valida empresa)."},{"group":"Faturas Recorrentes","objetivo":"Definir templates de faturamento recorrente por cliente/frequência e gerar automaticamente (via cron) faturas submetidas nas datas devidas, avançando a próxima data.","acoes":[{"nome":"add-recurring-template","desc":"Cria template 'draft' com cliente, frequência, start/end_date, itens e tax_template; next_invoice_date=start_date."},{"nome":"update-recurring-template","desc":"Atualiza frequência, status (active|paused|cancelled) e/ou itens do template."},{"nome":"list-recurring-templates","desc":"Lista templates por empresa/cliente/status ordenados por próxima data."},{"nome":"generate-recurring-invoices","desc":"Cron: para templates 'active' com next_invoice_date<=as_of_date, cria e auto-submete a fatura, posta GL+PLE e avança datas."}],"entradas":"--customer-id, --items, --frequency (weekly|monthly|quarterly|semi_annually|annually), --start-date, --end-date, --company-id, --tax-template-id, --payment-terms-id; update: --template-id, --template-status; gerar: --company-id, --as-of-date.","saidas":"template_id, frequency, next_invoice_date; generate retorna invoices_generated, templates_processed/completed, invoices[] e errors[].","regras":"frequency restrita ao conjunto válido; template status active/paused/cancelled (só 'active' gera). generate só processa não-vencido por end_date; calcula due_date = data+30; avança next_invoice_date por _next_invoice_date (clamp de fim de mês) e marca 'completed' quando ultrapassa end_date. Erros por template são coletados sem abortar o lote (rollback parcial em falha de GL).","efeitos":"add/update: INSERT/UPDATE/DELETE em recurring_invoice_template(_item); auditoria. generate: cria sales_invoice+itens (status submitted, update_stock=0), gl_entry (AR/receita/imposto), payment_ledger_entry, gera naming e UPDATE de last/next_invoice_date e status do template. Sem SLE (update_stock=0).","precondicoes":"Cliente ativo e empresa; itens válidos; contas de recebível/receita configuradas para postagem na geração; ano fiscal e cost center para o GL."},{"group":"Blanket Orders","objetivo":"Gerir acordos-quadro de venda (blanket order) com quantidades/valores acordados por período e gerar pedidos de venda que consomem (drawdown) o saldo do acordo.","acoes":[{"nome":"add-blanket-order","desc":"Cria blanket order 'draft' (type 'selling') com validade e itens (qty>0, rate>0); calcula total_qty."},{"nome":"submit-blanket-order","desc":"draft->active; valida tipo 'selling'."},{"nome":"get-blanket-order","desc":"Retorna o acordo e seus itens."},{"nome":"list-blanket-orders","desc":"Lista acordos do tipo 'selling' com filtros por empresa/cliente/status."},{"nome":"create-so-from-blanket","desc":"Cria SO 'draft' consumindo o acordo 'active' (não expirado), validando qty<=remanescente; atualiza ordered_qty."}],"entradas":"--customer-id, --items, --company-id, --valid-from, --valid-to; transições/uso: --blanket-order-id, --tax-template-id, --posting-date, --delivery-date.","saidas":"blanket_order_id, total_qty, validade; create-so retorna sales_order_id, total_amount, grand_total.","regras":"valid_to deve ser > valid_from; itens exigem qty>0 e rate>0. Ciclo: draft -> active (submit). create-so só de acordo 'active' e dentro da validade (valid_to>=hoje), com qty solicitada <= (quantity - ordered_qty) por item; recalcula ordered_qty total via decimal_sum.","efeitos":"INSERT/UPDATE em blanket_order(_item); create-so cria sales_order+itens e atualiza ordered_qty do item e do acordo. Auditoria em add/submit/create-so. Nenhum GL/SLE/PLE.","precondicoes":"Cliente ativo e empresa; itens válidos; acordo ativo e vigente para gerar SO."},{"group":"Faturamento Intercompany","objetivo":"Espelhar uma fatura de venda de uma empresa como fatura de compra (mirror PI) em outra empresa do grupo, mapeando contas, e cancelar em cascata ambas.","acoes":[{"nome":"add-intercompany-account-map","desc":"Mapeia conta da empresa origem para conta da empresa destino (valida pertencimento e duplicidade)."},{"nome":"list-intercompany-account-maps","desc":"Lista mapeamentos por par de empresas com nomes das contas."},{"nome":"create-intercompany-invoice","desc":"Cria purchase_invoice 'draft' espelhando a SI submetida na empresa destino (supplier dado); marca a SI como is_intercompany."},{"nome":"list-intercompany-invoices","desc":"Lista faturas intercompany (SI como vendedor + PI como comprador) da empresa."},{"nome":"cancel-intercompany-invoice","desc":"Cancela a SI intercompany e cascateia para a PI espelho (reverte GL/SLE, delinka PLE; PI draft é apagada)."}],"entradas":"mapa: --company-id (origem), --target-company-id, --source-account-id, --target-account-id; espelho: --sales-invoice-id, --target-company-id, --supplier-id; cancel: --sales-invoice-id; list: --company-id.","saidas":"map_id; create retorna purchase_invoice_id, source/target_company_id, totais, items_mirrored; cancel retorna status e contagens de reversões de SI e PI.","regras":"Empresas origem/destino devem ser diferentes; contas devem pertencer às respectivas empresas; SI deve estar submetida e ainda não intercompany. Mirror copia datas/moeda/totais e mapeia conta de receita->despesa (ou default expense). Cancel exige SI is_intercompany; reverte SI e PI conforme status (PI 'draft' é deletada).","efeitos":"INSERT em intercompany_account_map; create: INSERT purchase_invoice(_item) na empresa destino + UPDATE sales_invoice (is_intercompany=1, intercompany_reference_id). cancel: reverse_gl_entries/reverse_sle_entries em SI e PI, payment_ledger_entry delinked=1, UPDATE status='cancelled' em ambas (ou DELETE da PI draft). Sem auditoria explícita nessas ações.","precondicoes":"Duas empresas distintas; supplier no destino representando a origem; SI submetida; contas (income/expense) e mapeamentos configurados."},{"group":"Drop Ship/Romaneio","objetivo":"Gerar pedido de compra com envio direto (drop-ship) ao cliente a partir de itens marcados no SO, e emitir romaneios de embalagem (packing slip) vinculados à nota de entrega.","acoes":[{"nome":"create-drop-ship-order","desc":"Cria purchase_order 'draft' para o supplier com delivery_address=endereço do cliente, a partir dos itens do SO com is_drop_ship=1 e remanescente>0; linka aos itens do SO."},{"nome":"add-packing-slip","desc":"Cria packing_slip vinculado a uma DN, validando que qty_packed acumulada não exceda a qty do item da DN."},{"nome":"get-packing-slip","desc":"Retorna o romaneio com seus itens (item_code/item_name)."},{"nome":"list-packing-slips","desc":"Lista romaneios por DN e/ou empresa."}],"entradas":"drop-ship: --sales-order-id, --supplier-id, --posting-date; packing: --delivery-note-id, --items (delivery_note_item_id, qty_packed), --notes; get/list: --packing-slip-id, --delivery-note-id, --company-id.","saidas":"purchase_order_id com delivery_address, total_amount e item_count; packing retorna packing_slip_id e item_count.","regras":"drop-ship exige SO confirmed/partially_delivered e itens is_drop_ship=1 com remanescente (quantity-delivered_qty)>0; usa endereço primário do cliente. packing: qty_packed>0 e (qty_packed + já embalado) <= qty da DN por item.","efeitos":"create-drop-ship: INSERT em purchase_order/purchase_order_item (status draft) ligados aos itens do SO; auditoria. add-packing-slip: INSERT em packing_slip/packing_slip_item; auditoria. get/list somente leitura. Nenhum GL/SLE/PLE.","precondicoes":"SO confirmado com itens marcados is_drop_ship e supplier existente (drop-ship); DN existente com itens (packing); cliente com primary_address para o endereço de entrega."},{"group":"Status","objetivo":"Fornecer um panorama consolidado do domínio de vendas para uma empresa: contagens por status e total a receber em aberto.","acoes":[{"nome":"status","desc":"Resumo da empresa: nº de clientes, cotações/SOs/faturas agrupadas por status e total em aberto."}],"entradas":"--company-id (opcional; se ausente usa a primeira empresa encontrada).","saidas":"customers (contagem), quotations{}, sales_orders{}, sales_invoices{} por status e total_outstanding.","regras":"Se nenhuma empresa for informada, usa a primeira do banco; erro amigável se não houver empresa. total_outstanding soma faturas submitted/overdue/partially_paid com outstanding>0.","efeitos":"Nenhum (somente leitura) — apenas SELECTs agregados (Count/group by, decimal_sum).","precondicoes":"Ao menos uma empresa cadastrada; tabelas de cliente/cotação/SO/fatura existentes."}]},"buying":{"module":"buying","display":"Compras (Procure-to-Pay)","functionalities":[{"group":"Fornecedores","objetivo":"Cadastrar e manter o registro mestre de fornecedores e consultar sua posição em aberto (contas a pagar). Suporta importação em massa via CSV.","acoes":[{"nome":"add-supplier","desc":"Cria fornecedor em status 'active' (tipo company/individual, grupo, termos de pagamento, tax_id, flag 1099, endereço, e-mail, telefone, custom fields)."},{"nome":"update-supplier","desc":"Atualiza campos do fornecedor (nome, termos, grupo, tipo, e-mail, telefone); aceita id ou nome."},{"nome":"get-supplier","desc":"Retorna o fornecedor com resumo de saldo em aberto somando outstanding_amount de purchase_invoice (status submitted/overdue/partially_paid)."},{"nome":"list-suppliers","desc":"Lista paginada com filtro por company, supplier_group e busca textual (nome/tax_id)."},{"nome":"import-suppliers","desc":"Importa fornecedores em massa de CSV (.csv); pula duplicados por nome+empresa; gera naming_series."}],"entradas":"--name, --company-id, --supplier-type (company|individual), --supplier-group, --payment-terms-id, --tax-id, --is-1099-vendor, --primary-address (JSON), --email, --phone, --custom-fields; para listar: --search, --limit, --offset; para importar: --csv-path.","saidas":"supplier_id e nome (criação); updated_fields (update); registro completo + total_outstanding e outstanding_invoice_count (get); lista + total_count/has_more; imported/skipped/total_rows (import).","regras":"supplier_type deve ser 'company' ou 'individual'; valida existência de company e payment_terms; status nasce 'active'. import-suppliers exige extensão .csv, valida o CSV e ignora linhas com nome já existente na empresa.","efeitos":"Grava em supplier e custom_field_value; registra auditoria (add/update-supplier, import). Nenhuma postagem em GL/SLE/PLE. get/list são somente leitura.","precondicoes":"Empresa (company) existente; payment_terms opcional deve existir se informado. Tabelas company, account, item presentes (REQUIRED_TABLES)."},{"group":"Requisições de Material","objetivo":"Registrar necessidades internas de itens (compra, transferência, fabricação ou baixa) em rascunho e submetê-las para iniciar o ciclo de suprimentos.","acoes":[{"nome":"add-material-request","desc":"Cria requisição em 'draft' com itens (item_id, qty, warehouse_id); normaliza request_type 'transfer' para 'material_transfer'."},{"nome":"submit-material-request","desc":"Submete a requisição (draft -> submitted) e atribui naming_series sequencial."},{"nome":"list-material-requests","desc":"Lista paginada filtrando por company, request_type e status."}],"entradas":"--request-type (purchase|transfer|manufacture, internamente também material_issue), --items (JSON: item_id, qty, warehouse_id), --company-id; para submeter: --material-request-id; para listar: --mr-status, --limit, --offset.","saidas":"material_request_id, request_type e item_count (criação); naming_series e status='submitted' (submit); lista paginada.","regras":"request_type obrigatório e validado; itens em array não vazio, qty > 0 por item; só submete se status='draft'; naming_series gerado por empresa no submit.","efeitos":"Grava em material_request e material_request_item; auditoria (add/submit-material-request). Nenhuma postagem em GL/SLE/PLE. list é somente leitura.","precondicoes":"Empresa existente; itens referenciam item_id (não há validação rígida de existência do item nesta ação)."},{"group":"Cotações e RFQ","objetivo":"Conduzir o processo de cotação: criar RFQ para múltiplos fornecedores, registrar as respostas (supplier quotations) e comparar preços/prazos lado a lado.","acoes":[{"nome":"add-rfq","desc":"Cria RFQ em 'draft' com itens (item_id, qty, uom, required_date) e lista de fornecedores convidados; valida cada fornecedor."},{"nome":"submit-rfq","desc":"Submete RFQ (draft -> submitted), gera naming_series e marca sent_date nos rfq_supplier."},{"nome":"list-rfqs","desc":"Lista RFQs filtrando por company e status."},{"nome":"add-supplier-quotation","desc":"Registra a resposta de um fornecedor a um RFQ: cria supplier_quotation + itens (rate/lead_time), calcula totais e marca response_date."},{"nome":"list-supplier-quotations","desc":"Lista cotações de fornecedores filtrando por rfq_id e supplier_id."},{"nome":"compare-supplier-quotations","desc":"Compara cotações por item do RFQ, identificando menor preço (lowest_rate/lowest_supplier) e marcando is_lowest."}],"entradas":"--items (JSON), --suppliers (JSON de IDs), --company-id (add-rfq); --rfq-id (submit/quotation/compare); --supplier-id e --items com rfq_item_id+rate+lead_time_days (add-supplier-quotation).","saidas":"rfq_id, item_count, supplier_count; supplier_quotation_id e total_amount; lista de cotações; estrutura comparison com quotes por item, lowest_rate, lowest_supplier e supplier_count.","regras":"Itens e fornecedores em arrays não vazios; qty>0 e rate>0; só submete RFQ em 'draft'. Na cotação, qty vem do rfq_item e amount=qty*rate; ao registrar resposta marca rfq_supplier; quando TODOS os fornecedores respondem, RFQ passa a 'quotation_received'.","efeitos":"Grava request_for_quotation, rfq_item, rfq_supplier, supplier_quotation, supplier_quotation_item; atualiza status do RFQ e datas de envio/resposta; auditoria. Nenhuma postagem em GL/SLE/PLE. list/compare são somente leitura.","precondicoes":"Empresa existente; fornecedores cadastrados; para cotação, RFQ e rfq_item correspondentes devem existir."},{"group":"Pedidos de Compra","objetivo":"Criar, confirmar e gerenciar o ciclo de vida de pedidos de compra (PO), incluindo cálculo de impostos, controle de quantidades recebidas/faturadas e encerramento.","acoes":[{"nome":"add-purchase-order","desc":"Cria PO em 'draft' com itens (qty, rate, desconto%), calcula net_amount, imposto via template e grand_total."},{"nome":"update-purchase-order","desc":"Substitui os itens de um PO em 'draft' (delete+reinsert) e recalcula totais."},{"nome":"get-purchase-order","desc":"Retorna PO com itens e documentos vinculados (recebimentos e faturas)."},{"nome":"list-purchase-orders","desc":"Lista POs com filtros por company, supplier, status e intervalo de datas."},{"nome":"submit-purchase-order","desc":"Confirma PO (draft -> confirmed), gera naming_series e emite avisos (não bloqueia) de qty abaixo do min_order_qty do item_supplier."},{"nome":"cancel-purchase-order","desc":"Cancela PO somente se não houver recebimentos/faturas não-canceladas vinculadas."},{"nome":"close-purchase-order","desc":"Encerra PO parcialmente recebido (status 'closed') com motivo/responsável, preservando filhos e impedindo novos recebimentos/faturas."}],"entradas":"--supplier-id, --items (JSON: item_id, qty, rate, discount_percentage, uom, warehouse_id, required_date), --company-id, --tax-template-id, --posting-date; --purchase-order-id; --reason/--closed-by (close); filtros de lista.","saidas":"purchase_order_id, total_amount, tax_amount, grand_total; naming_series/status (submit); status='cancelled'/'closed'; warnings de min_order_qty; PO completo com items/receipts/invoices (get).","regras":"supplier deve estar 'active'; qty>0 e rate>0; net_amount=amount*(1-desc/100); imposto por tax_template_line (on_net_total/on_previous_row_total/actual, add/deduct). Ciclo: draft -> confirmed -> (partially_received/fully_received, partially_invoiced/fully_invoiced) -> closed/cancelled. update/cancel só em estados permitidos. per_received/per_invoiced atualizados pelos GRN/faturas.","efeitos":"Grava em purchase_order/purchase_order_item; submit/cancel/close apenas mudam status e naming; auditoria em todas. Nenhuma postagem direta em GL/SLE/PLE (a contabilização ocorre no GRN e na fatura). get/list são somente leitura.","precondicoes":"Fornecedor ativo e empresa existentes; tax_template opcional; item_supplier necessário para avisos de min_order_qty."},{"group":"Recebimentos (GRN)","objetivo":"Registrar a entrada física de mercadorias (Goods Receipt Note) a partir de um PO, total ou parcial, e contabilizar o estoque ao submeter.","acoes":[{"nome":"create-purchase-receipt","desc":"Cria GRN em 'draft' a partir do PO (full = itens não recebidos; partial = via --items com purchase_order_item_id), aplicando tolerância de recebimento."},{"nome":"get-purchase-receipt","desc":"Retorna o GRN com seus itens (com item_code/item_name)."},{"nome":"list-purchase-receipts","desc":"Lista GRNs filtrando por company, supplier e status."},{"nome":"submit-purchase-receipt","desc":"Submete o GRN: cria SLE positivo no depósito e GL de inventário perpétuo; atualiza received_qty e status do PO."},{"nome":"cancel-purchase-receipt","desc":"Cancela GRN submetido: reverte SLE e GL, reduz received_qty e reajusta status do PO."}],"entradas":"--purchase-order-id, --posting-date, --items (JSON: purchase_order_item_id, qty, warehouse_id, batch_id, serial_numbers); --purchase-receipt-id (get/submit/cancel); filtros de lista.","saidas":"purchase_receipt_id, total_qty, item_count; sle_entries_created/gl_entries_created e naming_series/status (submit); sle_reversals/gl_reversals (cancel).","regras":"PO deve estar 'confirmed' ou 'partially_received' (não 'closed'); qty recebida limitada ao remanescente + receipt_tolerance_pct da empresa; só submete 'draft', só cancela 'submitted'. SLE exige rate positivo (require_rate=True, nunca custo $0). per_received recalcula status do PO (partially/fully_received).","efeitos":"submit: insere stock_ledger_entry (entrada positiva) e gl_entry perpétuo (DR Estoque / CR Stock Received Not Billed); atualiza purchase_order_item.received_qty e status do PO; auditoria. cancel: reverte SLE e GL, reduz received_qty e pode voltar PO para 'confirmed'. create/get/list não postam.","precondicoes":"PO confirmado; depósito por item ou default_warehouse_id da empresa; fiscal_year aberto e cost_center existentes para o GL; contas de estoque/SRNB configuradas."},{"group":"Faturas de Compra","objetivo":"Registrar e contabilizar faturas de fornecedor (AP), com origem em PO, GRN ou avulsa, gerando GL (despesa/SRNB/imposto/AP), PLE e, se aplicável, movimentação de estoque.","acoes":[{"nome":"create-purchase-invoice","desc":"Cria fatura em 'draft' a partir de PO (qty remanescente), de GRN ou avulsa; define update_stock e suporta capitalização CWIP (--cwip-asset-id)."},{"nome":"update-purchase-invoice","desc":"Atualiza due_date e/ou itens de fatura em 'draft', recalculando totais e imposto."},{"nome":"get-purchase-invoice","desc":"Retorna a fatura com itens e payment_ledger_entry vinculados."},{"nome":"list-purchase-invoices","desc":"Lista faturas filtrando por company, supplier, status e datas."},{"nome":"submit-purchase-invoice","desc":"Submete a fatura: valida 3-way match, posta GL (despesa ou SRNB se GRN-linked, imposto de entrada, AP), cria PLE; se update_stock posta SLE + GL de estoque; trata CWIP."},{"nome":"cancel-purchase-invoice","desc":"Cancela fatura submetida/overdue/partially_paid: reverte GL (incl. COGS), PLE (delinked), SLE e acumulações CWIP; reajusta invoiced_qty do PO."},{"nome":"update-invoice-outstanding","desc":"Cross-skill (chamada por payments): aplica pagamento e reduz outstanding via payment_clearing (rejeita over-payment)."}],"entradas":"--supplier-id/--company-id/--items (avulsa), --purchase-order-id ou --purchase-receipt-id (origem), --posting-date, --due-date, --tax-template-id, --cwip-asset-id; --purchase-invoice-id (update/get/submit/cancel); --amount (outstanding).","saidas":"purchase_invoice_id, total/tax/grand_total, update_stock; naming_series/status e contagens gl_entries_created/sle_entries_created (submit); gl_reversals/sle_reversals (cancel); outstanding_amount/status (outstanding).","regras":"update_stock=1 por padrão (estoque perpétuo US); =0 quando há GRN vinculado ou CWIP. 3-way match (strict/tolerant/disabled) compara qty faturada acumulada vs recebida quando há PO. CWIP não combina com PO/GRN, não pode ser return, e capitaliza valor pré-imposto. Só submete 'draft'; só cancela submitted/overdue/partially_paid. invoiced_qty e status do PO atualizados (partially/fully_invoiced).","efeitos":"submit: insere gl_entry (DR despesa/SRNB/estoque + imposto de entrada / CR AP/payable por party=supplier), payment_ledger_entry (against o próprio invoice), e quando update_stock SLE + GL de COGS (entry_set='cogs'); registra acumulação CWIP. cancel: reverte GL/SLE, marca PLE delinked, reverte CWIP e invoiced_qty. update-invoice-outstanding altera outstanding/status. get/list somente leitura.","precondicoes":"Fornecedor e empresa existentes; contas payable/expense/SRNB/stock e imposto configuradas; fiscal_year aberto; para CWIP, asset 'under_construction' e conta CWIP resolvível."},{"group":"Notas de Débito","objetivo":"Emitir devolução/ajuste a fornecedor (debit note) contra uma fatura de compra existente, reduzindo o passivo de contas a pagar.","acoes":[{"nome":"create-debit-note","desc":"Cria a nota de débito como purchase_invoice com is_return=1 e quantidades/valores negativos, vinculada à fatura original (return_against)."}],"entradas":"--against-invoice-id, --items (JSON: item_id, qty, rate — rate herda da fatura original se omitido), --posting-date, --reason.","saidas":"debit_note_id, against_invoice_id e total_amount (negativo).","regras":"Fatura original deve estar submitted/partially_paid/paid/overdue; qty>0 por item (armazenada negativa); rate>0 (busca da fatura original quando não informada); herda supplier/update_stock/company da original; nasce em 'draft'.","efeitos":"Grava purchase_invoice (is_return=1) + purchase_invoice_item negativos; auditoria (create-debit-note). A contabilização efetiva (GL reverso despesa/SRNB, imposto e DR AP, e PLE negativo) ocorre ao chamar submit-purchase-invoice sobre esse documento (voucher_type='debit_note').","precondicoes":"Fatura de compra original existente em status válido; itens com referência a item da fatura para herdar rate."},{"group":"Custos de Importação","objetivo":"Distribuir custos adicionais (frete, seguro, taxas) sobre itens de recebimentos para compor o custo final (landed cost) e contabilizar a capitalização no estoque.","acoes":[{"nome":"add-landed-cost-voucher","desc":"Cria o voucher já 'submitted', rateia cada encargo entre os itens dos GRNs por quantidade ou valor, calcula final_rate e posta GL."}],"entradas":"--purchase-receipt-ids (JSON de GRNs submetidos), --charges (JSON: description, amount, allocation_method qty|value, expense_account_id), --company-id.","saidas":"landed_cost_voucher_id, total_landed_cost e gl_entries_created.","regras":"GRNs devem estar 'submitted' e conter itens; amount de cada charge>0; rateio por qty ou value com ajuste do resíduo no último item; final_rate=original_rate + encargo/qty; voucher criado diretamente como 'submitted' (sem etapa de rascunho).","efeitos":"Grava landed_cost_voucher, landed_cost_charge e landed_cost_item; posta gl_entry por encargo (DR conta de Estoque / CR conta de despesa informada) quando expense_account_id presente; auditoria. (Não reescreve SLE existentes; registra apenas final_rate nos landed_cost_item.)","precondicoes":"Empresa existente; GRNs submetidos com itens; conta de estoque e conta de despesa do encargo configuradas; fiscal_year/cost_center para o GL."},{"group":"Blanket PO (Pedido Guarda-Chuva)","objetivo":"Gerenciar acordos-quadro de compra com fornecedor (quantidade e preço acordados por período) dos quais se faz drawdown via POs.","acoes":[{"nome":"add-blanket-po","desc":"Cria blanket order tipo 'buying' em 'draft' com itens (qty, rate) e janela de validade (valid_from/valid_to)."},{"nome":"submit-blanket-po","desc":"Ativa o acordo (draft -> active)."},{"nome":"get-blanket-po","desc":"Retorna o blanket order com seus itens."},{"nome":"list-blanket-pos","desc":"Lista blanket orders de compra filtrando por company, supplier e status."}],"entradas":"--supplier-id, --items (JSON: item_id, qty, rate, uom), --company-id, --valid-from, --valid-to; --blanket-order-id (submit/get); filtros de lista.","saidas":"blanket_order_id, supplier_id, total_qty, valid_from/valid_to; doc_status='active' (submit); registro + itens (get); lista paginada.","regras":"supplier 'active'; valid_to deve ser posterior a valid_from; qty>0 e rate>0; tipo fixo 'buying'; só ativa se 'draft'. ordered_qty acompanha o consumo do acordo.","efeitos":"Grava blanket_order e blanket_order_item; submit muda status para 'active'; auditoria. Nenhuma postagem em GL/SLE/PLE. get/list somente leitura.","precondicoes":"Fornecedor ativo e empresa existentes."},{"group":"Conversão para PO","objetivo":"Gerar pedidos de compra automaticamente a partir de um blanket order (drawdown) ou de um pedido de venda (back-to-back SO -> PO por fornecedor).","acoes":[{"nome":"create-po-from-blanket","desc":"Cria PO em 'draft' consumindo itens de um blanket ativo, respeitando a qty remanescente e herdando o rate acordado; atualiza ordered_qty do acordo."},{"nome":"create-po-from-so","desc":"Cria um PO por fornecedor a partir dos itens de um sales order, resolvendo o fornecedor padrão de cada item via item_supplier (menor priority)."}],"entradas":"--blanket-order-id, --items (JSON: item_id, qty, rate?, warehouse_id), --posting-date, --tax-template-id (blanket); --sales-order-id, --posting-date, --tax-template-id (SO).","saidas":"purchase_order_id, blanket_order_id, total_amount, grand_total; ou sales_order_id, purchase_orders_created, lista de POs e items_without_supplier.","regras":"Blanket deve estar 'active', tipo 'buying' e não expirado; qty solicitada <= remanescente (quantity-ordered_qty); rate herda do acordo se omitido. SO deve estar 'draft'/'confirmed'; agrupa itens por fornecedor; ignora fornecedores não-ativos; reporta itens sem fornecedor configurado. POs criados em 'draft'.","efeitos":"Grava purchase_order/purchase_order_item; no blanket atualiza ordered_qty (item e total); auditoria (create-po-from-blanket / create-po-from-so). Nenhuma postagem em GL/SLE/PLE (POs nascem em draft).","precondicoes":"Blanket ativo dentro da validade; ou sales_order com itens e mapeamentos item_supplier para resolver fornecedores; fornecedores ativos."},{"group":"Contas Recorrentes","objetivo":"Definir templates de faturas de compra recorrentes (aluguéis, assinaturas) e gerar automaticamente as faturas devidas conforme a frequência, com opção de auto-submissão contábil.","acoes":[{"nome":"add-recurring-bill-template","desc":"Cria template em 'draft' com itens, frequência, start/end_date e flag auto_submit; next_bill_date inicia em start_date."},{"nome":"list-recurring-bill-templates","desc":"Lista templates ordenados por next_bill_date, filtrando por company, supplier e status."},{"nome":"generate-recurring-bills","desc":"Cron: gera purchase_invoice dos templates 'active' com next_bill_date<=as_of_date, avança datas e completa o template ao passar do end_date."}],"entradas":"--supplier-id, --items (JSON), --frequency (weekly|monthly|quarterly|semi_annually|annually), --start-date, --end-date, --tax-template-id, --auto-submit, --company-id; --as-of-date (geração); filtros de lista.","saidas":"template_id, frequency, start_date, next_bill_date; lista de templates; bills_generated, templates_processed/completed, lista de bills e errors.","regras":"frequency validada; supplier 'active'; template nasce 'draft'; geração só processa status 'active' e dentro de end_date; due_date = posting + 30 dias; next_bill_date avança por frequência (clamp ao último dia do mês); template vira 'completed' quando próximo vencimento ultrapassa end_date. Erros por template são coletados sem abortar o lote.","efeitos":"add: grava recurring_bill_template/_item. generate: cria purchase_invoice/_item por template; se auto_submit, gera naming e posta gl_entry (DR despesa / CR AP por party=supplier) e marca 'submitted'; atualiza last_bill_date/next_bill_date e status do template; auditoria. list somente leitura.","precondicoes":"Fornecedor ativo e empresa existentes; para auto_submit, contas payable e expense da empresa configuradas e fiscal_year aberto."},{"group":"Políticas de Compra","objetivo":"Configurar parâmetros de governança de compras por empresa (tolerância de recebimento e política de 3-way match) e definir UOM de compra de itens; expõe também um resumo geral.","acoes":[{"nome":"update-receipt-tolerance","desc":"Define receipt_tolerance_pct da empresa (0-100), usado em GRN e no 3-way match tolerante."},{"nome":"update-three-way-match-policy","desc":"Define a política three_way_match_policy da empresa: strict | tolerant | disabled."},{"nome":"set-item-purchase-uom","desc":"Cria/atualiza um uom_conversion (purchase UOM -> stock UOM) com conversion_factor para um item."},{"nome":"status","desc":"Resumo de compras da empresa: contagem de fornecedores, POs e faturas por status e total em aberto."}],"entradas":"--company-id e --tolerance-pct (tolerância); --company-id e --policy (match); --item-id, --purchase-uom, --conversion-factor (UOM); --company-id opcional (status, usa a primeira empresa se omitido).","saidas":"company_id + receipt_tolerance_pct; company_id + three_way_match_policy; uom_conversion_id/conversion_factor/action; resumo com suppliers, purchase_orders, purchase_invoices e total_outstanding.","regras":"tolerance_pct entre 0 e 100; policy restrita a strict/tolerant/disabled; conversion_factor>0; valida existência de company/item. A política e a tolerância são consumidas em create-purchase-receipt e em submit-purchase-invoice (3-way match).","efeitos":"update-receipt-tolerance e update-three-way-match-policy alteram colunas na tabela company; set-item-purchase-uom grava/atualiza uom_conversion; todas auditadas. status é somente leitura. Nenhuma postagem em GL/SLE/PLE.","precondicoes":"Empresa existente (e item existente para UOM)."}]},"inventory":{"module":"inventory","display":"Estoque","functionalities":[{"group":"Itens","objetivo":"Cadastrar e manter os itens do catálogo (produtos estocáveis, não estocáveis e serviços), incluindo importação em massa por CSV e resolução por nome solto. É a base para todas as movimentações de estoque, preços e compras/vendas.","acoes":[{"nome":"add-item","desc":"Cria um novo item com código, nome, grupo, tipo, UOM, método de valoração, flags de lote/série e preço padrão."},{"nome":"update-item","desc":"Atualiza nome, nível/qtd de reposição, preço padrão e status (active/disabled) de um item existente."},{"nome":"get-item","desc":"Retorna o item com resumo de saldos de estoque por depósito e totais de qtd/valor."},{"nome":"list-items","desc":"Lista/filtra itens por grupo, tipo, busca textual, empresa (via grupo) ou depósito com estoque, paginado."},{"nome":"resolve-item","desc":"Resolve uma frase solta/plural do usuário em candidatos rankeados via cascata determinística de 4 tiers (somente leitura)."},{"nome":"import-items","desc":"Importa itens em massa de um CSV (item_code globalmente único), pulando duplicados."}],"entradas":"add-item: --item-code, --item-name (obrigatórios), --item-type (stock|non_stock|service), --valuation-method (moving_average|fifo), --item-group, --stock-uom, --has-batch, --has-serial, --standard-rate, --custom-fields. update-item: --item-id + campos opcionais. get-item: --item-id. list-items: --item-group, --item-type, --search, --company-id, --warehouse-id, --limit/--offset. resolve-item: --name. import-items: --csv-path.","saidas":"add-item: item_id, item_code, item_name (+ custom fields). get-item: dados do item, stock_balances[] por depósito, total_qty, total_stock_value. list-items: items[], total_count, paginação. resolve-item: matched, single/multiple_match, match_type, candidates[]. import-items: imported, skipped, total_rows.","regras":"item_type deve estar em (stock|non_stock|service) e valuation_method em (moving_average|fifo); is_stock_item=1 só para tipo stock. item_group é normalizado de nome para id e deve existir. standard_rate é arredondado para moeda. Item disabled não pode ser atualizado a menos que se reative (--status active). resolve-item é determinístico: 4 tiers (exato case-insensitive, singularizado, substring LIKE, token-AND) parando no primeiro com resultado. import-items: item_code é globalmente único, valuation_method default moving_average, duplicados são pulados.","efeitos":"Escrita na tabela item (insert/update). Grava custom fields (add-item). Grava trilha de auditoria (audit) em add-item/update-item. import-items insere itens mas NÃO grava auditoria por linha. resolve-item, get-item e list-items são somente leitura. Nenhuma postagem em GL ou SLE.","precondicoes":"Banco com tabela company existente. Para vincular grupo, o item_group deve existir. Para import-items, arquivo .csv válido e legível; grupos referenciados devem existir (senão item fica sem grupo)."},{"group":"Grupos de Itens","objetivo":"Organizar itens em uma hierarquia de grupos (item_group) opcionalmente por empresa e com grupo pai. Usado para classificação e filtros de itens e regras de preço.","acoes":[{"nome":"add-item-group","desc":"Cria um grupo de itens com nome, empresa opcional e grupo pai opcional."},{"nome":"list-item-groups","desc":"Lista grupos filtrando por empresa e/ou grupo pai, paginado."}],"entradas":"add-item-group: --name (obrigatório), --company-id, --parent-id. list-item-groups: --company-id, --parent-id, --limit/--offset.","saidas":"add-item-group: item_group_id, name. list-item-groups: item_groups[], total_count, limit, offset, has_more.","regras":"Nome é obrigatório. Se --parent-id informado, o grupo pai deve existir. Nome único (por empresa quando company_id presente) — violação de integridade retorna erro de duplicado.","efeitos":"Insert na tabela item_group e trilha de auditoria em add-item-group. list-item-groups é somente leitura. Nenhuma postagem em GL/SLE.","precondicoes":"Banco com tabela company. Grupo pai (se informado) deve existir."},{"group":"Depósitos","objetivo":"Cadastrar e manter depósitos (warehouses) por empresa, com tipo, hierarquia (pai) e conta contábil de estoque vinculada. Depósitos são onde quantidades e valores de estoque residem.","acoes":[{"nome":"add-warehouse","desc":"Cria um depósito com nome, empresa, tipo, pai opcional, conta contábil opcional e flag is_group."},{"nome":"update-warehouse","desc":"Atualiza nome e/ou conta contábil de um depósito (resolvido por id ou nome)."},{"nome":"list-warehouses","desc":"Lista depósitos de uma empresa filtrando por pai e/ou tipo, paginado."}],"entradas":"add-warehouse: --warehouse-name/--name e --company-id (obrigatórios), --warehouse-type (stores|production|transit|rejected), --parent-id, --account-id, --is-group. update-warehouse: --warehouse-id (id ou nome) + --name/--account-id. list-warehouses: --company-id/--company, --parent-id, --warehouse-type.","saidas":"add-warehouse: warehouse_id, name. update-warehouse: warehouse_id, updated_fields. list-warehouses: warehouses[], total_count, paginação.","regras":"warehouse_type deve estar em (stores|production|transit|rejected), default stores. Empresa deve existir. Pai e conta (se informados) devem existir. update-warehouse resolve o alvo por id OU nome e normaliza para id; exige ao menos um campo a atualizar; valida account_id se informado.","efeitos":"Insert/update na tabela warehouse e trilha de auditoria em add-warehouse/update-warehouse. list-warehouses é somente leitura. Nenhuma postagem em GL/SLE.","precondicoes":"Empresa (--company-id) existente. account_id (se informado) deve referenciar conta existente — usado depois como conta de Estoque (Stock-in-Hand) nas postagens GL."},{"group":"Movimentações","objetivo":"Registrar entradas de estoque (stock_entry) nos tipos recebimento, saída, transferência e fabricação, com ciclo de vida rascunho -> submetido -> cancelado. No submit, gera SLE e postagens GL; no cancel, reverte ambos.","acoes":[{"nome":"add-stock-entry","desc":"Cria uma entrada de estoque em rascunho com itens, quantidades, depósitos origem/destino e taxas."},{"nome":"get-stock-entry","desc":"Retorna a entrada de estoque com suas linhas de item."},{"nome":"list-stock-entries","desc":"Lista entradas filtrando por empresa, tipo, status e intervalo de datas, paginado."},{"nome":"submit-stock-entry","desc":"Submete um rascunho: posta SLE (razão de estoque) e GL de inventário perpétuo, muda status para submitted."},{"nome":"cancel-stock-entry","desc":"Cancela uma entrada submetida: reverte SLE e GL e muda status para cancelled."}],"entradas":"add-stock-entry: --entry-type (receive|issue|transfer|manufacture), --company-id, --posting-date, --items (JSON array com item_id, qty, rate, from/to_warehouse_id, batch_id, serial_numbers) — todos obrigatórios. submit/cancel/get-stock-entry: --stock-entry-id. list-stock-entries: --company-id, --entry-type, --status-filter, --from-date/--to-date.","saidas":"add-stock-entry: stock_entry_id, naming_series, total_incoming_value, total_outgoing_value, value_difference. submit: sle_entries_created, gl_entries_created. cancel: reversed, sle_reversals, gl_reversals. get: cabeçalho + items[].","regras":"entry-type mapeado para material_receipt/issue/transfer/manufacture. Empresa deve existir; items array não vazio; cada item deve existir e qty>0; rate<=0 cai para standard_rate do item. Depósitos validados por tipo (receipt exige to; issue exige from; transfer exige ambos; manufacture exige from ou to), com fallback para default_warehouse_id da empresa. SLE: receipt +qty no destino (require_rate=True, não permite valorar a 0), issue -qty na origem, transfer -origem/+destino, manufacture +FG destino/-MP origem. Submit só de draft; cancel só de submitted.","efeitos":"add-stock-entry: insert em stock_entry (status draft) e stock_entry_item, mais auditoria. submit-stock-entry: insere stock_ledger_entry via insert_sle_entries, gera gl_entry via create_perpetual_inventory_gl/insert_gl_entries, muda status para submitted, auditoria. cancel-stock-entry: reverte SLE (reverse_sle_entries) e GL (reverse_gl_entries), muda status para cancelled, auditoria. get/list são somente leitura.","precondicoes":"Empresa existente; itens válidos; depósitos (per-item ou default da empresa) definidos. Para GL no submit: fiscal_year aberto cobrindo a posting_date, cost_center não-grupo da empresa e contas de estoque configuradas (caso contrário a postagem GL pode falhar/ser pulada)."},{"group":"Razão de Estoque (SLE)","objetivo":"Gateway transversal para outras skills (selling/buying) criarem e reverterem entradas no razão de estoque (stock_ledger_entry) para seus vouchers (ex.: Delivery Note, Purchase Receipt), canonizando o voucher_type.","acoes":[{"nome":"create-stock-ledger-entries","desc":"Cria entradas SLE para um voucher externo (chamado por selling/buying), atribuindo fiscal_year."},{"nome":"reverse-stock-ledger-entries","desc":"Reverte as entradas SLE de um voucher externo (ex.: cancelamento de nota)."}],"entradas":"create: --voucher-type, --voucher-id, --posting-date, --company-id, --entries (JSON array). reverse: --voucher-type, --voucher-id, --posting-date.","saidas":"create: sle_ids[], count. reverse: reversal_ids[], count.","regras":"voucher_type é canonicalizado para snake_case na fronteira (FINDING-006) para não quebrar filtros downstream. entries deve ser array não vazio. fiscal_year é derivado da posting_date e injetado em cada entrada. A lógica de valoração/saldo fica em insert_sle_entries/reverse_sle_entries da lib compartilhada.","efeitos":"create: insere linhas em stock_ledger_entry e grava auditoria. reverse: insere linhas de reversão em stock_ledger_entry e grava auditoria. NÃO posta GL diretamente (a skill chamadora cuida do GL). Sem mudança de status de documento próprio.","precondicoes":"Empresa existente; posting_date dentro de fiscal_year aberto (senão fiscal_year fica nulo). Voucher de origem (gerenciado por outra skill) já criado."},{"group":"Saldos e Relatórios","objetivo":"Consultar saldos de estoque por item/depósito, relatórios de saldo por empresa, detalhamento do razão de estoque e um resumo geral do estoque da empresa. Tudo somente leitura.","acoes":[{"nome":"get-stock-balance","desc":"Retorna qtd, taxa de valoração e valor de estoque de um item em um depósito."},{"nome":"stock-balance-report","desc":"Resumo de saldos de todos os itens (com saldo != 0) de uma empresa, opcionalmente por depósito (alias: stock-balance)."},{"nome":"stock-ledger-report","desc":"Lista detalhada de entradas do razão de estoque (não canceladas) com filtros de item, depósito e datas."},{"nome":"status","desc":"Resumo do estoque da empresa: contagem de itens, depósitos, entradas por status e valor total de estoque."}],"entradas":"get-stock-balance: --item-id, --warehouse-id (obrigatórios). stock-balance-report: --company-id/--company, --warehouse-id. stock-ledger-report: --item-id, --warehouse-id, --from-date/--to-date, --limit/--offset. status: --company-id/--company.","saidas":"get-stock-balance: qty, valuation_rate, stock_value. stock-balance-report: report[] por item/depósito, total_stock_value, row_count. stock-ledger-report: entries[], count. status: items, warehouses, stock_entries{draft/submitted/cancelled/total}, total_stock_value.","regras":"Saldos consideram apenas SLE com is_cancelled=0. stock-balance-report agrega via decimal_sum e usa a valuation_rate do SLE mais recente (correlated subquery), filtrando saldos != 0. status soma stock_value_difference dos SLE não cancelados (joined a warehouse da empresa) para o valor total.","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa existente (relatórios por empresa). Item/depósito existentes para get-stock-balance. SLE já postados para haver saldos."},{"group":"Lotes","objetivo":"Cadastrar lotes (batch) por item com datas de fabricação e validade, e listar lotes, inclusive filtrando por lotes que possuem saldo positivo em um depósito.","acoes":[{"nome":"add-batch","desc":"Cria um lote vinculado a um item com datas opcionais de fabricação e validade."},{"nome":"list-batches","desc":"Lista lotes por item; com --warehouse-id filtra apenas lotes com saldo > 0 naquele depósito."}],"entradas":"add-batch: --item-id, --batch-name (obrigatórios), --manufacturing-date, --expiry-date. list-batches: --item-id, --warehouse-id, --limit/--offset.","saidas":"add-batch: batch_id, batch_name. list-batches: batches[], total_count, paginação.","regras":"Item deve existir. batch_name é validado por integridade (duplicado retorna erro). list-batches com warehouse usa decimal_sum sobre SLE não cancelados e HAVING saldo > 0 para mostrar só lotes com estoque.","efeitos":"add-batch: insert na tabela batch e auditoria. list-batches é somente leitura. Nenhuma postagem GL/SLE.","precondicoes":"Item existente. O batch_id é então referenciável nas linhas de stock_entry e nos SLE."},{"group":"Números de Série","objetivo":"Registrar números de série (serial_number) por item, com depósito, lote e status (active/delivered/returned/scrapped), e listá-los com filtros.","acoes":[{"nome":"add-serial-number","desc":"Registra um número de série para um item, opcionalmente com depósito e lote, status inicial active."},{"nome":"list-serial-numbers","desc":"Lista números de série filtrando por item, depósito e status, paginado."}],"entradas":"add-serial-number: --item-id, --serial-no (obrigatórios), --warehouse-id, --batch-id. list-serial-numbers: --item-id, --warehouse-id, --serial-status, --limit/--offset.","saidas":"add-serial-number: serial_number_id, serial_no. list-serial-numbers: serial_numbers[] (com item_code/name), total_count, paginação.","regras":"Item deve existir; serial_no validado por integridade (duplicado retorna erro); status inicial fixado em 'active'. Em list, --serial-status deve estar em (active|delivered|returned|scrapped).","efeitos":"add-serial-number: insert na tabela serial_number e auditoria. list-serial-numbers é somente leitura. Nenhuma postagem GL/SLE; o status do serial não é alterado por essas ações (apenas registrado).","precondicoes":"Item existente. Depósito/lote (se informados) já cadastrados."},{"group":"Preços e Regras","objetivo":"Gerenciar listas de preço, preços de item por lista (com faixas de quantidade e validade), consulta do preço aplicável e regras de precificação/desconto por item, grupo, cliente ou grupo de cliente.","acoes":[{"nome":"add-price-list","desc":"Cria uma lista de preços com moeda e flags de compra/venda."},{"nome":"add-item-price","desc":"Define o preço de um item em uma lista, com min_qty e validade opcionais."},{"nome":"get-item-price","desc":"Retorna o preço aplicável de um item numa lista para uma quantidade/data, com fallback (somente leitura)."},{"nome":"add-pricing-rule","desc":"Cria uma regra de preço/desconto aplicável a item, grupo, cliente ou grupo de cliente."}],"entradas":"add-price-list: --name, --currency, --is-buying, --is-selling. add-item-price: --item-id, --price-list-id, --rate (obrigatórios), --min-qty, --valid-from/--valid-to. get-item-price: --item-id, --price-list-id, --qty. add-pricing-rule: --name, --applies-to (item|item_group|customer|customer_group), --company-id (obrigatórios), --entity-id, --discount-percentage, --pricing-rule-rate, --min-qty/--max-qty, --valid-from/--valid-to, --priority.","saidas":"add-price-list: price_list_id, name. add-item-price: item_price_id, rate. get-item-price: linha do item_price aplicável. add-pricing-rule: pricing_rule_id, name.","regras":"currency default USD. add-item-price valida item e price_list e arredonda rate. get-item-price escolhe a faixa mais específica (min_qty <= qty, dentro da validade, ordenando min_qty DESC); se nada casar, faz fallback para o preço mais recente do item na lista; se nenhum, erro. add-pricing-rule: applies_to restrito ao enum; priority default 0.","efeitos":"Inserts em price_list, item_price e pricing_rule com auditoria (add-price-list, add-item-price, add-pricing-rule). get-item-price é somente leitura. Nenhuma postagem GL/SLE.","precondicoes":"Para add-item-price: item e price_list existentes. Para add-pricing-rule: empresa existente; entity_id deve referenciar a entidade do applies_to."},{"group":"Reconciliação","objetivo":"Registrar uma reconciliação de estoque (contagem física) por depósito, calculando diferenças de quantidade e valor, com ciclo rascunho -> submetido; no submit posta SLE e GL apenas para as diferenças.","acoes":[{"nome":"add-stock-reconciliation","desc":"Cria uma reconciliação em rascunho calculando diferenças entre saldo atual e contado por item/depósito."},{"nome":"submit-stock-reconciliation","desc":"Submete a reconciliação: posta SLE das diferenças de qtd e GL de ajuste de valor, muda status para submitted."}],"entradas":"add-stock-reconciliation: --posting-date, --items (JSON array com item_id, warehouse_id, qty, valuation_rate), --company-id — todos obrigatórios. submit-stock-reconciliation: --stock-reconciliation-id.","saidas":"add: stock_reconciliation_id, naming_series, difference_amount, item_count. submit: sle_entries_created, gl_entries_created.","regras":"Empresa deve existir; cada linha exige item_id e warehouse_id. Calcula qty_diff = contado - atual e amount_diff = valor contado - valor atual (usando saldo/valoração corrente). No submit (só de draft), gera SLE apenas para linhas com qty_diff != 0 (incoming_rate = valoração se diferença positiva, senão 0) e GL de ajuste usando a conta account_type='stock_adjustment' da empresa como contra.","efeitos":"add-stock-reconciliation: insert em stock_reconciliation (draft) e stock_reconciliation_item, auditoria. submit-stock-reconciliation: insere stock_ledger_entry (insert_sle_entries) e gl_entry (create_perpetual_inventory_gl/insert_gl_entries) para as diferenças, muda status para submitted, auditoria. (Não há ação de cancelar reconciliação neste arquivo.)","precondicoes":"Empresa existente; itens/depósitos válidos com saldo conhecido. Para o GL: fiscal_year aberto, cost_center e conta de ajuste de estoque (stock_adjustment) configurada na empresa."},{"group":"Revaloração","objetivo":"Revalorar o estoque de um item em um depósito alterando a taxa de valoração sem mexer na quantidade, em uma ação imediata (sem rascunho); registra SLE, GL de ajuste e um documento stock_revaluation. Permite listar, consultar e cancelar.","acoes":[{"nome":"revalue-stock","desc":"Revalora um item/depósito para uma nova taxa, postando SLE (qty=0) e GL do ajuste; posta imediatamente como submitted."},{"nome":"list-stock-revaluations","desc":"Lista revalorações de uma empresa, paginado."},{"nome":"get-stock-revaluation","desc":"Retorna uma revaloração com suas entradas SLE e GL associadas."},{"nome":"cancel-stock-revaluation","desc":"Cancela uma revaloração submetida revertendo SLE e GL e mudando status para cancelled."}],"entradas":"revalue-stock: --item-id, --warehouse-id, --new-rate, --posting-date (obrigatórios), --reason. list-stock-revaluations: --company-id/--company, --limit/--offset. get/cancel-stock-revaluation: --revaluation-id.","saidas":"revalue-stock: revaluation_id, naming_series, old/new_rate, adjustment_amount, gl_entries_created. list: revaluations[], total_count. get: documento + sle_entries[] + gl_entries[]. cancel: cancelled=True.","regras":"new_rate deve ser não-negativo e diferente do atual; item deve ser stock item; depósito deve existir e fornece company_id; exige saldo (current_qty>0). ajuste = (qty*new_rate) - valor_atual. GL: se ajuste>0 DR Estoque/CR Stock Adjustment; se <0 inverso (usa conta do depósito ou account_type='stock'/'stock_adjustment' da empresa). cancel só de status submitted.","efeitos":"revalue-stock: insere stock_ledger_entry (actual_qty=0, registrando nova valoração e stock_value_difference), gl_entry de ajuste, e documento stock_revaluation (status submitted); auditoria. cancel-stock-revaluation: reverte SLE e GL, muda status para cancelled, auditoria. list/get são somente leitura.","precondicoes":"Item stock e depósito existentes com saldo > 0. Contas de estoque/ajuste configuradas e (para GL) fiscal_year aberto e cost_center da empresa."},{"group":"Reposição/Projeção","objetivo":"Apoiar planejamento de compras: identificar itens com estoque no/abaixo do nível de reposição e calcular a quantidade projetada de um item em um depósito (saldo + pedidos de compra pendentes - reservas de venda). Somente leitura.","acoes":[{"nome":"check-reorder","desc":"Lista itens ativos cujo estoque corrente (na empresa) está no ou abaixo do reorder_level, com shortfall e reorder_qty."},{"nome":"get-projected-qty","desc":"Calcula projected_qty = actual_qty + ordered_qty (PO aberto) - reserved_qty (SO confirmado) para item/depósito."}],"entradas":"check-reorder: --company-id/--company. get-projected-qty: --item-id, --warehouse-id (obrigatórios).","saidas":"check-reorder: items_below_reorder, items[] (current_stock, reorder_level, reorder_qty, shortfall). get-projected-qty: actual_qty, ordered_qty, reserved_qty, projected_qty.","regras":"check-reorder considera só itens com reorder_level definido (não nulo/vazio/'0') e status active; soma actual_qty de SLE não cancelados da empresa. get-projected-qty: ordered_qty = soma de (quantity - received_qty) de purchase_order_item de POs em status confirmed/partially_received; reserved_qty = soma de (quantity - delivered_qty) de sales_order_item de SOs confirmed/partially_delivered; pega linhas do depósito ou sem depósito (NULL).","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa existente; itens com reorder_level configurado (check-reorder). Para get-projected-qty: item e depósito existentes; tabelas purchase_order(_item) e sales_order(_item) populadas pelas skills de compras/vendas."},{"group":"Variantes","objetivo":"Gerenciar itens com variantes: definir atributos no item template (marcando-o como template), criar variantes individuais ou gerar todas as combinações (produto cartesiano) e listar as variantes existentes.","acoes":[{"nome":"add-item-attribute","desc":"Adiciona um atributo (nome + valores JSON) ao item template e marca has_variants=1."},{"nome":"create-item-variant","desc":"Cria uma variante a partir do template com valores específicos de atributos (JSON object)."},{"nome":"generate-item-variants","desc":"Gera todas as variantes possíveis (produto cartesiano dos atributos do template), pulando as já existentes."},{"nome":"list-item-variants","desc":"Lista todas as variantes de um template com seus atributos."}],"entradas":"add-item-attribute: --item-id, --attribute-name, --attribute-values (JSON array). create-item-variant: --template-item-id, --attributes (JSON object). generate/list-item-variants: --template-item-id.","saidas":"add-item-attribute: attribute_id, values. create-item-variant: variant_id, item_code, item_name, attributes. generate-item-variants: created, skipped, skipped_codes, variants[]. list-item-variants: count, variants[] com atributos.","regras":"add-item-attribute exige item existente, não variante (variant_of nulo), valores array não vazio, nome de atributo único no item; marca o item como template (has_variants=1). create/generate exigem template com has_variants=1; valores de atributo devem constar na definição do template. Código da variante = item_code-Val1-Val2 e nome = nome (Val1-Val2); variantes duplicadas são puladas/rejeitadas. Variante herda grupo, tipo, UOM, valoração, flags e standard_rate do template e grava variant_of.","efeitos":"Insert em item_attribute e update em item (has_variants=1) em add-item-attribute; insert de novos itens (variantes) + item_attribute em create/generate. Auditoria em add-item-attribute e create-item-variant (generate NÃO grava auditoria). list é somente leitura. Nenhuma postagem GL/SLE.","precondicoes":"Item template existente. Para criar variantes: atributos definidos no template (add-item-attribute) com valores."},{"group":"Fornecedores de Item","objetivo":"Vincular itens a fornecedores com quantidade mínima de pedido, prazo de entrega (lead time) e prioridade, apoiando reposição e compras; e listar esses vínculos por item ou por fornecedor.","acoes":[{"nome":"add-item-supplier","desc":"Cria um vínculo item-fornecedor com min_order_qty, lead_time_days e priority."},{"nome":"list-item-suppliers","desc":"Lista fornecedores de um item ou itens de um fornecedor (ordenados por prioridade)."}],"entradas":"add-item-supplier: --item-id, --supplier-id (obrigatórios), --min-order-qty, --lead-time-days, --priority. list-item-suppliers: --item-id e/ou --supplier-id (ao menos um obrigatório).","saidas":"add-item-supplier: item_supplier_id, item_id, supplier_id, min_order_qty, lead_time_days, priority. list-item-suppliers: count, item_suppliers[] (com item_code/name e supplier_name).","regras":"Item e fornecedor devem existir. min_order_qty arredondado (default 0); priority default 0. Vínculo item-fornecedor duplicado é rejeitado por integridade. list exige ao menos um filtro (--item-id ou --supplier-id).","efeitos":"Insert na tabela item_supplier e auditoria em add-item-supplier. list-item-suppliers é somente leitura. Nenhuma postagem GL/SLE.","precondicoes":"Item e fornecedor (tabela supplier, da skill de compras) já cadastrados."}]},"billing":{"module":"billing","display":"Faturamento por Uso","functionalities":[{"group":"Medidores","objetivo":"Cadastrar e gerenciar medidores (pontos de consumo) vinculados a um cliente, com tipo de serviço, ponto/endereço de serviço, plano de tarifa opcional e ciclo de vida operacional.","acoes":[{"nome":"add-meter","desc":"Registra um novo medidor para um cliente, gerando meter_number sequencial; status inicial fixo 'active'."},{"nome":"update-meter","desc":"Atualiza configuracao do medidor: ponto de servico (--name -> service_point_id), status e/ou plano de tarifa."},{"nome":"get-meter","desc":"Retorna o medidor com a ultima leitura (latest_reading) e a contagem total de leituras."},{"nome":"list-meters","desc":"Lista medidores com join no nome do cliente e filtros por cliente, tipo de servico e status, paginado."}],"entradas":"add-meter: --customer-id, --meter-type (obrigatorios), --unit (vira metadata.uom), --name (ponto de servico), --address, --rate-plan-id, --install-date. update-meter: --meter-id + --name/--status/--rate-plan-id. list-meters: --customer-id, --meter-type, --status, --limit, --offset.","saidas":"add-meter/update-meter/get-meter retornam {meter:{...}} (get-meter adiciona latest_reading e reading_count). list-meters retorna {meters:[...], total_count, limit, offset, has_more}.","regras":"meter-type deve estar em VALID_SERVICE_TYPES (electricity, water, gas, telecom, saas, parking, rental, waste, custom). status deve estar em VALID_METER_STATUSES (active, disconnected, removed, suspended). Cliente deve existir; se informado, rate-plan deve existir. update-meter exige ao menos um campo; --name grava em service_point_id. company_id e herdado do cliente.","efeitos":"Insere/atualiza linha em meter; add-meter consome sequencia de naming (get_next_name) e grava metadata.uom. Registra auditoria (audit) em add-meter e update-meter. Nenhuma postagem em GL, SLE de estoque ou payment_ledger.","precondicoes":"Tabela company instalada (REQUIRED_TABLES). Cliente (customer) existente com company_id. Plano de tarifa existente se --rate-plan-id for informado."},{"group":"Leituras","objetivo":"Registrar leituras de medidor calculando consumo automaticamente a partir da leitura anterior, com tipo e fonte da leitura, e manter o ultimo valor/data no medidor.","acoes":[{"nome":"add-meter-reading","desc":"Registra leitura com calculo automatico de consumo (delta vs leitura anterior) e tratamento de rollover."},{"nome":"list-meter-readings","desc":"Lista leituras de um medidor com filtros de data (from/to), ordenadas por data desc, paginado."}],"entradas":"add-meter-reading: --meter-id, --reading-date, --reading-value (obrigatorios), --reading-type (default 'actual'), --source (default 'manual'), --uom. list-meter-readings: --meter-id (obrigatorio), --from-date, --to-date, --limit, --offset.","saidas":"add-meter-reading retorna {reading:{...}} com previous_reading_value e consumption. list-meter-readings retorna {readings:[...], total_count, limit, offset, has_more}.","regras":"reading-type em VALID_READING_TYPES (actual, estimated, adjusted, rollover); source em VALID_READING_SOURCES (manual, smart_meter, api, import, estimated). consumption = leitura - leitura anterior; se delta < 0 trata como rollover (consumption = valor lido) e converte reading_type 'actual' em 'rollover'. UOM resolvida do argumento ou de metadata.uom do medidor. validated gravado como 0 (nao validada).","efeitos":"Insere linha em meter_reading e atualiza meter.last_reading_date/last_reading_value/updated_at na mesma transacao. Registra auditoria. Nenhuma postagem em GL, SLE de estoque ou payment_ledger.","precondicoes":"Medidor (meter) existente. Para calculo de consumo, leitura anterior registrada no medidor (last_reading_value)."},{"group":"Eventos de Uso","objetivo":"Ingerir eventos de uso (quantidade por timestamp) por medidor, de forma unitaria ou em lote, com deduplicacao por idempotency_key, para posterior agregacao no bill run.","acoes":[{"nome":"add-usage-event","desc":"Registra um evento de uso unico; se idempotency_key ja existir, retorna o existente marcado deduplicated."},{"nome":"add-usage-events-batch","desc":"Ingere em lote um array JSON de eventos, deduplicando por idempotency_key e acumulando erros por indice."}],"entradas":"add-usage-event: --meter-id, --event-date, --quantity (obrigatorios), --event-type (default 'usage'), --properties (metadata), --idempotency-key. add-usage-events-batch: --events (array JSON com meter_id, event_date, quantity, opcional event_type/idempotency_key/properties).","saidas":"add-usage-event retorna {usage_event:{...}} (ou {usage_event, deduplicated:true} se duplicado). add-usage-events-batch retorna {inserted, duplicates, errors:[{index,error}], total_processed}.","regras":"customer_id e derivado do medidor. Eventos sao gravados com processed=0 (nao processados). Deduplicacao: idempotency_key existente nao gera novo registro (retorna existente / conta como duplicate). No lote, registros sem meter_id, event_date ou quantity sao reportados em errors e pulados; medidor inexistente gera erro por indice.","efeitos":"Insere linha(s) em usage_event (processed=0). add-usage-event registra auditoria; o batch NAO registra auditoria. Nenhuma postagem em GL, SLE de estoque ou payment_ledger.","precondicoes":"Medidor (meter) existente para cada evento. Cliente vinculado ao medidor."},{"group":"Planos de Tarifa","objetivo":"Criar e manter planos de precificacao (rate plans) com encargos base, encargo minimo, taxa de excedente e faixas (tiers), suportando varios modelos de cobranca.","acoes":[{"nome":"add-rate-plan","desc":"Cria um plano de tarifa, opcionalmente com faixas (tiers) em array JSON; moeda default USD."},{"nome":"update-rate-plan","desc":"Atualiza campos do plano e/ou substitui integralmente as faixas (delete + reinsert)."},{"nome":"get-rate-plan","desc":"Retorna o plano com suas faixas ordenadas por sort_order."},{"nome":"list-rate-plans","desc":"Lista planos com filtro opcional por service_type, paginado."}],"entradas":"add-rate-plan: --name, --billing-model (obrigatorios), --service-type, --base-charge, --base-charge-period, --effective-from/--effective-to, --minimum-charge, --minimum-commitment, --overage-rate, --tiers (JSON). update-rate-plan: --rate-plan-id + name/base-charge/effective-to/minimum-charge/overage-rate e/ou --tiers. list: --service-type, --limit, --offset.","saidas":"add/update/get-rate-plan retornam {rate_plan:{..., tiers:[...]}}. list-rate-plans retorna {rate_plans:[...], total_count, limit, offset, has_more}.","regras":"billing-model deve estar em VALID_PLAN_TYPES (flat, tiered, time_of_use, demand, volume_discount, prepaid_credit, hybrid). base-charge-period (se informado) em VALID_BASE_CHARGE_PERIODS (monthly, quarterly, annually). effective_from default = data atual. Tiers com tier_start/tier_end/rate/fixed_charge/time_of_use_*/demand_type e sort_order = indice. update substitui TODAS as faixas quando --tiers e enviado; exige pelo menos um campo ou tiers.","efeitos":"Insere/atualiza rate_plan e insere/recria rate_tier (update faz DELETE de todas as faixas antes de reinserir). Registra auditoria em add e update. Nenhuma postagem em GL, SLE de estoque ou payment_ledger.","precondicoes":"Tabela company instalada. Nenhuma dependencia de cliente; planos sao globais (sem company_id no insert)."},{"group":"Cálculo de Tarifação","objetivo":"Calcular o encargo de um consumo contra um plano de tarifa (motor de rating puro), retornando encargo de uso, encargo base, total e detalhamento por faixa, sem persistir nada.","acoes":[{"nome":"rate-consumption","desc":"Calcula os encargos de um consumo informado contra um plano (flat, tiered ou volume_discount) e retorna o breakdown."}],"entradas":"--rate-plan-id, --consumption (obrigatorios).","saidas":"{calculation:{usage_charge, base_charge, total_charge, breakdown:[...], rate_plan_name, plan_type, consumption}}.","regras":"plan_type deve estar em VALID_SUPPORTED_PLAN_TYPES (flat, tiered, volume_discount); demais tipos retornam erro 'not yet supported'. flat: rate da 1a faixa x consumo. tiered: soma por bandas (band_width=tier_end-tier_start) consumindo o restante. volume_discount: aplica a taxa da faixa onde o consumo se enquadra (>=start e <end). total = base + usage_charge; se < minimum_charge, eleva ao minimo. Arredondamento via round_currency (ROUND_HALF_UP).","efeitos":"Nenhum (somente leitura) — funcao pura, nao grava nem audita.","precondicoes":"Plano de tarifa existente, do tipo flat/tiered/volume_discount, com faixas cadastradas (flat exige ao menos uma faixa)."},{"group":"Ciclos de Faturamento","objetivo":"Criar e consultar periodos de faturamento (billing_period) por cliente/medidor, controlando datas, consumo, encargos, ajustes, impostos e total, alem de gerar faturas a partir de periodos tarifados.","acoes":[{"nome":"create-billing-period","desc":"Cria um periodo de faturamento 'open' validando sobreposicao com periodos nao-void existentes do medidor."},{"nome":"generate-invoices","desc":"Gera faturas de venda a partir de periodos com status 'rated', chamando a skill selling se disponivel, e marca o periodo como 'invoiced'."},{"nome":"list-billing-periods","desc":"Lista periodos com nome do cliente e numero do medidor, com filtros por cliente/medidor/status/datas, paginado."},{"nome":"get-billing-period","desc":"Retorna o periodo com nomes de cliente/medidor/plano e a lista de ajustes."}],"entradas":"create-billing-period: --customer-id, --meter-id, --from-date, --to-date (obrigatorios), --rate-plan-id (senao usa o do medidor). generate-invoices: --billing-period-ids (array JSON). list: --customer-id/--meter-id/--status/--from-date/--to-date/--limit/--offset. get: --billing-period-id.","saidas":"create/get retornam {billing_period:{...}} (get inclui adjustments). generate-invoices retorna {invoiced, results:[{billing_period_id, invoice_id, status}]}. list retorna {billing_periods:[...], total_count, limit, offset, has_more}.","regras":"create exige plano (argumento ou do medidor) existente; rejeita periodo sobreposto (mesmo medidor, status != void, com interseccao de datas). Periodo nasce 'open' com totais zerados. status validos em VALID_BILLING_PERIOD_STATUSES (open, rated, invoiced, paid, disputed, void). generate-invoices so processa periodos 'rated'; demais status retornam erro no item.","efeitos":"create-billing-period insere billing_period e registra auditoria. generate-invoices INVOCA via subprocess a skill selling (add-sales-invoice) — efeito colateral real podendo criar sales_invoice no dominio de vendas (e seus efeitos a jusante) — e atualiza billing_period para 'invoiced' com invoice_id/invoiced_at. Nao posta diretamente em GL/SLE/payment_ledger nesta skill.","precondicoes":"Cliente e medidor existentes; plano de tarifa existente. Para faturar: periodo em status 'rated'; tabela sales_invoice e script da skill selling presentes (senao invoice_id fica nulo mas status vira 'invoiced')."},{"group":"Bill Run","objetivo":"Executar o processamento de faturamento de uma empresa: agregar consumo de leituras e eventos nao processados, tarifar e criar/atualizar periodos de faturamento como 'rated'.","acoes":[{"nome":"run-billing","desc":"Roda o faturamento de todos os medidores ativos com plano da empresa: agrega consumo, calcula encargos e gera/atualiza periodos 'rated'."}],"entradas":"--company-id, --billing-date (obrigatorios); --from-date (default billing-date menos 30 dias); --to-date (default billing-date).","saidas":"{periods_created, period_ids:[...], total_billed} (ou mensagem se nao houver clientes/medidores).","regras":"Processa apenas medidores com status 'active' e rate_plan_id nao nulo dos clientes da empresa. Pula medidores ja faturados no periodo (status rated/invoiced/paid). Plano deve ter plan_type suportado (flat/tiered/volume_discount). Consumo total = soma de meter_reading.consumption no periodo + soma de usage_event.quantity nao processados no periodo. subtotal = total_charge (antes de ajustes). Periodo 'open' existente e atualizado para 'rated'; senao cria novo 'rated'.","efeitos":"Insere ou atualiza linhas em billing_period (status 'rated', rated_at). Marca usage_event como processed=1 e vincula billing_period_id. Registra auditoria com periodos e total faturado. Nao posta em GL/SLE/payment_ledger (a faturacao contabil ocorre em generate-invoices).","precondicoes":"Empresa (company) existente. Clientes com medidores 'active' e plano de tarifa atribuido. Leituras com consumo e/ou eventos de uso nao processados no intervalo."},{"group":"Ajustes","objetivo":"Aplicar ajustes financeiros (credito, multa, deposito, reembolso, proracao, desconto, penalidade, write-off) a um periodo de faturamento, recalculando os totais do periodo.","acoes":[{"nome":"add-billing-adjustment","desc":"Registra um ajuste no periodo e recalcula adjustments_total, subtotal e grand_total."}],"entradas":"--billing-period-id, --amount, --adjustment-type (obrigatorios); --reason, --approved-by.","saidas":"{adjustment:{..., updated_grand_total}}.","regras":"adjustment-type deve estar em VALID_ADJUSTMENT_TYPES (credit, late_fee, deposit, refund, proration, discount, penalty, write_off). Periodo deve existir. Recalculo: adjustments_total = soma (DecimalSum) dos ajustes do periodo; subtotal = base_charge + usage_charge + adjustments_total; grand_total = subtotal + tax_amount; tudo via round_currency.","efeitos":"Insere linha em billing_adjustment e atualiza billing_period (adjustments_total, subtotal, grand_total, updated_at). Registra auditoria. Nenhuma postagem em GL/SLE/payment_ledger.","precondicoes":"Periodo de faturamento (billing_period) existente. Tabela billing_adjustment disponivel."},{"group":"Créditos Pré-pagos","objetivo":"Registrar compromissos pre-pagos (saldo de credito) de um cliente com validade e consultar o saldo remanescente agregado.","acoes":[{"nome":"add-prepaid-credit","desc":"Registra um saldo pre-pago para o cliente (valor original = remanescente), status 'active'."},{"nome":"get-prepaid-balance","desc":"Consulta os saldos pre-pagos do cliente e soma o remanescente dos creditos ativos."}],"entradas":"add-prepaid-credit: --customer-id, --amount, --valid-until (obrigatorios), --rate-plan-id (opcional). get-prepaid-balance: --customer-id.","saidas":"add-prepaid-credit retorna {prepaid_credit:{...}}. get-prepaid-balance retorna {customer_id, active_credits, total_remaining, balances:[...]}.","regras":"Cliente deve existir. Se --rate-plan-id nao informado, usa um plano com plan_type 'prepaid_credit' ou, na ausencia, o primeiro plano disponivel; se nenhum existir, erro. period_start = data atual, period_end = valid-until. original_amount = remaining_amount = amount; overage_amount=0; status 'active'. status validos em VALID_PREPAID_STATUSES (active, exhausted, expired). get soma remaining_amount apenas de creditos 'active'.","efeitos":"Insere linha em prepaid_credit_balance e registra auditoria. get-prepaid-balance e somente leitura. Nenhuma postagem em GL/SLE/payment_ledger.","precondicoes":"Cliente existente. Ao menos um rate_plan cadastrado quando nao se informa --rate-plan-id."},{"group":"Status","objetivo":"Fornecer um resumo do dominio de faturamento: contagens de medidores e periodos por status, planos, eventos nao processados e saldos pre-pagos, opcionalmente filtrado por empresa.","acoes":[{"nome":"status","desc":"Retorna metricas agregadas de medidores, periodos, planos, eventos nao processados e creditos pre-pagos."}],"entradas":"--company-id (opcional; restringe aos clientes da empresa).","saidas":"{meters:{status:cnt}, meters_total, billing_periods:{status:cnt}, billing_periods_total, rate_plans_total, unprocessed_events, prepaid_balances}.","regras":"Se --company-id informado, valida a empresa e restringe medidores/periodos/eventos/pre-pagos aos clientes daquela empresa (IN dinamico). Contagens agrupadas por status para medidores e periodos. unprocessed_events conta usage_event com processed=0.","efeitos":"Nenhum (somente leitura).","precondicoes":"Tabela company instalada. Se filtrar, empresa existente."}]},"tax":{"module":"tax","display":"Impostos","functionalities":[{"group":"Modelos","objetivo":"Gerencia modelos de imposto (tax_template) com suas linhas de cálculo (tax_template_line), que definem contas, alíquotas e tipo de incidência para vendas, compras ou ambos.","acoes":[{"nome":"add-tax-template","desc":"Cria um modelo de imposto com uma ou mais linhas (conta, alíquota, charge_type, add_deduct)."},{"nome":"update-tax-template","desc":"Atualiza nome, flag padrão e/ou substitui integralmente as linhas do modelo."},{"nome":"get-tax-template","desc":"Retorna o modelo e suas linhas (com nome da conta), ordenadas por row_order."},{"nome":"list-tax-templates","desc":"Lista modelos da empresa com paginação, filtrando opcionalmente por tax_type (inclui 'both')."},{"nome":"delete-tax-template","desc":"Exclui o modelo e suas linhas se nao houver referencias."}],"entradas":"--name, --tax-type (sales|purchase|both), --company-id, --lines (array JSON: tax_account_id, rate, charge_type, add_deduct, row_order, included_in_print_rate, description), --is-default, --tax-template-id, --limit, --offset.","saidas":"Em criar/atualizar: status e tax_template_id (e line_count/updated_fields). get retorna o cabecalho mais a lista de lines com account_name. list retorna templates, total_count, limit, offset, has_more.","regras":"--name, --tax-type valido e --company-id obrigatorios; --lines obrigatorio e nao vazio. Cada linha valida rate (decimal), charge_type em (actual, on_net_total, on_previous_row_amount, on_previous_row_total, on_item_quantity) e add_deduct em (add, deduct). Empresa e todas as tax_account_id devem existir. is_default zera os demais defaults do mesmo tax_type (e 'both') da empresa. update substitui linhas apagando e reinserindo. delete bloqueia se referenciado por tax_rule ou item_tax_template.","efeitos":"Escreve em tax_template e tax_template_line (insert/update/delete). Grava trilha de auditoria via audit() para cada acao. Faz conn.commit(). Nenhuma postagem em GL, SLE de estoque ou payment_ledger_entry.","precondicoes":"Empresa (company) existente; contas (account) das linhas previamente cadastradas. Tabelas requeridas: company, account, party_type_registry."},{"group":"Categorias","objetivo":"Mantem categorias de imposto (tax_category) usadas como criterio de classificacao e como filtro em regras de imposto.","acoes":[{"nome":"add-tax-category","desc":"Cria uma categoria de imposto com nome e descricao opcional."},{"nome":"list-tax-categories","desc":"Lista todas as categorias de imposto com paginacao, ordenadas por nome."}],"entradas":"--name (obrigatorio), --description (opcional), --limit, --offset.","saidas":"add retorna status created e tax_category_id e name. list retorna categories, total_count, limit, offset, has_more.","regras":"--name obrigatorio. Categoria nao tem vinculo de empresa (global). Sem ciclo de vida rascunho/submit. Sem validacao de unicidade explicita no codigo.","efeitos":"Insere em tax_category e grava auditoria via audit(); faz commit. Nenhuma postagem em GL/estoque/pagamentos.","precondicoes":"Banco inicializado com tabelas requeridas (company, account, party_type_registry)."},{"group":"Regras","objetivo":"Define regras de imposto (tax_rule) que associam um modelo a criterios (cliente, grupo, fornecedor, estado de entrega, categoria) e uma prioridade, para selecao automatica do modelo aplicavel.","acoes":[{"nome":"add-tax-rule","desc":"Cria uma regra que aponta para um modelo, com tipo, prioridade e ao menos um filtro."},{"nome":"list-tax-rules","desc":"Lista regras da empresa com nome do modelo, ordenadas por prioridade e data, com paginacao."}],"entradas":"--tax-template-id, --tax-type (sales|purchase), --priority (int), e ao menos um filtro: --customer-id, --customer-group, --supplier-id, --shipping-state, --tax-category-id; --company-id/--company para listar; --limit, --offset.","saidas":"add retorna status created e tax_rule_id. list retorna rules (com template_name), total_count, limit, offset, has_more.","regras":"--tax-template-id, --tax-type (apenas sales ou purchase) e --priority obrigatorios. Pelo menos uma condicao de filtro e exigida. O modelo deve existir; company_id da regra herda o do modelo. supplier_group e gravado como None. Sem ciclo de vida rascunho/submit.","efeitos":"Insere em tax_rule e grava auditoria; faz commit. Nenhuma postagem contabil, de estoque ou de pagamento.","precondicoes":"Modelo de imposto (tax_template) existente; empresa resolvida para listagem; categorias/clientes/fornecedores referenciados conforme o filtro usado."},{"group":"Resolucao","objetivo":"Seleciona automaticamente o modelo de imposto aplicavel para um parceiro e transacao, avaliando as regras por prioridade e caindo no modelo padrao da empresa quando nenhuma casa.","acoes":[{"nome":"resolve-tax-template","desc":"Resolve o melhor tax_template para party/transacao, avalia isencao e lista overrides por item."}],"entradas":"--party-type (deve estar no party_type_registry), --party-id, --company-id/--company; opcionais --transaction-type (sales|purchase), --tax-category-id, --shipping-address (JSON com state).","saidas":"tax_template_id, template_name, is_exempt (bool) e item_overrides (itens cujo tax_template_id difere do resolvido).","regras":"party-type deve estar registrado; party-id obrigatorio. tx_type vem de --transaction-type ou inferido (customer=sales, supplier=purchase, generico=sales). Regras filtradas por empresa e tipo (inclui 'both'), avaliadas em ordem de prioridade asc; primeira correspondencia em customer_id/customer_group/supplier_id/shipping_state/tax_category_id vence. Sem match, usa template is_default da empresa do tipo. Cliente com exempt_from_sales_tax marca is_exempt=True.","efeitos":"Nenhum (somente leitura) — apenas SELECTs; nao escreve em nenhuma tabela nem em GL.","precondicoes":"party_type_registry populado; cliente/fornecedor existente; regras e/ou modelo padrao cadastrados na empresa; item_tax_template para overrides."},{"group":"Calculo","objetivo":"Calcula impostos de uma lista de itens contra um modelo, aplicando linhas em cascata e distribuindo o imposto proporcionalmente por item.","acoes":[{"nome":"calculate-tax","desc":"Calcula imposto por linha (cascata) e por item, retornando totais; calculo puro sem gravacao."}],"entradas":"--tax-template-id, --items (array JSON: item_id, net_amount, qty), opcional --item-overrides (item_id, override_template_id).","saidas":"tax_lines (conta, nome, descricao, rate, amount), total_tax, net_total, grand_total e per_item_tax (item_id, tax_amount).","regras":"tax-template-id e --items obrigatorios; modelo deve ter linhas. Base por charge_type: on_net_total=net_total; on_previous_row_total=total da linha anterior (ou net); on_previous_row_amount=valor da linha anterior; actual=rate vira valor fixo; on_item_quantity=soma das qty. add_deduct=deduct inverte sinal. Itens em override_map nao recebem rateio. Arredondamento via round_currency.","efeitos":"Nenhum (somente leitura) — calculo puro, declarado 'no database writes'; nenhuma postagem em GL, SLE ou pagamentos.","precondicoes":"Modelo de imposto com linhas (tax_template_line) existente; contas das linhas cadastradas."},{"group":"Impostos por Item","objetivo":"Associa um item a um modelo de imposto especifico (item_tax_template), permitindo sobrescrever a tributacao padrao para aquele item.","acoes":[{"nome":"add-item-tax-template","desc":"Vincula um item a um tax_template com alíquota opcional, criando o override por item."}],"entradas":"--item-id, --tax-template-id (obrigatorios), --tax-rate (opcional).","saidas":"status created e item_tax_template_id.","regras":"item-id e tax-template-id obrigatorios; o tax_template referenciado deve existir. Nao valida existencia do item nem unicidade do par item/modelo. Sem ciclo de vida rascunho/submit.","efeitos":"Insere em item_tax_template e grava auditoria; faz commit. Nenhuma postagem contabil, de estoque ou de pagamento.","precondicoes":"Modelo de imposto (tax_template) existente; item previamente cadastrado (nao verificado pelo codigo)."},{"group":"Retencao na Fonte","objetivo":"Registra lancamentos de retencao na fonte (tax_withholding_entry) para um fornecedor, vinculando-os ao voucher de origem e ao ano fiscal.","acoes":[{"nome":"record-withholding-entry","desc":"Cria um lancamento de retencao com o valor retido para o fornecedor, voucher e ano fiscal."}],"entradas":"--supplier-id, --voucher-type, --voucher-id, --withholding-amount, --tax-year (todos obrigatorios).","saidas":"status created e withholding_entry_id.","regras":"Todos os campos obrigatorios. voucher_type e normalizado para snake_case via canonical_voucher_type (FINDING-006). Fornecedor deve existir e ter tax_withholding_category_id atribuido. Grava withheld_amount=valor, taxable_amount=0, e armazena withholding_voucher_type/withholding_voucher_id.","efeitos":"Insere em tax_withholding_entry (somente do lado withholding) e grava auditoria; faz commit. Nao posta em GL/gl_entry nem em payment_ledger_entry; nao altera status de documento.","precondicoes":"Fornecedor (supplier) existente com tax_withholding_category_id definido; categoria de retencao cadastrada."},{"group":"Retencao de Fornecedores","objetivo":"Cadastra categorias de retencao (tax_withholding_category) com alíquota e limiar, e consulta a situacao de retencao/1099 de um fornecedor em um ano fiscal.","acoes":[{"nome":"add-tax-withholding-category","desc":"Cria categoria de retencao com limiar e tipo de formulario, e um grupo padrao com a alíquota."},{"nome":"get-withholding-details","desc":"Agrega situacao de retencao do fornecedor no ano: pagamentos YTD, limiar, alíquota e backup withholding."}],"entradas":"Para criar: --name, --rate, --threshold-amount, --form-type (1099-NEC|1099-MISC), --company-id. Para consultar: --supplier-id, --tax-year, --company-id/--company.","saidas":"add retorna status created, category_id, name. get retorna is_1099_vendor, withholding_category, ytd_payments, threshold_exceeded, withholding_rate, backup_withholding_rate, w9_on_file, withholding_amount.","regras":"Criar: name, rate, threshold-amount, form-type valido e company-id obrigatorios; rate/threshold validados como decimal; form_type gravado em category_code e threshold em cumulative_threshold; cria grupo 'Default' com a alíquota e effective_from=2020-01-01 usando a primeira conta de tipo tax/payable da empresa. Consultar: soma taxable_amount YTD do twe; threshold_exceeded = ytd>=threshold; backup withholding de 24% aplicado quando is_1099_vendor e sem W9 em arquivo.","efeitos":"add insere em tax_withholding_category e (se houver conta) em tax_withholding_group, grava auditoria e faz commit. get e somente leitura (apenas SELECTs/agregacao). Nenhuma postagem em GL ou pagamentos.","precondicoes":"Empresa existente; para o grupo padrao deve haver conta com account_type tax ou payable na empresa; fornecedor existente para a consulta; lancamentos em tax_withholding_entry para haver YTD."},{"group":"Relatorios 1099","objetivo":"Registra pagamentos tributaveis 1099 e gera os dados consolidados de 1099 por fornecedor/categoria para o ano fiscal, aplicando o limiar de reporte.","acoes":[{"nome":"record-1099-payment","desc":"Registra um pagamento tributavel 1099 (taxable_amount) para o fornecedor e retorna o total YTD."},{"nome":"generate-1099-data","desc":"Gera a lista de vendors 1099 da empresa no ano, filtrando os que atingiram o limiar da categoria."}],"entradas":"record: --supplier-id, --amount, --tax-year, --voucher-type, --voucher-id. generate: --tax-year, --company-id/--company.","saidas":"record retorna status created e ytd_1099_total. generate retorna vendors (supplier_id, name, tin, total_paid, form_type, box_1).","regras":"record: campos obrigatorios; voucher_type normalizado (canonical_voucher_type); fornecedor deve existir e ter categoria; grava taxable_amount=valor, withheld_amount=0, e taxable_voucher_type/id; recalcula YTD. generate: soma decimal_sum(taxable_amount) por party/categoria; descarta quem ficou abaixo do cumulative_threshold da categoria; form_type vem de category_code (default 1099-NEC); box_1 = total quando 1099-NEC, senao 0.00.","efeitos":"record insere em tax_withholding_entry (lado taxable) e grava auditoria; faz commit. generate e somente leitura (agregacao). Nenhuma postagem em GL/gl_entry, SLE ou payment_ledger_entry; nao altera status de documento.","precondicoes":"Fornecedor com tax_withholding_category_id atribuido; categorias de retencao da empresa cadastradas; lancamentos taxable em tax_withholding_entry para o ano."},{"group":"Status","objetivo":"Fornece um panorama do dominio de impostos da empresa: contagem de modelos, regras, categorias de retencao e fornecedores 1099 do ano corrente.","acoes":[{"nome":"status","desc":"Retorna contagens agregadas de modelos, regras, categorias de retencao e vendors 1099 YTD da empresa."}],"entradas":"--company-id ou --company (resolve a empresa).","saidas":"templates, rules, withholding_categories e ytd_1099_vendors (distintos no ano corrente).","regras":"Empresa resolvida via resolve_company_id. Conta tax_template, tax_rule e tax_withholding_category por company_id; conta party_id distintos em tax_withholding_entry do ano corrente (UTC) cuja category pertence a empresa.","efeitos":"Nenhum (somente leitura) — apenas COUNTs e agregacoes.","precondicoes":"Empresa existente; tabelas de impostos/retencao presentes no banco."}]},"payments":{"module":"payments","display":"Pagamentos","functionalities":[{"group":"Cadastro","objetivo":"Criar e editar lançamentos de pagamento (payment_entry) em rascunho — recebimentos, pagamentos e transferências internas — com suas alocações a faturas.","acoes":[{"nome":"add-payment","desc":"Cria um novo payment_entry em status 'draft', opcionalmente já com alocações."},{"nome":"update-payment","desc":"Edita valor pago, número de referência e/ou alocações de um pagamento ainda em rascunho."}],"entradas":"add: --company-id, --payment-type (receive|pay|internal_transfer), --posting-date, --party-type, --party-id, --paid-from-account, --paid-to-account, --paid-amount, --payment-currency (USD), --exchange-rate (1), --reference-number, --reference-date, --allocations (JSON). update: --payment-entry-id e os campos a alterar (--paid-amount, --reference-number, --allocations).","saidas":"add: {status:'created', payment_entry_id, naming_series}. update: {status:'updated', payment_entry_id, updated_fields}.","regras":"payment_type deve ser receive/pay/internal_transfer; party_type/party_id obrigatórios exceto em internal_transfer e o party_type deve estar registrado em party_type_registry. paid_amount > 0. received_amount = paid_amount * exchange_rate. Contas paid_from/paid_to validadas como não-grupo (grupo é auto-resolvido para único filho-folha ou gera erro). unallocated_amount inicia igual ao paid_amount e é recalculado quando há alocações. update só permitido em status 'draft'; em update --allocations substitui todas as alocações (delete + reinsert).","efeitos":"Insere/atualiza linha em payment_entry e linhas em payment_allocation (recalculando unallocated_amount). Grava auditoria (audit) para add-payment e update-payment. NÃO posta GL nem PLE nesta fase (apenas no submit). Faz conn.commit().","precondicoes":"Empresa (company) existente; contas (account) paid_from e paid_to existentes e não-grupo; party_type registrado em party_type_registry; tabelas company e account presentes (REQUIRED_TABLES)."},{"group":"Listagem","objetivo":"Consultar pagamentos individualmente ou em lista filtrada/paginada, e localizar pagamentos com saldo não alocado por parte.","acoes":[{"nome":"get-payment","desc":"Retorna um payment_entry completo com suas alocações."},{"nome":"list-payments","desc":"Lista paginada de pagamentos da empresa com filtros e nome da parte resolvido."},{"nome":"get-unallocated-payments","desc":"Lista pagamentos submitted de uma parte que ainda têm saldo não alocado (>0)."},{"nome":"list-open-advances","desc":"Alias (vocabulário SAP-B1) de get-unallocated-payments; lista adiantamentos em aberto."}],"entradas":"get: --payment-entry-id. list: --company-id/--company (nome), filtros --payment-type, --party-type, --party-id, --status, --from-date, --to-date, --limit (20), --offset (0). get-unallocated/list-open-advances: --party-type, --party-id, --company-id/--company.","saidas":"get: objeto do pagamento + array allocations (id, voucher_type, voucher_id, allocated_amount, exchange_gain_loss). list: {payments[], total_count, limit, offset, has_more}, cada item com party_name resolvido. get-unallocated: {payments[]} com id, naming_series, paid_amount, unallocated_amount, posting_date.","regras":"list ordena por posting_date desc e created_at desc; resolve party_name por subconsulta CASE em customer/supplier/employee. get-unallocated filtra status='submitted' e unallocated_amount (CAST NUMERIC) > 0, ordenado por posting_date.","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa resolvível (por id ou nome); tabela payment_entry presente."},{"group":"Ciclo de Vida","objetivo":"Conduzir o pagamento pelo fluxo rascunho → submetido → cancelado, postando e revertendo a contabilidade, além de excluir rascunhos.","acoes":[{"nome":"submit-payment","desc":"Submete um draft: posta GL, cria PLE, aplica desconto por pagamento antecipado e limpa faturas alocadas."},{"nome":"cancel-payment","desc":"Cancela um pagamento submitted: reverte GL, reverte PLE e desfaz a baixa das faturas."},{"nome":"delete-payment","desc":"Exclui fisicamente um pagamento ainda em rascunho (com suas alocações e deduções)."}],"entradas":"Todas usam --payment-entry-id.","saidas":"submit: {status:'submitted', payment_entry_id, gl_entries_created, documents_cleared, outstanding_updated} (+ early_payment_discount e/ou exchange_gain_loss quando aplicável). cancel: {status:'cancelled', payment_entry_id, reversed:true}. delete: {status:'deleted', deleted:true}.","regras":"submit exige status 'draft'; revalida contas não-grupo (auto-resolve folha). Monta GL conforme tipo: receive DR paid_to(banco)/CR paid_from(receber); pay DR paid_to(pagar)/CR paid_from(banco); internal_transfer DR/CR banco↔banco. Calcula desconto antecipado se a fatura tem payment_terms com discount_percentage/discount_days e o pagamento ocorre dentro da janela (reduz valor no banco, conta de desconto absorve). Guarda contra falso sucesso: se há alocações de fatura mas nenhuma é baixada, faz rollback e erro. Branch de FX (gain/loss) está dormente (regra: moeda da fatura = moeda do pagamento, rate=1). cancel exige status 'submitted'. delete só em 'draft'.","efeitos":"submit: valida e insere gl_entry (insert_gl_entries via validate_gl_entries 12 passos), insere payment_ledger_entry de nível-parte (-paid_amount) e PLE por alocação (INV-22), aplica baixa em sales_invoice/purchase_invoice (apply_payment_to_document: outstanding/status), pode rotear porção de adiantamento a sub-conta (advance_account_id), muda status para 'submitted', auditoria. cancel: reverse_gl_entries, marca PLE como delinked e cria PLE de reversão, reverse_payment_on_document restaura outstanding/status das faturas, status 'cancelled', auditoria. delete: DELETE em payment_allocation, payment_deduction e payment_entry, auditoria. Todas fazem commit (rollback em falha).","precondicoes":"Pagamento existente no status correto; contas válidas; para submit com alocações, faturas com moeda igual à do pagamento; conta de desconto ('Sales/Purchase Discounts') e cost center default existentes para aplicar desconto; sub-conta de adiantamento configurada na company para rotear advance."},{"group":"Alocação a Faturas","objetivo":"Vincular o saldo não alocado de um pagamento já submetido a uma fatura específica, baixando o documento e registrando a baixa no razão de pagamentos.","acoes":[{"nome":"allocate-payment","desc":"Aloca um valor de um pagamento submitted a um voucher (sales_invoice/purchase_invoice), limpando o documento."}],"entradas":"--payment-entry-id, --voucher-type (canonizado, ex.: 'Sales Invoice' → sales_invoice), --voucher-id, --allocated-amount.","saidas":"{status:'created', allocation_id, document_cleared (bool), remaining_unallocated}.","regras":"Pagamento deve estar 'submitted'. allocated_amount > 0 e não pode exceder o unallocated_amount atual. Recalcula unallocated após inserir alocação. Para voucher de tipo fatura, deve efetivamente baixar o documento — caso contrário rollback e erro (guarda contra falso sucesso). Se o adiantamento foi roteado a sub-conta no submit (advance_account_id), aplica reclassificação GL: receive DR Advance-from-Customer/CR AR; pay DR AP/CR Advance-to-Supplier (entry_set próprio, GL imutável).","efeitos":"Insere linha em payment_allocation, recalcula unallocated_amount, baixa a fatura (apply_payment_to_document: outstanding/status) e posta PLE por alocação (INV-22). Quando há advance_account_id, valida e insere gl_entry de reclassificação. Auditoria. commit (rollback em falha).","precondicoes":"Pagamento existente e 'submitted' com saldo não alocado suficiente; fatura-alvo existente e em estado que aceite baixa; para reclassificação, advance_account_id previamente gravado no submit."},{"group":"Adiantamentos","objetivo":"Tratar a porção não alocada de um pagamento como adiantamento (advance) — listando os em aberto e aplicando-os a faturas com reclassificação contábil da sub-conta de adiantamento para a conta de controle AR/AP.","acoes":[{"nome":"list-open-advances","desc":"Alias de get-unallocated-payments: lista adiantamentos (pagamentos com saldo) em aberto da parte."},{"nome":"apply-advance-to-invoice","desc":"Alias de allocate-payment: aplica um adiantamento a uma fatura, reclassificando a sub-conta de adiantamento para AR/AP."}],"entradas":"list-open-advances: --party-type, --party-id, --company-id/--company. apply-advance-to-invoice: --payment-entry-id, --voucher-type, --voucher-id, --allocated-amount.","saidas":"list-open-advances: {payments[]} (mesma de get-unallocated-payments). apply-advance-to-invoice: {status:'created', allocation_id, document_cleared, remaining_unallocated} (mesma de allocate-payment).","regras":"São aliases de vocabulário SAP-B1 com a MESMA semântica das ações originais. O roteamento de adiantamento só ocorre se a company tem advance_from_customer_account_id (receive) ou advance_to_supplier_account_id (pay) configurada; no submit a porção unallocated > 0 é movida para a sub-conta e advance_account_id é gravado. Na aplicação, reclassifica esse valor de volta para a conta de controle AR/AP.","efeitos":"list-open-advances: nenhum (somente leitura). apply-advance-to-invoice: idêntico a allocate-payment — payment_allocation, recálculo de unallocated, baixa da fatura (apply_payment_to_document), PLE por alocação, gl_entry de reclassificação quando há advance_account_id, auditoria e commit.","precondicoes":"Pagamento submetido com saldo (adiantamento) e, para roteamento/reclassificação, sub-contas de adiantamento configuradas na company; fatura-alvo existente."},{"group":"Razão de Pagamentos (PLE)","objetivo":"Manter o payment_ledger_entry — subrazão que rastreia o outstanding por parte e por voucher — e consultar saldos em aberto. Usado em integração cross-skill por selling/buying na submissão de faturas.","acoes":[{"nome":"create-payment-ledger-entry","desc":"Cria uma linha de PLE; chamada cross-skill por selling/buying no submit da fatura (+grand_total)."},{"nome":"get-outstanding","desc":"Agrega e retorna o saldo em aberto de uma parte a partir das linhas de PLE não delinkadas."}],"entradas":"create-PLE: --voucher-type, --voucher-id, --party-type, --party-id, --amount, --posting-date, --account-id, --against-voucher-type, --against-voucher-id. get-outstanding: --party-type, --party-id, opcionais --voucher-type, --voucher-id.","saidas":"create-PLE: {status:'created', ple_id}. get-outstanding: {outstanding (total), vouchers[]} com voucher_type, voucher_id, outstanding_amount, posting_date.","regras":"party_type deve estar registrado em party_type_registry. voucher_type e against_voucher_type são canonizados na fronteira de escrita (label 'Sales Invoice' → sales_invoice) para o netting bater. amount arredondado a moeda; currency fixada em 'USD' na create. get-outstanding soma amount por (voucher_type, voucher_id) filtrando delinked=0, com HAVING sum != 0, ordenado por posting_date; aceita filtro por voucher (também canonizado).","efeitos":"create-payment-ledger-entry: insere linha em payment_ledger_entry, auditoria e commit. get-outstanding: nenhum (somente leitura).","precondicoes":"party_type registrado; conta (account-id) existente; para get-outstanding, existir PLE da parte. Tabela payment_ledger_entry presente."},{"group":"Conciliação","objetivo":"Conciliar automaticamente pagamentos não alocados de uma parte contra suas faturas em aberto usando algoritmo FIFO.","acoes":[{"nome":"reconcile-payments","desc":"Casa em FIFO pagamentos com saldo contra faturas em aberto (PLE), criando alocações e baixando documentos."}],"entradas":"--party-type, --party-id, --company-id.","saidas":"{matched[] (payment_id, voucher_id, allocated_amount), unmatched_payments, unmatched_invoices}.","regras":"Busca pagamentos status='submitted' com unallocated>0 (FIFO por posting_date, created_at) e faturas em aberto via PLE (sum>0, somente sales_invoice/purchase_invoice, FIFO por MIN(posting_date)). Casa o menor entre saldo do pagamento e saldo da fatura, avançando índices. Como só casa faturas, toda alocação DEVE baixar um documento; um cleared=False faz rollback e erro (proteção contra drift de voucher_type). Recalcula unallocated de todos os pagamentos afetados ao final.","efeitos":"Insere linhas em payment_allocation, baixa cada fatura casada (apply_payment_to_document: outstanding/status) e posta PLE por alocação (INV-22), recalcula unallocated_amount dos pagamentos. commit (rollback em falha). Não grava auditoria explícita.","precondicoes":"Existirem pagamentos submetidos com saldo e faturas em aberto da mesma parte/empresa; PLE das faturas previamente criado (no submit das faturas)."},{"group":"Conciliação Bancária","objetivo":"Comparar, em modo leitura, o saldo contábil (GL) de uma conta bancária com a movimentação de pagamentos em um período, sem alterar dados.","acoes":[{"nome":"bank-reconciliation","desc":"Calcula saldo GL da conta bancária no período e conta pagamentos que a tocam (paid_from/paid_to)."}],"entradas":"--bank-account-id, --from-date, --to-date.","saidas":"{bank_account (nome), from_date, to_date, gl_entries (contagem), gl_balance (débito - crédito), payment_entries (contagem)}.","regras":"Conta bancária deve existir. gl_balance = soma(débito) - soma(crédito) sobre gl_entry da conta no período com is_cancelled=0. payment_entries conta payment_entry status='submitted' no período onde paid_from_account OU paid_to_account é a conta.","efeitos":"Nenhum (somente leitura).","precondicoes":"Conta (account) bancária existente; intervalo de datas informado; tabela gl_entry e payment_entry presentes."},{"group":"Status","objetivo":"Apresentar um resumo de contagens de pagamentos por status e totais recebidos/pagos da empresa.","acoes":[{"nome":"status","desc":"Conta pagamentos por status e soma paid_amount dos submitted por tipo (received/paid)."}],"entradas":"--company-id ou --company (nome).","saidas":"{total, draft, submitted, cancelled, total_received, total_paid}.","regras":"Agrupa payment_entry por status para contagens. Soma paid_amount apenas dos status='submitted' agrupado por payment_type: 'receive' → total_received, 'pay' → total_paid. Valores monetários arredondados.","efeitos":"Nenhum (somente leitura).","precondicoes":"Empresa resolvível (id ou nome); tabela payment_entry presente."}]},"reports":{"module":"reports","display":"Relatórios","functionalities":[{"group":"DRE (Demonstração de Resultado)","objetivo":"Apura receitas e despesas do período a partir do gl_entry, gerando o resultado líquido (lucro/prejuízo). Suporta visão plana, comparativa entre períodos e quebra por uma dimensão contábil.","acoes":[{"nome":"profit-and-loss","desc":"DRE do período por conta de receita/despesa; com --group-by quebra o resultado por uma dimensão contábil."},{"nome":"comparative-pl","desc":"DRE comparativa de vários períodos lado a lado (recebe array JSON de períodos)."}],"entradas":"profit-and-loss: --company-id/--company, --from-date, --to-date (ambas obrigatórias); opcionais --project-id, --group-by (uma dimensão), pares --dimension-key/--dimension-value. comparative-pl: --company-id/--company e --periods (array JSON de {from_date,to_date,label}).","saidas":"profit-and-loss plano: period, listas income/expenses (account, account_id, amount), income_total, expense_total, net_income. Agrupado: groups (valor da dimensão + revenue/expenses/net), income_total, expense_total, net_income. comparative-pl: accounts (com amount por período) e totals (income/expenses/net por período).","regras":"Receita = credit - debit; Despesa = debit - credit (contas root_type income/expense, is_group=0, is_cancelled=0). Linhas com amount=0 são omitidas (HAVING). --group-by aceita exatamente uma dimensão e exige que ela esteja registrada e ativa em dimension_registry; entradas sem a chave caem no bucket '(untagged)'. net_income = income_total - expense_total. Apenas leitura; sem ciclo de vida.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa existente; plano de contas com contas income/expense; lançamentos em gl_entry no período. Para --group-by, a dimensão precisa estar registrada e ativa em dimension_registry."},{"group":"Balanço Patrimonial","objetivo":"Monta o balanço (ativo, passivo e patrimônio líquido) em uma data de corte, incluindo o resultado do exercício acumulado no PL.","acoes":[{"nome":"balance-sheet","desc":"Balanço patrimonial em --as-of-date com ativo/passivo/PL e lucro do exercício (YTD) somado ao PL."}],"entradas":"--company-id/--company, --as-of-date (obrigatória); opcionais --project-id e pares --dimension-key/--dimension-value.","saidas":"as_of_date, assets + total_assets, liabilities + total_liabilities, equity + total_equity, net_income_ytd.","regras":"Saldos acumulados até as_of_date (is_cancelled=0). Ativo = debit - credit; Passivo/PL = credit - debit. Contas com saldo zero são omitidas. net_income_ytd é apurado do início do exercício fiscal vigente (fiscal_year cuja faixa contém as_of_date) até a data e somado ao total_equity. Apenas leitura; sem ciclo de vida.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; plano de contas com root_type asset/liability/equity/income/expense; lançamentos em gl_entry; fiscal_year cadastrado cobrindo a data para apurar o resultado do exercício."},{"group":"Balancete (Trial Balance)","objetivo":"Lista por conta os saldos de abertura, a movimentação do período e o saldo de fechamento, com totais de débito e crédito para conferência de fechamento.","acoes":[{"nome":"trial-balance","desc":"Balancete por conta com abertura, movimento e fechamento até --to-date."}],"entradas":"--company-id/--company, --to-date (obrigatória); opcionais --from-date (separa abertura de movimento), --project-id e pares --dimension-key/--dimension-value.","saidas":"as_of_date, total_debit, total_credit e accounts (account_id/name/number, root_type, opening_debit/credit, debit/credit do período, closing_debit/credit).","regras":"Sem --from-date, todo o saldo até to-date entra como movimento (abertura zero). Com --from-date, abertura = lançamentos antes da data; movimento = entre from e to. Considera apenas is_cancelled=0 e contas não-grupo; contas sem atividade (fechamento débito e crédito zero) são puladas. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; plano de contas; lançamentos em gl_entry."},{"group":"Fluxo de Caixa","objetivo":"Demonstra a variação de caixa do período classificando movimentos em operacional, investimento e financiamento (método indireto simplificado).","acoes":[{"nome":"cash-flow","desc":"Fluxo de caixa do período com saldos de abertura/fechamento de contas bank/cash e movimentos categorizados."}],"entradas":"--company-id/--company, --from-date, --to-date (ambas obrigatórias); opcionais pares --dimension-key/--dimension-value.","saidas":"operating, investing, financing, net_change, opening_balance, closing_balance e details (categoria, conta, amount por conta movimentada).","regras":"Saldos de caixa = soma debit-credit de contas account_type bank/cash. net_change = fechamento - abertura. Classificação por root_type/account_type: income/expense e ativos/passivos correntes → operacional; fixed_asset/accumulated_depreciation → investimento; equity e 'Long Term Loan' → financiamento. Sinais ajustados (despesa/aumento de ativo = saída; aumento de passivo/receita = entrada). Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; contas com account_type bank/cash; lançamentos em gl_entry no período."},{"group":"Razão (General Ledger)","objetivo":"Lista os lançamentos do livro razão no período com saldo corrente acumulado, opcionalmente filtrados por conta, parceiro ou tipo de documento.","acoes":[{"nome":"general-ledger","desc":"Razão geral do período com saldo de abertura, lançamentos paginados e saldo corrente."}],"entradas":"--company-id/--company, --from-date, --to-date (obrigatórias); opcionais --account-id, --party-type, --party-id, --voucher-type, pares --dimension-key/--dimension-value, --limit (100), --offset (0).","saidas":"entries (posting_date, account_name, debit, credit, balance corrente, voucher_type, voucher_id, party_type/id, remarks), opening_balance, total_debit, total_credit, closing_balance.","regras":"opening_balance = soma debit-credit antes de from-date (respeitando filtros de conta/dimensão). Saldo corrente acumula por linha (debit-credit). --voucher-type é normalizado por canonical_voucher_type (ex.: 'Sales Invoice' casa com 'sales_invoice'). Considera apenas is_cancelled=0; ordenado por posting_date e created_at. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; plano de contas; lançamentos em gl_entry."},{"group":"Razão por Parceiro (Party Ledger)","objetivo":"Extrato de conta-corrente de um cliente ou fornecedor específico, com abertura, lançamentos e saldo corrente.","acoes":[{"nome":"party-ledger","desc":"Razão de um parceiro (cliente/fornecedor) com saldo de abertura e fechamento."}],"entradas":"--party-type (customer ou supplier, obrigatório), --party-id (obrigatório); opcionais --from-date, --to-date.","saidas":"party_name, opening_balance, entries (posting_date, voucher_type, voucher_id, debit, credit, balance), closing_balance.","regras":"Filtra gl_entry por party_type/party_id e is_cancelled=0. Sem --from-date a abertura é zero (cláusula 1=0); com from-date, abertura = soma debit-credit antes da data. Saldo corrente acumula debit-credit por linha. party_name resolvido em customer/supplier (cai no party_id se não achar). Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Parceiro (customer/supplier) cadastrado; lançamentos em gl_entry com party_type/party_id preenchidos."},{"group":"Aging AR/AP (Contas a Receber/Pagar por idade)","objetivo":"Classifica o saldo em aberto de clientes (AR) e fornecedores (AP) em faixas de vencimento (aging) a partir do payment_ledger_entry.","acoes":[{"nome":"ar-aging","desc":"Aging de contas a receber por cliente em faixas configuráveis."},{"nome":"ap-aging","desc":"Aging de contas a pagar por fornecedor em faixas configuráveis."}],"entradas":"--company-id/--company, --as-of-date (obrigatória); opcional --aging-buckets (padrão '30,60,90,120').","saidas":"as_of_date, total_outstanding e lista de customers/suppliers, cada um com nome/id, valor 'current', colunas days_<n> por faixa, days_<ultima>_plus e total.","regras":"Saldo em aberto vem do payment_ledger_entry (delinked=0, posting_date <= as_of_date) somado por party_type/party_id, mantendo apenas saldos significativos (|soma| > 0,005 via HAVING). Idade em dias = as_of_date - posting_date de cada entrada, distribuída nas faixas informadas; acima da última faixa vai para o bucket '_plus'. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; clientes/fornecedores cadastrados; registros em payment_ledger_entry com party_type/party_id e amount."},{"group":"Faturas Vencidas (Overdue)","objetivo":"Lista as notas fiscais de venda vencidas e em aberto na data de hoje, agrupando-as em faixas de atraso.","acoes":[{"nome":"check-overdue","desc":"Faturas de venda vencidas com saldo aberto, em faixas de atraso (0-30, 31-60, 61-90, 90+)."}],"entradas":"--company-id/--company.","saidas":"overdue_count, total_overdue, buckets (0_30/31_60/61_90/90_plus com count e total) e invoices (id, name/série, customer_name, grand_total, outstanding, due_date, days_overdue, ordenadas por atraso desc).","regras":"Considera sales_invoice da empresa com status submitted/partially_paid/overdue, outstanding_amount > 0 e due_date < hoje (datetime.now()). days_overdue = hoje - due_date, distribuído nas faixas fixas. Apenas leitura; não altera status das faturas.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; tabela sales_invoice com faturas submetidas/parcialmente pagas/vencidas, due_date e outstanding_amount preenchidos."},{"group":"Orçado vs Realizado (Budget vs Actual)","objetivo":"Compara o valor orçado de cada conta/centro de custo com o realizado em gl_entry no exercício, calculando variação absoluta e percentual.","acoes":[{"nome":"budget-vs-actual","desc":"Comparativo orçado x realizado por conta/centro de custo do exercício fiscal."},{"nome":"budget-variance","desc":"Alias de budget-vs-actual."}],"entradas":"--fiscal-year-id (obrigatório), --company-id/--company; opcionais --account-id, --cost-center-id.","saidas":"items com account_or_cc, budget, actual, variance, variance_pct e action_if_exceeded.","regras":"Lê linhas de budget do fiscal_year/empresa (filtráveis por conta e centro de custo). Realizado = soma debit-credit em gl_entry (is_cancelled=0) no intervalo start_date..end_date do exercício, casando account_id e/ou cost_center_id da linha orçada. variance = budget - actual; variance_pct = variance/budget*100 (0 se budget zero). Carrega o campo action_if_exceeded da linha de orçamento. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Exercício fiscal (fiscal_year) existente; linhas em budget para o exercício; lançamentos em gl_entry."},{"group":"Relatórios Dimensionais","objetivo":"Relatórios contábeis quebrados por dimensões contábeis (project, department, etc.) lidas de gl_entry.dimensions_json, para análise por dimensão.","acoes":[{"nome":"multi-dim-trial-balance","desc":"Balancete agrupado por uma ou mais dimensões (--group-by 'project,department')."},{"nome":"dimension-balance-report","desc":"Saldo líquido por valor de uma única dimensão (--dimension), opcionalmente restrito a --values."}],"entradas":"Ambas: --company-id/--company, --to-date (obrigatória); opcional --from-date e pares --dimension-key/--dimension-value. multi-dim-trial-balance: --group-by (lista separada por vírgula, obrigatório). dimension-balance-report: --dimension (obrigatório), --values (lista opcional).","saidas":"multi-dim: group_by, as_of_date, groups (valor por dimensão + debit/credit/balance), total_debit, total_credit. dimension-balance: dimension, as_of_date, values (value, debit, credit, balance), total_debit, total_credit.","regras":"Agrupa por fragmentos json_get(dimensions_json, chave) (dialeto-aware, chave escapada); valores ficam como parâmetros vinculados. Considera is_cancelled=0 e posting_date <= to-date (>= from-date se informado). dimension-balance-report ignora valores nulos da dimensão; --values restringe via IN. balance = debit - credit. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; lançamentos em gl_entry com dimensions_json populado. (Estes endpoints não exigem registro em dimension_registry — diferente do --group-by da DRE.)"},{"group":"Resumo de Impostos (Tax Summary)","objetivo":"Resume os impostos coletados e pagos no período por conta de imposto, apurando o saldo líquido a recolher.","acoes":[{"nome":"tax-summary","desc":"Resumo de impostos do período: coletado, pago e passivo líquido por conta de imposto."}],"entradas":"--company-id/--company, --from-date, --to-date (ambas obrigatórias).","saidas":"collected (total), paid (total), net_liability (collected - paid) e by_account (account_id, account_name, amount líquido por conta).","regras":"Considera contas account_type='tax' não-grupo da empresa. Coletado = soma de credit; pago = soma de debit, no período e is_cancelled=0. amount por conta = collected - paid; contas totalmente zeradas são omitidas. net_liability = total coletado - total pago. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa; contas com account_type='tax'; lançamentos de imposto em gl_entry no período."},{"group":"Eliminações Intercompany","objetivo":"Cadastra regras de eliminação intercompany (conta-fonte/destino entre duas empresas) e gera lançamentos de eliminação no GL por exercício para consolidação, com trilha de auditoria das eliminações.","acoes":[{"nome":"add-elimination-rule","desc":"Cria regra de eliminação ligando conta de uma empresa-fonte a conta de uma empresa-destino."},{"nome":"list-elimination-rules","desc":"Lista regras de eliminação (com nomes de empresas e contas), filtrável por empresa."},{"nome":"run-elimination","desc":"Executa as regras ativas no exercício, criando pares de lançamentos no GL e registros de elimination_entry (idempotente)."},{"nome":"list-elimination-entries","desc":"Lista os elimination_entry gerados (trilha de auditoria), filtrável por exercício."}],"entradas":"add-elimination-rule: --name, --company-id (fonte), --target-company-id, --source-account-id, --target-account-id. run-elimination: --fiscal-year-id e --posting-date (ou --as-of-date). list-elimination-rules: --company-id opcional. list-elimination-entries: --fiscal-year-id opcional.","saidas":"add-elimination-rule: rule_id, name. list-elimination-rules: rules + total. run-elimination: fiscal_year, posting_date, eliminations (rule_name, amount, source_gl_id, target_gl_id, entry_id) e total_eliminated. list-elimination-entries: entries (com empresas/contas/exercício) + total.","regras":"add: empresas fonte e destino devem existir e ser diferentes; cada conta deve pertencer à sua empresa. run: valor a eliminar = (credits - debits) da source_account no período do exercício excluindo voucher_type='elimination_entry'; só elimina se > 0; idempotente (pula regra+FY se já houver elimination_entry status='posted'). Cada eliminação debita a conta-fonte (reduz receita) e credita a conta-destino (reduz despesa), em par balanceado.","efeitos":"EFEITOS REAIS: add-elimination-rule INSERE em elimination_rule (commit). run-elimination INSERE pares de lançamentos em gl_entry (voucher_type='elimination_entry', entry_set='primary', is_cancelled=0, currency='USD'/exchange_rate=1 fixos, ignorando insert_gl_entries) e em elimination_entry (commit). NÃO grava em stock_ledger_entry/payment_ledger_entry e NÃO chama audit(). list-* são somente leitura.","precondicoes":"Duas empresas distintas; contas-fonte/destino válidas em cada empresa; regras de eliminação ativas; exercício fiscal (fiscal_year) existente para run-elimination."},{"group":"Status / Diagnóstico","objetivo":"Fornece um panorama rápido do estado contábil da empresa: volume de lançamentos, janela de datas e número de exercícios fiscais.","acoes":[{"nome":"status","desc":"Resumo de saúde: contagem de gl_entry, datas de lançamento mais antiga/recente e nº de exercícios fiscais."},{"nome":"gl-summary","desc":"Resumo do GL no período agregado por voucher_type (contagem, total debit/credit)."},{"nome":"payment-summary","desc":"Resumo de pagamentos do período (recebido x pago) por tipo de parceiro, a partir de payment_entry submetidos."}],"entradas":"status: --company-id/--company. gl-summary e payment-summary: --company-id/--company, --from-date, --to-date (obrigatórias).","saidas":"status: gl_entry_count, latest/earliest_posting_date, fiscal_years. gl-summary: by_voucher_type (voucher_type, count, total_debit, total_credit). payment-summary: total_received, total_paid e by_party_type (party_type, count, amount).","regras":"Todos consideram a empresa resolvida e is_cancelled=0 onde aplicável. payment-summary soma paid_amount de payment_entry com status='submitted' no período: received = payment_type='receive', paid = payment_type='pay', e quebra por party_type. gl-summary agrupa gl_entry por voucher_type. Apenas leitura.","efeitos":"nenhum (somente leitura).","precondicoes":"Empresa cadastrada; para gl-summary há de existir gl_entry; para payment-summary, registros em payment_entry submetidos; fiscal_year para a contagem em status."}]},"hr":{"module":"hr","display":"Recursos Humanos","functionalities":[{"group":"Funcionários","objetivo":"Cadastrar, atualizar, consultar e listar funcionários, incluindo dados pessoais, vínculo organizacional e parâmetros fiscais/folha (W4, FICA, 401k, HSA).","acoes":[{"nome":"add-employee","desc":"Cria funcionário com status 'active', gera naming_series e calcula full_name."},{"nome":"update-employee","desc":"Atualização dinâmica de campos do funcionário (nome, datas, status, FKs, campos fiscais/folha)."},{"nome":"get-employee","desc":"Retorna o funcionário com nomes de depto/cargo/grade/lista de feriados e resumos derivados."},{"nome":"list-employees","desc":"Lista paginada com filtros e busca textual."}],"entradas":"add: --first-name, --date-of-joining, --company-id (obrigatórios) + opcionais (--last-name, --gender, --employment-type, --department-id, --designation-id, --employee-grade-id, --reporting-to, --emergency-contact/--bank-details JSON, --federal-filing-status, --w4-allowances, --holiday-list-id, --payroll-cost-center-id). update: --employee-id + qualquer campo opcional. get: --employee-id. list: --company-id, --department-id, --designation-id, --status, --employment-type, --search, --limit(20), --offset(0).","saidas":"add: employee_id, naming_series, full_name. update: employee_id, updated_fields. get: objeto employee (com emergency_contact/bank_details em JSON parseado), leave_balances do ano fiscal corrente, attendance_summary do mês corrente, reporting_to_name e direct_reports_count. list: lista de funcionários, total_count, paginação e has_more.","regras":"Validações: gênero em VALID_GENDERS; employment_type em VALID_EMPLOYMENT_TYPES (default full_time); status em VALID_EMPLOYEE_STATUSES; datas ISO YYYY-MM-DD; e-mails por regex; FKs (depto, cargo, grade, gestor, holiday_list, cost_center) devem existir. Funcionário não pode reportar a si mesmo. update exige ao menos um campo; full_name recalculado quando nome muda.","efeitos":"add-employee: INSERT em employee + INSERT de evento de ciclo de vida 'hiring' (employee_lifecycle_event) + auditoria. update-employee: UPDATE em employee + auditoria com old/new values. get-employee e list-employees: nenhum (somente leitura). Sem postagens no GL ou estoque.","precondicoes":"Empresa (company) deve existir; tabela 'company' é dependência obrigatória (REQUIRED_TABLES). FKs referenciadas (departamento, cargo, grade, gestor, holiday_list, cost_center) precisam existir previamente quando informadas."},{"group":"Estrutura Org.","objetivo":"Gerir a estrutura organizacional: departamentos (hierárquicos, por empresa) e designações/cargos (job titles globais).","acoes":[{"nome":"add-department","desc":"Cria departamento vinculado a empresa, com pai e cost center opcionais."},{"nome":"list-departments","desc":"Lista departamentos com nome do pai, da empresa e contagem de funcionários ativos."},{"nome":"add-designation","desc":"Cria designação (cargo) com nome único global."},{"nome":"list-designations","desc":"Lista designações com contagem de funcionários ativos por cargo."}],"entradas":"add-department: --name, --company-id (obrig.) + --parent-id, --cost-center-id. list-departments: --company-id, --parent-id, --limit, --offset. add-designation: --name (obrig.) + --description. list-designations: --limit, --offset.","saidas":"add-department: department_id, name. list-departments: departments (com parent_name, company_name, employee_count), total_count, paginação. add-designation: designation_id, name. list-designations: designations (com employee_count), total_count, paginação.","regras":"Departamento: empresa deve existir; pai (se informado) deve existir e pertencer à mesma empresa; cost center deve existir; nome único por empresa. Designação: nome é UNIQUE global (duplicidade rejeitada). Contagens consideram apenas funcionários com status 'active'.","efeitos":"add-department: INSERT em department + auditoria. add-designation: INSERT em designation + auditoria. list-*: nenhum (somente leitura). Sem GL/estoque.","precondicoes":"Empresa deve existir para departamento. Cost center e departamento pai (quando usados) precisam existir. Designação não depende de empresa."},{"group":"Tipos/Alocação de Férias","objetivo":"Definir tipos de licença/férias e suas regras (pago, carry-forward, compensatório, carência) e alocar saldos por funcionário e ano fiscal, incluindo transporte de saldo do ano anterior.","acoes":[{"nome":"add-leave-type","desc":"Cria tipo de licença com limites e flags (pago, carry-forward, compensatório, carência)."},{"nome":"list-leave-types","desc":"Lista os tipos de licença cadastrados."},{"nome":"add-leave-allocation","desc":"Aloca dias de licença ao funcionário num ano fiscal, aplicando carry-forward quando habilitado."},{"nome":"get-leave-balance","desc":"Retorna o saldo por tipo de licença, com dias pendentes em rascunho."}],"entradas":"add-leave-type: --name, --max-days-allowed (obrig.) + --is-paid-leave(1), --is-carry-forward(0), --max-carry-forward-days, --is-compensatory(0), --applicable-after-days(0). add-leave-allocation: --employee-id, --leave-type-id, --total-leaves, --fiscal-year (obrig.). get-leave-balance: --employee-id (obrig.) + --leave-type-id, --fiscal-year.","saidas":"add-leave-type: leave_type_id, name, max_days_allowed. add-leave-allocation: allocation_id, total/used/remaining_leaves, e carry_forwarded/carry_forwarded_from quando aplicável. get-leave-balance: balances por tipo (total/used/remaining + pending_days em rascunho), fiscal_year, total_count.","regras":"leave_type.name é UNIQUE; max_days_allowed > 0; flags 0/1; max_carry_forward_days >= 0; applicable_after_days >= 0. Alocação: funcionário/tipo/ano fiscal devem existir; total_leaves >= 0; impede alocação duplicada (mesmo emp+tipo+ano). Carry-forward: se o tipo permite, busca alocação do ano anterior e soma remaining_leaves (limitado a max_carry_forward_days). remaining = total - used (used inicia 0).","efeitos":"add-leave-type: INSERT em leave_type + auditoria. add-leave-allocation: INSERT em leave_allocation (com carry_forwarded_from) + auditoria. list/get: nenhum (somente leitura). Sem GL/estoque.","precondicoes":"Para alocação: funcionário, leave_type e fiscal_year (registro em fiscal_year) devem existir. get-leave-balance usa o ano fiscal aberto corrente quando não informado."},{"group":"Solicitações de Férias","objetivo":"Gerir o ciclo de solicitações de licença/férias: criação (rascunho), aprovação com baixa de saldo, rejeição e consulta.","acoes":[{"nome":"add-leave-application","desc":"Cria solicitação em 'draft' calculando dias úteis (excluindo fins de semana e feriados)."},{"nome":"approve-leave","desc":"Aprova solicitação 'draft' e deduz used/remaining da alocação."},{"nome":"reject-leave","desc":"Rejeita solicitação em 'draft'."},{"nome":"list-leave-applications","desc":"Lista solicitações com nomes de funcionário, tipo e aprovador."}],"entradas":"add: --employee-id, --leave-type-id, --from-date, --to-date (obrig.) + --half-day(0/1), --half-day-date, --reason. approve: --leave-application-id, --approved-by (obrig.). reject: --leave-application-id (obrig.) + --reason. list: --employee-id, --status, --from-date, --to-date, --leave-type-id, --limit, --offset.","saidas":"add: leave_application_id, naming_series, total_days, half_day, status 'draft', holidays_excluded. approve: status 'approved', approver_name, total_days, leave_type. reject: status 'rejected', rejection_reason. list: leave_applications + total_count e paginação.","regras":"Ciclo: draft -> approved | rejected. add: funcionário deve estar 'active'; from <= to; half-day-date dentro do intervalo; respeita applicable_after_days do tipo; total_days = dias úteis excluindo feriados (- 0,5 se half-day) e deve ser > 0; valida saldo suficiente na alocação; bloqueia sobreposição com solicitações draft/approved. approve: exige status 'draft', aprovador válido, não pode aprovar a própria; deduz da alocação e bloqueia saldo negativo (rollback). reject: exige status 'draft'.","efeitos":"add: INSERT em leave_application (status draft) + auditoria. approve: UPDATE leave_application (approved, approved_by) + UPDATE leave_allocation (used += total_days, remaining -= total_days) + auditoria. reject: UPDATE leave_application (rejected) + auditoria. list: nenhum (somente leitura). Sem GL/estoque.","precondicoes":"Funcionário ativo e tipo de licença existentes; alocação de licença para o ano fiscal da from-date (approve faz rollback se não houver alocação ou ano fiscal aberto). Feriados via lista do funcionário ou da empresa."},{"group":"Ponto","objetivo":"Registrar e consultar marcações de ponto/presença por funcionário e data, individualmente ou em lote.","acoes":[{"nome":"mark-attendance","desc":"Marca o ponto de um funcionário numa data com status, horários e flags."},{"nome":"bulk-mark-attendance","desc":"Marca o ponto de vários funcionários numa data (pula duplicados, acumula erros)."},{"nome":"list-attendance","desc":"Lista marcações com nome do funcionário e resumo agregado por status."}],"entradas":"mark: --employee-id, --date, --status (obrig.) + --shift, --check-in-time, --check-out-time, --working-hours, --late-entry(0/1), --early-exit(0/1), --source. bulk: --date, --entries (JSON [{employee_id,status}]) + --source. list: --employee-id, --from-date, --to-date, --status, --limit, --offset.","saidas":"mark: attendance_id, employee_name, date, status, source. bulk: total, created, skipped_duplicates, errors[]. list: attendance[] + total_count, paginação e summary (contagens por status: present/absent/half_day/on_leave/work_from_home).","regras":"status em VALID_ATTENDANCE_STATUSES; source em VALID_ATTENDANCE_SOURCES (default manual); late_entry/early_exit 0/1; data ISO e não futura (mark). Unicidade por employee_id+attendance_date: mark rejeita duplicado; bulk pula duplicado (skipped_duplicates) e valida cada entrada acumulando erros sem abortar.","efeitos":"mark-attendance: INSERT em attendance + auditoria. bulk-mark-attendance: INSERT em attendance por entrada válida (sem auditoria por linha). list: nenhum (somente leitura). Sem GL/estoque.","precondicoes":"Funcionário deve existir. Não pode haver marcação prévia para a mesma data (chave única employee_id+attendance_date)."},{"group":"Regularização","objetivo":"Definir regras de regularização de atraso por empresa e aplicá-las às marcações de ponto com atraso, ajustando status ou gerando avisos.","acoes":[{"nome":"add-regularization-rule","desc":"Cria regra com limite de minutos de atraso e ação (half_day/deduct_leave/warn)."},{"nome":"apply-attendance-regularization","desc":"Aplica as regras às marcações com late_entry=1 num período."}],"entradas":"add-regularization-rule: --company-id, --late-threshold-minutes, --regularization-action (obrig.). apply-attendance-regularization: --company-id (obrig.) + --from-date, --to-date.","saidas":"add: rule_id, company_id, late_threshold_minutes, action. apply: records_processed, records_updated, warnings[] (com employee_id, data, late_minutes) e warning_count.","regras":"Ação em VALID_REGULARIZATION_ACTIONS (half_day, deduct_leave, warn); late_threshold_minutes inteiro > 0. apply: processa apenas attendance com late_entry=1 da empresa no período; calcula atraso a partir de check_in_time considerando início às 9h; ao atingir o threshold da primeira regra aplicável: 'half_day' altera status, 'warn'/'deduct_leave' apenas geram aviso (não alteram saldo de licença).","efeitos":"add-regularization-rule: INSERT em attendance_regularization_rule + auditoria. apply-attendance-regularization: UPDATE em attendance (status='half_day') para registros com ação half_day; ações warn/deduct_leave NÃO alteram dados (somente avisos). Sem GL/estoque e sem auditoria por registro alterado.","precondicoes":"Empresa deve existir. apply exige ao menos uma regra de regularização cadastrada para a empresa; depende de marcações de ponto com late_entry=1 e check_in_time preenchido."},{"group":"Feriados","objetivo":"Cadastrar listas de feriados por empresa, com entradas filhas de datas, usadas no cálculo de dias úteis das solicitações de licença.","acoes":[{"nome":"add-holiday-list","desc":"Cria lista de feriados com período e entradas de datas filtradas ao intervalo."}],"entradas":"--name, --company-id, --from-date, --to-date (obrig.) + --holidays (JSON [{date, description}]).","saidas":"holiday_list_id, name, from_date, to_date, holiday_count (feriados efetivamente inseridos).","regras":"Empresa deve existir; from <= to; holiday_list.name é UNIQUE. Cada feriado precisa de date válida e dentro do intervalo (datas inválidas ou fora do range são ignoradas silenciosamente).","efeitos":"INSERT em holiday_list + INSERT em holiday para cada feriado válido + auditoria. Somente escrita nessas tabelas; sem GL/estoque.","precondicoes":"Empresa deve existir. As listas/feriados são posteriormente consumidos no cálculo de licenças (lista do funcionário ou da empresa)."},{"group":"Reembolsos de Despesas","objetivo":"Gerir o ciclo de reembolso de despesas de funcionários: rascunho com itens, submissão, aprovação com postagem contábil, rejeição, integração com pagamentos e consulta.","acoes":[{"nome":"add-expense-claim","desc":"Cria reembolso 'draft' com itens, calcula total e gera naming_series."},{"nome":"submit-expense-claim","desc":"Submete reembolso 'draft' para aprovação (status 'submitted')."},{"nome":"approve-expense-claim","desc":"Aprova reembolso 'submitted' e gera lançamentos no GL (DR despesa / CR conta a pagar)."},{"nome":"reject-expense-claim","desc":"Rejeita reembolso 'submitted'."},{"nome":"update-expense-claim-status","desc":"Atualiza status/payment_entry_id (uso cross-skill por payments, ex.: marcar 'paid')."},{"nome":"list-expense-claims","desc":"Lista reembolsos com nome do funcionário e contagem de itens."}],"entradas":"add: --employee-id, --expense-date, --company-id, --items (JSON [{expense_type,description,amount,account_id}]) (obrig.). submit/approve/reject: --expense-claim-id (approve também --approved-by; reject opcional --reason). update-status: --expense-claim-id, --status (+ --payment-entry-id). list: --employee-id, --status, --company-id, --from-date, --to-date, --limit, --offset.","saidas":"add: expense_claim_id, naming_series, total_amount, item_count, status 'draft'. submit: status 'submitted'. approve: status 'approved', gl_entry_count, gl_entry_ids. reject: status 'rejected'. update-status: old_status/new_status. list: expense_claims (com item_count) + total_count e paginação.","regras":"Ciclo: draft -> submitted -> approved | rejected; pode ir a 'paid' via update-status. add: itens não vazios; expense_type em VALID_EXPENSE_TYPES; amount > 0; account_id (se informado) deve existir, não ser grupo e ser da empresa; total = soma dos itens. submit exige 'draft'; approve exige 'submitted' e aprovador válido (não pode aprovar o próprio); reject exige 'submitted'. update-status valida status em VALID_EXPENSE_STATUSES.","efeitos":"add: INSERT em expense_claim + expense_claim_item + auditoria. submit/reject: UPDATE de status + auditoria. approve-expense-claim: postagem REAL no GL via insert_gl_entries (voucher_type='expense_claim') — DR conta de despesa de cada item, CR conta a pagar/passivo da empresa pelo total (party employee); UPDATE status='approved' + approval_date + auditoria; rollback se faltar conta a pagar/despesa ou ano fiscal. update-expense-claim-status: UPDATE status e payment_entry_id + auditoria (sem GL). list: somente leitura. Sem SLE de estoque.","precondicoes":"Funcionário e empresa devem existir; contas dos itens (quando informadas) devem existir/não-grupo/mesma empresa. Para aprovar: empresa precisa de conta a pagar (default_payable_account_id ou conta payable/liability) e conta de despesa default, cost center não-grupo e ano fiscal aberto na data."},{"group":"Turnos","objetivo":"Definir tipos de turno por empresa e atribuí-los a funcionários por período.","acoes":[{"nome":"add-shift-type","desc":"Cria tipo de turno com horários de início/fim e status."},{"nome":"list-shift-types","desc":"Lista tipos de turno por empresa/status."},{"nome":"update-shift-type","desc":"Atualiza nome/horários/status de um tipo de turno."},{"nome":"assign-shift","desc":"Atribui um tipo de turno a um funcionário num intervalo de datas."},{"nome":"list-shift-assignments","desc":"Lista atribuições com nome do turno e do funcionário."}],"entradas":"add-shift-type: --name, --start-time, --end-time, --company-id (obrig.) + --status. update-shift-type: --shift-type-id + campos opcionais. assign-shift: --employee-id, --shift-type-id, --start-date (obrig.) + --end-date, --status. list-shift-types: --company-id, --status, --limit, --offset. list-shift-assignments: --employee-id, --shift-type-id, --status, --company-id, --limit, --offset.","saidas":"add-shift-type: shift_type_id, name, horários, shift_status. update: registro atualizado (status renomeado para shift_status). assign-shift: shift_assignment_id, datas, assignment_status. list-*: listas + count.","regras":"Horários em HH:MM ou HH:MM:SS (regex); status em (active, inactive); shift_type.name é único (validado na criação e atualização). assign-shift: funcionário e tipo de turno devem existir; datas em YYYY-MM-DD; end_date não anterior a start_date. update exige ao menos um campo.","efeitos":"add-shift-type: INSERT em shift_type (sem auditoria). update-shift-type: UPDATE em shift_type (sem auditoria). assign-shift: INSERT em shift_assignment (sem auditoria). list-*: somente leitura. Sem GL/estoque.","precondicoes":"Empresa deve existir (tipo de turno). Funcionário e tipo de turno devem existir para atribuição."},{"group":"Documentos","objetivo":"Gerir documentos de funcionários (passaporte, visto, I9, W4, contrato etc.), consultá-los e monitorar vencimentos.","acoes":[{"nome":"add-employee-document","desc":"Adiciona documento ao funcionário com tipo, nome, validade e status 'active'."},{"nome":"list-employee-documents","desc":"Lista documentos de um funcionário com filtros por tipo/status."},{"nome":"get-employee-document","desc":"Retorna um documento específico por id."},{"nome":"check-expiring-documents","desc":"Lista documentos ativos a vencer em N dias, com dias restantes e flag de vencido."}],"entradas":"add: --employee-id, --document-type, --document-name (obrig.) + --expiry-date, --notes. list: --employee-id (obrig.) + --document-type, --status. get: --document-id (obrig.). check-expiring: --company-id, --days (default 30).","saidas":"add: employee_document_id, employee_name, document_type, expiry_date. list/get: documento(s) (campos completos). check-expiring: expiring_documents (com days_until_expiry e is_expired), count, days_window.","regras":"document_type em VALID_DOCUMENT_TYPES; status em VALID_DOCUMENT_STATUSES (default 'active'); expiry_date ISO YYYY-MM-DD quando informado. check-expiring considera apenas documentos 'active' com expiry_date <= hoje+N dias.","efeitos":"add-employee-document: INSERT em employee_document + auditoria. list/get/check-expiring: nenhum (somente leitura). Sem GL/estoque.","precondicoes":"Funcionário deve existir (add e list). Sem outras dependências contábeis."},{"group":"Eventos de Carreira","objetivo":"Registrar eventos do ciclo de vida do funcionário (contratação, promoção, transferência, desligamento etc.), atualizando o cadastro em eventos de saída.","acoes":[{"nome":"record-lifecycle-event","desc":"Registra evento de ciclo de vida; em separation/resignation/retirement marca o funcionário como 'left' e define date_of_exit."}],"entradas":"--employee-id, --event-type, --event-date (obrig.) + --details, --old-values, --new-values (JSON).","saidas":"event_id, employee_name, event_type, event_date; em eventos de saída inclui employee_status_updated=true, new_employee_status='left' e date_of_exit.","regras":"event_type em VALID_LIFECYCLE_EVENTS (hiring, confirmation, promotion, transfer, separation, resignation, retirement); event_date ISO. Para separation/resignation/retirement: além de registrar o evento, atualiza employee.status='left' e date_of_exit = event_date. Obs.: 'hiring' também é gerado automaticamente ao criar funcionário em add-employee.","efeitos":"INSERT em employee_lifecycle_event + auditoria; em eventos de saída, UPDATE em employee (status='left', date_of_exit). Sem GL/estoque.","precondicoes":"Funcionário deve existir. Sem dependências contábeis."},{"group":"Status","objetivo":"Fornecer um painel-resumo do módulo de RH com contagens e indicadores agregados, opcionalmente por empresa.","acoes":[{"nome":"status","desc":"Resumo: funcionários por status, departamentos, licenças e ponto do período corrente, reembolsos por status e eventos recentes."}],"entradas":"--company-id (opcional, filtra todos os agregados por empresa).","saidas":"total_employees, employees_by_status, total_departments, leave_summary (ano fiscal corrente), attendance_summary_current_month, expense_claims_by_status, recent_lifecycle_events (últimos 10) e fiscal_year.","regras":"Agrega contagens por status/categoria sobre employee, department, leave_application, attendance e expense_claim; licenças e ponto usam o ano fiscal aberto corrente e o mês corrente, respectivamente; quando --company-id é informado, todos os recortes são filtrados pela empresa.","efeitos":"Nenhum (somente leitura).","precondicoes":"Tabela 'company' presente (dependência do módulo). Indicadores de licença dependem de existir ano fiscal aberto para a data corrente."}]},"payroll":{"module":"payroll","display":"Folha de Pagamento","functionalities":[{"group":"Componentes","objetivo":"Cadastrar e listar componentes salariais (vencimentos, descontos e contribuições patronais) que servem de blocos para montar estruturas salariais e calcular holerites.","acoes":[{"nome":"add-salary-component","desc":"Cria um componente salarial com tipo (earning/deduction/employer_contribution) e flags fiscais."},{"nome":"list-salary-components","desc":"Lista componentes com filtro por tipo, busca por nome e paginação."}],"entradas":"add: --name, --component-type (obrigatórios), --is-tax-applicable, --is-statutory, --is-pre-tax, --variable-based-on-taxable-salary, --depends-on-payment-days, --is-supplemental, --gl-account-id, --description. list: --component-type, --search, --limit, --offset.","saidas":"add: salary_component_id, name, component_type. list: count, components[], limit, offset, has_more.","regras":"component-type deve estar em (earning, deduction, employer_contribution). Nome único (erro se já existir). Booleanos aceitam 1/0, true/false, yes/no com defaults: is_tax_applicable=1, depends_on_payment_days=1, demais=0. Se --gl-account-id informado, valida que a conta existe.","efeitos":"Insere em salary_component e grava auditoria (audit) para add-salary-component. list é somente leitura.","precondicoes":"Tabelas company e employee existentes. Conta GL deve existir se --gl-account-id for usado."},{"group":"Estruturas","objetivo":"Definir estruturas salariais que agrupam componentes com regra de cálculo (valor fixo, percentual sobre base, ou fórmula) e frequência de pagamento; consultar e listar essas estruturas.","acoes":[{"nome":"add-salary-structure","desc":"Cria estrutura salarial com array JSON de componentes e seus detalhes de cálculo."},{"nome":"get-salary-structure","desc":"Retorna a estrutura com o detalhamento ordenado de seus componentes."},{"nome":"list-salary-structures","desc":"Lista estruturas com filtro por empresa/busca e contagem de componentes."}],"entradas":"add: --name, --company-id, --components (JSON: salary_component_id, amount?, percentage?, formula?, base_component_id?, sort_order?), --payroll-frequency (default monthly). get: --salary-structure-id. list: --company-id, --search, --limit, --offset.","saidas":"add: salary_structure_id, name, payroll_frequency, component_count. get: salary_structure com components[] (inclui base_component_name) e component_count. list: count, structures[] com component_count.","regras":"payroll-frequency em (monthly, biweekly, weekly). Nome único. Empresa deve existir. Cada componente: no máximo UM de amount/percentage/formula; percentual entre 0 e 100; sem componentes duplicados; base_component_id e salary_component_id devem existir. Moeda fixada em USD; is_active=1.","efeitos":"Insere em salary_structure e salary_structure_detail; grava auditoria. get e list são somente leitura.","precondicoes":"Empresa cadastrada e componentes salariais já criados (referenciados por id no JSON)."},{"group":"Atribuições","objetivo":"Vincular um funcionário a uma estrutura salarial com um valor-base e vigência, gerenciando o histórico de atribuições; listar atribuições.","acoes":[{"nome":"add-salary-assignment","desc":"Atribui estrutura salarial ao funcionário com base-amount e vigência, auto-encerrando a atribuição anterior."},{"nome":"list-salary-assignments","desc":"Lista atribuições com filtros por funcionário, empresa e intervalo de datas."}],"entradas":"add: --employee-id, --salary-structure-id, --base-amount, --effective-from (obrigatórios), --effective-to (opcional). list: --employee-id, --company-id, --from-date, --to-date, --limit, --offset.","saidas":"add: salary_assignment_id, employee_id, salary_structure_id, base_amount, effective_from, effective_to, e previous_assignment_closed se houve encerramento. list: count, assignments[] (com employee_name e salary_structure_name), paginação.","regras":"Funcionário e estrutura devem existir e pertencer à MESMA empresa. base-amount não-negativo (arredondado). effective-to >= effective-from. Se já existe atribuição ativa (effective_to nula ou >= novo effective_from), ela é encerrada no dia anterior ao novo início. Moeda USD.","efeitos":"Insere em salary_assignment; faz UPDATE da atribuição anterior (effective_to); grava auditoria com descrição do encerramento. list é somente leitura.","precondicoes":"Funcionário e estrutura salarial existentes e da mesma empresa."},{"group":"Tabelas de IR (Income Tax Slabs)","objetivo":"Configurar tabelas progressivas de imposto de renda federal/estadual com faixas (brackets) de alíquotas e dedução padrão, usadas no cálculo do holerite; também cadastrar faixas estaduais para folha multi-estado.","acoes":[{"nome":"add-income-tax-slab","desc":"Cria tabela de IR federal/estadual com faixas contíguas de alíquota e dedução padrão."},{"nome":"add-state-tax-slab","desc":"Cria uma faixa (bracket) de imposto estadual por estado e filing-status."}],"entradas":"income-tax-slab: --name, --tax-jurisdiction (federal/state), --effective-from (obrig.), --filing-status, --state-code, --standard-deduction, --rates (JSON: from_amount, to_amount, rate). state-tax-slab: --state-code, --bracket-start, --rate (obrig.), --bracket-end, --filing-status (default single).","saidas":"income-tax-slab: income_tax_slab_id, name, tax_jurisdiction, state_code, filing_status, effective_from, standard_deduction, rate_count. state-tax-slab: state_tax_slab_id, state_code, bracket_start, bracket_end, rate, filing_status.","regras":"jurisdiction em (federal, state); state-code obrigatório para state e ignorado para federal. filing-status em (single, married_jointly, married_separately, head_of_household). Faixas devem ser contíguas (from == to anterior); última pode ter to_amount null; rate 0-100; to>from. Alíquotas são percentuais. Aplicação no cálculo é progressiva (graduada).","efeitos":"add-income-tax-slab insere em income_tax_slab e income_tax_slab_rate e grava auditoria. add-state-tax-slab insere em state_tax_slab (sem auditoria).","precondicoes":"Nenhuma dependência de outras entidades; estado válido para faixas estaduais."},{"group":"Config. de Impostos (FICA/FUTA/SUTA)","objetivo":"Configurar por ano-fiscal as alíquotas e bases de FICA (Social Security e Medicare) e os tributos de desemprego FUTA (federal) e SUTA (estadual), parâmetros que alimentam o cálculo das retenções e contribuições patronais.","acoes":[{"nome":"update-fica-config","desc":"Upsert da configuração FICA do ano: base salarial e alíquotas de SS/Medicare empregado/empregador e Medicare adicional."},{"nome":"update-futa-suta-config","desc":"Upsert de FUTA (state_code nulo) ou SUTA (state_code preenchido) com base, alíquota e override patronal."}],"entradas":"fica: --tax-year, --ss-wage-base, --ss-employee-rate, --ss-employer-rate, --medicare-employee-rate, --medicare-employer-rate, --additional-medicare-threshold, --additional-medicare-rate (todos obrig.). futa-suta: --tax-year, --wage-base, --rate (obrig.), --state-code (NULL=FUTA), --employer-rate-override.","saidas":"Os parâmetros gravados mais action='created' ou 'updated' (e, em futa-suta, config_type 'FUTA (federal)' ou 'SUTA (XX)').","regras":"tax-year inteiro em [2000,2100]. Todos os valores decimais validados e não-negativos; rate 0-100. FICA usa ON CONFLICT(tax_year); FUTA/SUTA usa ON CONFLICT(tax_year, state_code). employer_rate_override permite ajuste por empresa (SUTA experience-rated).","efeitos":"Upsert em fica_config e futa_suta_config respectivamente; grava auditoria com old_values/new_values. Nenhuma postagem contábil aqui (apenas configuração).","precondicoes":"Nenhuma dependência de empresa/funcionário; apenas o ano-fiscal."},{"group":"Ciclos de Folha (Payroll Runs)","objetivo":"Gerenciar o ciclo de vida de uma corrida de folha por período: criar (rascunho), gerar holerites, submeter com postagem no GL e cancelar com estorno; também o status individual da corrida.","acoes":[{"nome":"create-payroll-run","desc":"Cria uma corrida de folha em status 'draft' para um período, validando sobreposição."},{"nome":"submit-payroll-run","desc":"Submete a corrida: marca holerites como 'submitted' e posta entradas no GL de forma atômica e balanceada."},{"nome":"cancel-payroll-run","desc":"Cancela corrida submetida, estorna o GL e marca holerites como 'cancelled'."}],"entradas":"create: --company-id, --period-start, --period-end (obrig.), --department-id, --payroll-frequency. submit: --payroll-run-id, --cost-center-id (busca default se ausente). cancel: --payroll-run-id.","saidas":"create: payroll_run_id, naming_series, período, frequência. submit: gl_entries (qtd), total_gross, total_net, total_employer_tax. cancel: reversed_entries (qtd), naming_series.","regras":"Ciclo: draft -> submitted -> cancelled. create exige period_start < period_end, empresa existente, departamento válido se informado, e proíbe corrida sobreposta não-cancelada. submit exige status 'draft' e ao menos 1 holerite draft; calcula impostos patronais (SS/Medicare/FUTA/SUTA), monta DR despesa salarial+tributos patronais e CR líquido(+pré-tax por funcionário)/IR federal/estadual/SS/Medicare/FUTA/SUTA, valida DR=CR (auto-corrige diferença <=1.00) e descarta entradas zeradas. cancel exige status 'submitted'.","efeitos":"create: insere payroll_run, auditoria. submit: insere gl_entry via insert_gl_entries (voucher_type='payroll_entry'), atualiza salary_slip para 'submitted' e payroll_run para 'submitted', auditoria; rollback se a postagem falhar. cancel: reverse_gl_entries, atualiza slips e run para 'cancelled', auditoria.","precondicoes":"Empresa com plano de contas (conta de despesa salarial e payroll payable localizáveis), FICA/FUTA/SUTA do ano configurados para os tributos patronais, cost center, e holerites já gerados antes do submit."},{"group":"Holerites (Salary Slips)","objetivo":"Gerar, consultar e listar os holerites de cada funcionário de uma corrida, executando o motor de cálculo completo (vencimentos, proporcionalização, pré-tax, IR federal/estadual, FICA, horas extras e penhoras).","acoes":[{"nome":"generate-salary-slips","desc":"Motor de cálculo: gera salary_slip e salary_slip_detail para todos os funcionários elegíveis da corrida."},{"nome":"get-salary-slip","desc":"Retorna um holerite com earnings e deductions aninhados."},{"nome":"list-salary-slips","desc":"Lista holerites filtrando por corrida, funcionário e status, com paginação."}],"entradas":"generate: --payroll-run-id. get: --salary-slip-id. list: --payroll-run-id, --employee-id, --status, --limit, --offset.","saidas":"generate: payroll_run_id, slips_generated, total_gross, total_deductions, total_net. get: campos do slip + earnings[], deductions[], details[]. list: count, slips[] (com employee_name), paginação.","regras":"generate exige run em 'draft'; reapaga slips draft existentes (permite regerar). Vencimentos por valor/percentual sobre base (percentual tem prioridade) e prorrateio por payment_days (dias úteis menos folga não-paga). Pré-tax 401k (% do bruto) e HSA do cadastro do funcionário. IR federal progressivo anualizado menos dedução padrão; salário suplementar com flat 22% (37% acima de 1M YTD). IR estadual via employee_state_config. FICA: SS limitado à wage base via YTD, Medicare sem teto + Medicare adicional 0.9% acima do limiar; respeita is_exempt_from_fica. Penhoras pós-imposto por prioridade com teto federal. Slips criados em status 'draft'.","efeitos":"generate: deleta/insere salary_slip e salary_slip_detail, atualiza totais da payroll_run, ATUALIZA wage_garnishment (cumulative_paid e auto status 'completed'), pode auto-criar componentes estatutários, auditoria. get/list são somente leitura. Sem postagem GL nesta etapa (ocorre no submit).","precondicoes":"Corrida em 'draft'; funcionários ativos com salary_assignment vigente; estrutura com componentes; FICA do ano para reter FICA; opcionalmente tabelas de IR, overtime_policy, employee_state_config e penhoras."},{"group":"W-2 (Dados de Fim de Ano)","objetivo":"Consolidar todos os holerites submetidos do ano por funcionário e produzir os dados das caixas (boxes) do formulário W-2 para fins de declaração anual.","acoes":[{"nome":"generate-w2-data","desc":"Agrega slips submetidos do ano e calcula as caixas 1-6 e 12 (códigos D/W) do W-2 por funcionário."}],"entradas":"--tax-year, --company-id (ambos obrigatórios).","saidas":"tax_year, company_id, company_name, employee_count e w2_data[] com employee_id, employee_name, ssn_last_four, filing_status e boxes (1=salários líquidos de pré-tax, 2=IR federal, 3=salário SS limitado à base, 4=SS retido, 5=salário Medicare, 6=Medicare retido, 12.D=401k, 12.W=HSA).","regras":"tax-year inteiro; empresa deve existir. Considera apenas slips com status 'submitted' do ano-calendário. Box1 = bruto - pré-tax (401k+HSA+demais pré-tax). Box3 limitado à ss_wage_base do FICA (default 168600 se sem config). Box12 só inclui códigos não-zero. SSN é descriptografado e mascarado para os 4 últimos dígitos.","efeitos":"Nenhum (somente leitura); apenas descriptografa SSN para exibição parcial.","precondicoes":"Empresa cadastrada; holerites do ano já submetidos; idealmente FICA do ano configurado para a base de SS da Box 3."},{"group":"Penhoras (Wage Garnishments)","objetivo":"Gerenciar ordens de penhora salarial por funcionário (pensão, levy fiscal, empréstimo estudantil, credor), com prioridade legal e teto federal, aplicadas pós-imposto na geração dos holerites.","acoes":[{"nome":"add-garnishment","desc":"Cria ordem de penhora com tipo, valor/percentual, prioridade e teto federal."},{"nome":"update-garnishment","desc":"Atualiza status, valor, total devido ou data-fim da penhora."},{"nome":"list-garnishments","desc":"Lista penhoras por funcionário/empresa/status, ordenadas por prioridade."},{"nome":"get-garnishment","desc":"Retorna uma penhora pelo id."}],"entradas":"add: --employee-id, --order-number, --creditor-name, --garnishment-type, --start-date (obrig.), --amount-or-percentage, --is-percentage, --total-owed, --end-date. update: --garnishment-id + campos. list: --employee-id, --company-id, --status. get: --garnishment-id.","saidas":"add: garnishment_id, priority. update: updated=true. list: garnishments[], count. get: registro completo.","regras":"garnishment-type em (child_support, tax_levy, student_loan, creditor) com prioridade 1-4 nessa ordem; teto (max_percentage) 50% para child_support, 25% para os demais. Status válidos: active/paused/completed/cancelled. Criada com status 'active' e cumulative_paid=0. Na folha, aplica-se por prioridade sobre a renda disponível, respeitando teto e saldo devedor.","efeitos":"add insere em wage_garnishment + auditoria; update faz dynamic_update + auditoria; list/get somente leitura. O cumulative_paid e o status 'completed' são atualizados em generate-salary-slips (não nestas ações).","precondicoes":"Funcionário existente (a empresa é derivada do funcionário)."},{"group":"Horas Extras (Overtime)","objetivo":"Configurar a política de horas extras da empresa e calcular HE de um funcionário a partir da frequência (attendance), integrando o valor de HE ao bruto na geração de holerites.","acoes":[{"nome":"add-overtime-policy","desc":"Cria/atualiza (upsert) a política de HE da empresa: limiares semanal/diário e multiplicadores."},{"nome":"calculate-overtime","desc":"Calcula horas regulares/extras e valores de um funcionário no período a partir da attendance."}],"entradas":"policy: --company-id (obrig.), --weekly-threshold (default 40), --daily-threshold, --ot-multiplier (default 1.5), --double-ot-multiplier (default 2.0). calculate: --employee-id, --period-start, --period-end (obrig.), --hourly-rate (senão derivado da atribuição).","saidas":"policy: company_id e parâmetros gravados. calculate: total_hours, regular_hours, ot_hours, hourly_rate, ot_multiplier, regular_amount, ot_amount, total_amount.","regras":"Empresa deve existir; multiplicadores e limiares não-negativos. Upsert ON CONFLICT(company_id). Hora derivada = salário-base*12/2080. HE = maior entre HE diária (horas>daily_threshold) e HE semanal (total - weekly_threshold*nº semanas), sem dupla contagem. Considera attendance com status present/work_from_home/half_day (working_hours default 8).","efeitos":"add-overtime-policy faz upsert em overtime_policy (sem auditoria). calculate-overtime é somente leitura. Observação: a integração de HE ao bruto e a criação do componente 'Overtime Pay' ocorrem em generate-salary-slips.","precondicoes":"Empresa cadastrada e política de HE existente (para calculate); registros de attendance no período; salary_assignment vigente se não for passada --hourly-rate."},{"group":"Retro (Pagamento Retroativo)","objetivo":"Calcular pagamento retroativo de um funcionário comparando a taxa-base atual com a anterior e gerando ajustes por período afetado.","acoes":[{"nome":"calculate-retro-pay","desc":"Compara as duas últimas atribuições e gera ajustes retroativos por período afetado."}],"entradas":"--employee-id (obrig.), --from-date, --to-date (limitam o intervalo).","saidas":"employee_id, periods_affected, total_retro_amount, details[] (period_from, period_to, old_rate, new_rate, adjustment_amount); mensagem se não houver retro.","regras":"Exige >= 2 atribuições salariais. Compara as duas mais recentes; se a atual não for maior que a anterior, retorna 0 sem gerar ajustes. Intervalo padrão = effective_from da anterior até o da atual, ajustável por from/to-date. Ajuste por período = diferença de taxa-base (rate_diff). Se houver slips no intervalo, gera um ajuste por slip; senão, gera por períodos aproximados de 30 dias.","efeitos":"Insere registros em retro_pay_adjustment com status 'pending'. Sem postagem no GL e sem auditoria nesta ação.","precondicoes":"Funcionário com pelo menos duas atribuições salariais no histórico."},{"group":"ACH/NACHA (Depósito Direto)","objetivo":"Gerenciar contas bancárias dos funcionários (com criptografia em repouso) e gerar o arquivo NACHA/ACH de pagamento líquido a partir de uma corrida submetida.","acoes":[{"nome":"add-employee-bank-account","desc":"Cadastra conta bancária do funcionário para depósito direto, criptografando routing/conta."},{"nome":"list-employee-bank-accounts","desc":"Lista contas do funcionário com número de conta mascarado."},{"nome":"generate-nacha-file","desc":"Gera o arquivo NACHA de largura fixa (registros 1/5/6/8/9) com os líquidos da corrida."}],"entradas":"add: --employee-id, --bank-name, --routing-number, --account-number (obrig.), --account-type (checking/savings, default checking). list: --employee-id. nacha: --payroll-run-id.","saidas":"add: employee_bank_account_id e dados básicos. list: accounts[] (account_number mascarado, routing descriptografado), count. nacha: file_content, entry_count, total_amount, payroll_run_id.","regras":"routing-number exatamente 9 dígitos; account-number 4-17 dígitos; account-type checking/savings (conta criada como is_primary=1). NACHA exige corrida em status 'submitted' ou 'paid'; usa apenas conta primária por funcionário e líquido > 0; txn code 22(checking)/32(savings); monta header de arquivo/lote, entry details, batch e file control com entry hash e totais em centavos.","efeitos":"add-employee-bank-account insere em employee_bank_account (campos sensíveis criptografados) + auditoria. list e generate-nacha-file são somente leitura (descriptografam para exibir/montar o arquivo); o arquivo é retornado no JSON, não persistido.","precondicoes":"Funcionário existente; para NACHA, corrida submetida/paga com holerites não-cancelados e funcionários com conta bancária primária cadastrada."},{"group":"Status","objetivo":"Retornar um painel de métricas e contagens do domínio de folha (componentes, estruturas, atribuições ativas, corridas por status, holerites, configs FICA/IR/FUTA-SUTA e última corrida).","acoes":[{"nome":"status","desc":"Resumo agregado de contadores da folha, opcionalmente filtrado por empresa."}],"entradas":"--company-id (opcional, filtra contagens scoped por empresa).","saidas":"total_salary_components e por tipo, total/active salary_structures, total/active salary_assignments, total_payroll_runs e por status, total_salary_slips, fica_configs e fica_years, total_income_tax_slabs e por jurisdição, futa_suta_configs e latest_payroll_run.","regras":"Componentes salariais são globais (não filtrados por empresa); demais contagens respeitam --company-id quando informado. Atribuições 'ativas' = effective_to nula ou futura e effective_from <= hoje. Última corrida ordenada por period_end desc.","efeitos":"Nenhum (somente leitura).","precondicoes":"Banco inicializado com as tabelas do domínio; empresa opcional para filtro."}]},"accounting-adv":{"module":"accounting-adv","display":"Contabilidade Avançada","functionalities":[{"group":"Contratos de Receita (ASC 606)","objetivo":"Gerenciar o ciclo de vida de contratos de receita conforme ASC 606 (CRUD e modificação), servindo de cabeçalho para obrigações de desempenho, consideração variável e cronogramas de apropriação.","acoes":[{"nome":"add-revenue-contract","desc":"Cria contrato de receita em status 'draft' com naming series RCON-, total_value informado e allocated_value zerado."},{"nome":"update-revenue-contract","desc":"Atualiza cliente, número, datas, total_value e/ou contract_status (validado contra lista de status)."},{"nome":"get-revenue-contract","desc":"Retorna o contrato com suas obrigações de desempenho e considerações variáveis aninhadas."},{"nome":"list-revenue-contracts","desc":"Lista paginada com filtros por empresa, contract_status e busca textual em cliente/número."},{"nome":"modify-contract","desc":"Marca contrato como 'modified' e incrementa modification_count (apenas se draft ou active)."}],"entradas":"--company-id, --customer-name, --contract-number, --start-date, --end-date, --total-value, --contract-status; para get/update/modify: --id; filtros: --search, --limit, --offset.","saidas":"JSON com id, naming_series (RCON-), customer_name, contract_status, total_value; get inclui obligations[], obligation_count e variable_considerations[]; list traz rows[], total_count, has_more.","regras":"total_value deve ser Decimal válido; contract_status restrito a draft/active/modified/completed/terminated; ciclo: cria em draft, modify só de draft/active passa a modified incrementando contador; customer_name obrigatório na criação.","efeitos":"Insere/atualiza em advacct_revenue_contract; grava trilha de auditoria (audit) em cada criação/atualização/modificação; commit transacional. Nenhuma postagem em GL/gl_entry nem SLE de estoque.","precondicoes":"Empresa (company) deve existir; tabela advacct_revenue_contract criada via init_db.py."},{"group":"Obrigações de Desempenho","objetivo":"Registrar e satisfazer obrigações de desempenho (performance obligations) de um contrato ASC 606, controlando preço autônomo, alocado, método/base de reconhecimento e percentual de conclusão.","acoes":[{"nome":"add-performance-obligation","desc":"Cria obrigação 'unsatisfied' usando standalone_price como allocated_price e re-soma allocated_value do contrato."},{"nome":"list-performance-obligations","desc":"Lista paginada com filtros por contrato, empresa e obligation_status."},{"nome":"satisfy-performance-obligation","desc":"Define pct_complete (0-100) e deriva status: 100=satisfied (com satisfied_date), >0=partially_satisfied, 0=unsatisfied."},{"nome":"update-performance-obligation","desc":"Atualiza standalone_price, allocated_price, nome, método e base de reconhecimento."}],"entradas":"--contract-id, --company-id, --name, --standalone-price, --recognition-method (point_in_time/over_time), --recognition-basis (output/input/time); satisfy/update: --id, --pct-complete, --allocated-price.","saidas":"JSON com id, contract_id, name, standalone_price, allocated_price, recognition_method, obligation_status; satisfy retorna pct_complete e novo obligation_status.","regras":"recognition_method e recognition_basis validados contra listas; allocated_price recebe standalone_price na criação; pct_complete deve estar entre 0 e 100; não permite satisfazer obrigação já 'satisfied'; ao criar, recalcula e atualiza allocated_value do contrato (soma de allocated_price, arredondada a 0.01).","efeitos":"Insere/atualiza em advacct_performance_obligation; atualiza allocated_value/updated_at em advacct_revenue_contract na criação; grava auditoria; commit. Sem GL/SLE.","precondicoes":"Contrato de receita (advacct_revenue_contract) e empresa existentes; nome da obrigação obrigatório."},{"group":"Consideração Variável","objetivo":"Registrar e listar estimativas de consideração variável (descontos, bônus, multas) de um contrato ASC 606, com método de estimativa e valor de restrição (constraint).","acoes":[{"nome":"add-variable-consideration","desc":"Cria registro de consideração variável com valor estimado, constraint, método e probabilidade."},{"nome":"list-variable-considerations","desc":"Lista paginada das considerações variáveis filtrando por contrato e empresa."}],"entradas":"--contract-id, --company-id, --description, --estimated-amount, --constraint-amount, --method (expected_value/most_likely), --probability; list: --limit, --offset.","saidas":"JSON com id, contract_id, description, estimated_amount, method; list traz rows[], total_count, has_more.","regras":"method restrito a expected_value/most_likely; description obrigatória; estimated_amount, constraint_amount e probability default '0'; sem ciclo de status (registro append-only, sem updated_at).","efeitos":"Insere em advacct_variable_consideration; grava auditoria; commit. Sem efeito em GL/estoque/contrato.","precondicoes":"Contrato de receita e empresa existentes."},{"group":"Cronograma / Apropriação de Receita","objetivo":"Gerar o cronograma mensal de receita de uma obrigação e efetivar o reconhecimento das parcelas, suportando modificações de contrato (ajuste de períodos futuros) e reconhecimento ponto-a-ponto.","acoes":[{"nome":"calculate-revenue-schedule","desc":"Recria o cronograma mensal distribuindo allocated_price linearmente entre os meses do contrato (resto no último mês)."},{"nome":"generate-revenue-entries","desc":"Marca como recognized=1 todas as parcelas ainda não reconhecidas da obrigação e soma o total reconhecido."},{"nome":"update-schedule-amounts","desc":"Atualiza o valor de todas as parcelas não reconhecidas (modificação upgrade/downgrade afeta só o futuro)."},{"nome":"recognize-schedule-entry","desc":"Marca uma única parcela específica como reconhecida pelo seu id (reconhecimento período-a-período)."}],"entradas":"--obligation-id; para recognize-schedule-entry: --id da parcela; para update-schedule-amounts: --amount.","saidas":"JSON com obligation_id, entries_created, monthly_amount, total_amount; generate retorna recognized_count e total_recognized; recognize-schedule-entry retorna id, recognized=1 e amount.","regras":"Contrato precisa de start_date e end_date; meses = diferença ano/mês + 1, deve ser >0; allocated_price deve ser >0; valor mensal arredondado a 0.01 com resíduo no último mês; calculate APAGA cronograma anterior da obrigação antes de recriar; generate exige existir parcela não reconhecida; recognize-schedule-entry rejeita parcela já reconhecida.","efeitos":"Insere/exclui/atualiza em advacct_revenue_schedule (DELETE+INSERT em calculate; flag recognized em generate/recognize; amount em update); grava auditoria; commit. Apenas marca 'recognized' — NÃO cria gl_entry; não há postagem contábil real.","precondicoes":"Obrigação de desempenho existente; contrato associado com datas; allocated_price positivo."},{"group":"Relatórios de Receita","objetivo":"Fornecer relatórios analíticos de receita: waterfall de contratos x obrigações e resumo de reconhecimento por período.","acoes":[{"nome":"revenue-waterfall-report","desc":"Agrega por contrato: total_value, allocated_value, status, contagem de obrigações e quantas estão satisfeitas."},{"nome":"revenue-recognition-summary","desc":"Agrega o cronograma por period_date somando total, reconhecido e não reconhecido por período."}],"entradas":"--company-id (filtro opcional).","saidas":"JSON com report, rows[] e total_contracts (waterfall) ou total_periods (summary).","regras":"waterfall usa LEFT JOIN contrato x obrigação agrupado por contrato; summary agrupa parcelas por period_date e separa recognized=1 de recognized=0; sem validações de escrita.","efeitos":"Nenhum (somente leitura).","precondicoes":"Tabelas advacct_revenue_contract, advacct_performance_obligation e advacct_revenue_schedule existentes."},{"group":"Arrendamentos (ASC 842)","objetivo":"Gerenciar o cadastro de arrendamentos (leases) conforme ASC 842 (CRUD) e classificá-los como operacional ou financeiro.","acoes":[{"nome":"add-lease","desc":"Cria lease em 'draft' (naming LEAS-) com locatário, locador, prazo, pagamento mensal e taxa; ROU e passivo ficam nulos."},{"nome":"update-lease","desc":"Atualiza partes, datas, pagamento, taxa, escalonamento, opção de compra, tipo e prazo."},{"nome":"get-lease","desc":"Retorna o lease com pagamentos e lançamentos de amortização aninhados."},{"nome":"list-leases","desc":"Lista paginada filtrando por empresa, lease_type, lease_status e busca textual."},{"nome":"classify-lease","desc":"Classifica como finance (prazo >=36 meses) ou operating; aceita override via --lease-type."}],"entradas":"--company-id, --lessee-name, --lessor-name, --asset-description, --lease-type (operating/finance), --term-months, --monthly-payment, --annual-escalation, --discount-rate, --purchase-option-price; get/update/classify: --id.","saidas":"JSON com id, naming_series (LEAS-), lessee_name, lessor_name, lease_status, term_months; get inclui payments[], payment_count e amortization_entries[]; classify retorna lease_type.","regras":"lease_type restrito a operating/finance (default operating); lease_status restrito a draft/active/modified/expired/terminated; lessee_name e lessor_name obrigatórios; classify usa regra simplificada por prazo (>=36 meses => finance); ciclo inicia em draft.","efeitos":"Insere/atualiza em advacct_lease (classify atualiza lease_type); grava auditoria; commit. Sem GL/SLE.","precondicoes":"Empresa existente; tabela advacct_lease criada."},{"group":"ROU / Passivo de Arrendamento","objetivo":"Calcular o ativo de direito de uso (ROU) e o passivo de arrendamento como valor presente dos pagamentos mensais usando a taxa de desconto.","acoes":[{"nome":"calculate-rou-asset","desc":"Calcula rou_asset_value = VP de uma anuidade ordinária dos pagamentos mensais e grava no lease."},{"nome":"calculate-lease-liability","desc":"Calcula lease_liability = VP dos pagamentos restantes (igual ao ROU no início) e grava no lease."}],"entradas":"--id (lease).","saidas":"JSON com id e rou_asset_value (ou lease_liability).","regras":"term_months e monthly_payment devem ser >0; taxa mensal = discount_rate/12; VP via fórmula de anuidade ordinária com Decimal (se taxa=0, VP = pagamento x períodos), arredondado a 0.01.","efeitos":"Atualiza rou_asset_value ou lease_liability em advacct_lease; grava auditoria; commit. Sem postagem em GL.","precondicoes":"Lease existente com term_months e monthly_payment positivos e discount_rate informada."},{"group":"Amortização / Pagamentos de Arrendamento","objetivo":"Gerar o cronograma de amortização do passivo e registrar pagamentos de arrendamento decompostos em principal e juros.","acoes":[{"nome":"generate-amortization-schedule","desc":"Recria mês a mês o cronograma de amortização (saldo abertura, pagamento, juros, principal, saldo final) a partir do VP."},{"nome":"record-lease-payment","desc":"Registra um pagamento 'paid' calculando juros sobre o saldo corrente, principal e saldo após o pagamento."}],"entradas":"--lease-id, --payment-date, --payment-amount (record); generate usa --lease-id.","saidas":"generate: lease_id, entries_created, initial_balance, monthly_payment; record: id, lease_id, payment_amount, principal, interest, balance_after, payment_status='paid'.","regras":"term_months e monthly_payment >0 e start_date obrigatória (generate); saldo inicial = VP da anuidade; juros = saldo x taxa mensal, principal = pagamento - juros; último período zera o saldo (ajuste de arredondamento); record usa o closing_balance da última parcela de amortização, senão lease_liability, senão 0, como saldo corrente.","efeitos":"generate APAGA e reinsere advacct_amortization_entry; record insere em advacct_lease_payment; grava auditoria; commit. Não gera gl_entry nem payment_ledger_entry — apenas tabelas próprias.","precondicoes":"Lease existente com prazo, pagamento e start_date; para record, idealmente cronograma de amortização ou lease_liability já calculados."},{"group":"Relatórios de Leasing","objetivo":"Fornecer relatórios de maturidade, divulgação (disclosure) e resumo dos arrendamentos para fins de demonstração financeira ASC 842.","acoes":[{"nome":"lease-maturity-report","desc":"Lista leases ordenados por data de término com prazo, pagamento, ROU e passivo."},{"nome":"lease-disclosure-report","desc":"Agrega por lease_type: contagem, soma de pagamentos mensais, total de ROU e total de passivos."},{"nome":"lease-summary","desc":"Conta total de leases e distribui por lease_status e lease_type."}],"entradas":"--company-id (filtro opcional).","saidas":"JSON com report e rows[] (maturity/disclosure); summary traz total_leases, by_status{} e by_type{}.","regras":"disclosure usa COALESCE de ROU/passivo para '0' e agrupa por tipo; summary agrupa contagens por status e tipo; somente leitura.","efeitos":"Nenhum (somente leitura).","precondicoes":"Tabela advacct_lease existente (e advacct_lease_payment/advacct_amortization_entry para valores derivados)."},{"group":"Transações Intercompany","objetivo":"Gerenciar transações entre empresas do grupo (sale, purchase, service, loan, dividend, allocation) com fluxo de aprovação e postagem (draft → approved → posted).","acoes":[{"nome":"add-ic-transaction","desc":"Cria transação IC em 'draft' (naming ICT-) entre duas empresas distintas com tipo, valor e moeda."},{"nome":"update-ic-transaction","desc":"Atualiza descrição, valor, moeda, tipo e método de preço (só em draft/pending_approval)."},{"nome":"get-ic-transaction","desc":"Retorna uma transação IC pelo id."},{"nome":"list-ic-transactions","desc":"Lista paginada filtrando por empresa, from/to, tipo, ic_status e busca."},{"nome":"approve-ic-transaction","desc":"Move status para 'approved' (a partir de draft/pending_approval)."},{"nome":"post-ic-transaction","desc":"Move status para 'posted' e grava posted_date (apenas se 'approved')."}],"entradas":"--from-company-id, --to-company-id, --company-id, --transaction-type, --amount, --currency, --transfer-price-method; get/update/approve/post: --id.","saidas":"JSON com id, naming_series (ICT-), from_company_id, to_company_id, transaction_type, amount, ic_status; post retorna posted_date.","regras":"from e to devem existir e ser diferentes; transaction_type validado; amount Decimal >0; transfer_price_method (se informado) validado; ciclo: draft → approved → posted; update só em draft/pending_approval; approve só de draft/pending_approval; post só de approved; status eliminated alcançado fora deste fluxo direto.","efeitos":"Insere/atualiza em advacct_ic_transaction (post grava posted_date); grava auditoria; commit. 'posted' é apenas marcação de status — NÃO gera gl_entry real nas duas empresas.","precondicoes":"Três empresas válidas (from, to, company); tabela advacct_ic_transaction existente."},{"group":"Preços de Transferência (Transfer Pricing)","objetivo":"Cadastrar e listar regras de preço de transferência por método (cost_plus, resale_minus, comparable, other) e markup aplicáveis a transações intercompany.","acoes":[{"nome":"add-transfer-price-rule","desc":"Cria regra de transfer pricing com método, markup_pct, tipo de transação e vigência."},{"nome":"list-transfer-price-rules","desc":"Lista paginada filtrando por empresa, from/to e transaction_type."}],"entradas":"--company-id, --from-company-id, --to-company-id, --transaction-type, --method, --markup-pct, --effective-date, --expiry-date.","saidas":"JSON com id, method, markup_pct, transaction_type; list traz rows[], total_count, has_more.","regras":"method restrito a cost_plus/resale_minus/comparable/other (default cost_plus); transaction_type (se informado) validado; markup_pct default '0'; regra é cadastro de referência, não aplica automaticamente preço nas transações IC.","efeitos":"Insere em advacct_transfer_price_rule; grava auditoria; commit. Sem GL; não altera transações existentes.","precondicoes":"Empresa existente; tabela advacct_transfer_price_rule existente."},{"group":"Relatórios Intercompany","objetivo":"Fornecer relatórios de reconciliação e de eliminação das transações intercompany para conferência e preparação da consolidação.","acoes":[{"nome":"ic-reconciliation-report","desc":"Agrupa transações por from/to/tipo/status somando contagem e valor total."},{"nome":"ic-elimination-report","desc":"Lista transações 'posted' e soma o total a eliminar na consolidação."}],"entradas":"--company-id (filtro opcional).","saidas":"reconciliation: report e rows[] agrupados; elimination: rows[], total_to_eliminate e transaction_count.","regras":"elimination considera apenas ic_status='posted'; total_to_eliminate é a soma Decimal dos amounts; somente leitura.","efeitos":"Nenhum (somente leitura).","precondicoes":"Tabela advacct_ic_transaction existente com transações postadas (para o relatório de eliminação)."},{"group":"Grupos de Consolidação","objetivo":"Definir grupos de consolidação multi-entidade (controladora, moeda de consolidação) e cadastrar as entidades participantes com percentual de propriedade e método de consolidação.","acoes":[{"nome":"add-consolidation-group","desc":"Cria grupo de consolidação 'active' (naming CGRP-) com controladora e moeda de consolidação."},{"nome":"list-consolidation-groups","desc":"Lista paginada filtrando por empresa, group_status e busca por nome."},{"nome":"add-group-entity","desc":"Adiciona entidade ativa ao grupo com ownership_pct, moeda funcional e método (full/proportional/equity)."}],"entradas":"--company-id, --name, --parent-company-id, --consolidation-currency; add-group-entity: --group-id, --entity-company-id, --entity-name, --ownership-pct, --functional-currency, --consolidation-method.","saidas":"JSON com id, naming_series (CGRP-), name, group_status (grupo); add-group-entity retorna id, group_id, entity_company_id, entity_name, ownership_pct, consolidation_method.","regras":"name obrigatório; group_status default 'active' (válidos active/inactive); consolidation_method validado contra full/proportional/equity (default full); ownership_pct default '100'; moeda de consolidação/funcional default 'USD'; entidade criada com is_active=1.","efeitos":"Insere em advacct_consolidation_group e advacct_group_entity; grava auditoria; commit. Sem GL.","precondicoes":"Empresa existente; para add-group-entity, grupo de consolidação já criado."},{"group":"Execução de Consolidação","objetivo":"Executar a consolidação de um grupo em uma data-base e gerar lançamentos de eliminação (eliminações intercompany e ajustes de conversão cambial).","acoes":[{"nome":"run-consolidation","desc":"Executa consolidação do grupo numa data, lista entidades ativas e marca a execução como concluída."},{"nome":"generate-elimination-entries","desc":"Cria lançamentos de eliminação para IC transactions 'posted' entre entidades do grupo (débito IC Revenue, crédito IC Expense)."},{"nome":"add-currency-translation","desc":"Cria lançamento de ajuste de conversão cambial (CTA) do tipo currency_translation."}],"entradas":"--group-id, --period-date; generate/add-currency: --company-id; add-currency-translation: --amount, --debit-account, --credit-account, --description.","saidas":"run-consolidation: group_id, group_name, period_date, entity_count, entities[] e consolidation_run='completed'; generate: entries_created; add-currency: id, group_id, amount, entry_type.","regras":"run exige período e ao menos uma entidade ativa; generate exige período, empresa e >=2 entidades ativas, eliminando IC transactions 'posted' com from e to dentro do grupo; entry_type fixo 'ic_elimination' (generate) ou 'currency_translation'; contas padrão 'IC Revenue'/'IC Expense' e 'CTA - Debit'/'CTA - Credit'.","efeitos":"generate-elimination-entries e add-currency-translation INSEREM em advacct_elimination_entry; run-consolidation NÃO grava lançamentos (apenas audita a execução). Todas gravam auditoria e commit. Eliminações ficam em tabela própria — NÃO postam em gl_entry; não alteram o ic_status das transações (não vira 'eliminated').","precondicoes":"Grupo de consolidação com entidades ativas (>=2 para eliminação); transações IC 'posted' entre as entidades; empresa válida."},{"group":"Relatórios de Consolidação","objetivo":"Apresentar o balancete consolidado (trial balance) com entidades e eliminações, e o resumo do grupo com totais de eliminações por tipo.","acoes":[{"nome":"consolidation-trial-balance-report","desc":"Lista entidades ativas e lançamentos de eliminação do grupo (filtráveis por período) somando o total eliminado."},{"nome":"consolidation-summary","desc":"Resume o grupo: contagem de entidades, de eliminações e eliminações agrupadas por entry_type com totais."}],"entradas":"--group-id; trial-balance: --period-date (opcional).","saidas":"trial-balance: group_name, period_date, entities[], elimination_entries[], total_eliminations, entity_count; summary: entity_count, elimination_count, eliminations_by_type{} com count e total.","regras":"ambos validam existência do grupo; trial-balance filtra eliminações por period_date quando informado; totais somados em Decimal e arredondados a 0.01; somente leitura.","efeitos":"Nenhum (somente leitura).","precondicoes":"Grupo de consolidação existente; idealmente entidades e lançamentos de eliminação já cadastrados."},{"group":"Conformidade / Status","objetivo":"Fornecer um painel de conformidade às normas (ASC 606/842, intercompany, consolidação) e o status técnico do módulo com contagem de registros.","acoes":[{"nome":"standards-compliance-dashboard","desc":"Painel com contadores: contratos e obrigações não satisfeitas (606), leases ativos e sem ROU (842), IC não postadas e grupos ativos."},{"nome":"status","desc":"Retorna skill, versão e contagem de registros de todas as 12 tabelas do módulo."}],"entradas":"--company-id (filtro opcional, apenas no dashboard).","saidas":"dashboard: report e blocos asc_606, asc_842, intercompany, consolidation com contadores; status: skill, version (1.0.0), total_tables (12) e record_counts{} por tabela.","regras":"dashboard sinaliza pendências (obrigações != satisfied, leases não-draft sem rou_asset_value, IC fora de posted/eliminated); status tolera tabela ausente retornando contagem 0; somente leitura.","efeitos":"Nenhum (somente leitura).","precondicoes":"Banco inicializado; tabelas do módulo idealmente criadas (status funciona mesmo sem elas, retornando 0)."}]},"meta":{"module":"meta","display":"Meta / Transversal","functionalities":[{"group":"Verificação de Instalação","objetivo":"Diagnostica o estado da instalação do ERPClaw: quais skills estão instaladas, qual a versão de cada uma, se o banco existe e se as tabelas esperadas de cada skill estão presentes. Serve de ponto de entrada padrão (sem dependências além da stdlib).","acoes":[{"nome":"check-installation","desc":"Varre ~/clawd/skills procurando diretórios erpclaw-*/webclaw com SKILL.md, lê a versão do frontmatter YAML, confere as tabelas esperadas de cada skill (mapa SKILL_TABLES) contra as tabelas existentes no banco e verifica a presença da biblioteca compartilhada."}],"entradas":"--action check-installation; --db-path (opcional, padrão ~/.openclaw/erpclaw/data.sqlite).","saidas":"JSON com status, total_skills_available, installed_skills (lista com name/version/tables_ok), installed_count, missing_skills, missing_count, database_exists, database_tables (contagem), company_count, shared_library_installed, db_path e skills_dir.","regras":"Itera sobre ALL_SKILLS (29 skills) classificando cada uma como instalada (diretório com SKILL.md presente) ou ausente. tables_ok é True quando todas as tabelas representativas da skill existem no banco, ou True por padrão para skills sem tabelas próprias (ex.: reports, regionais, webclaw). Versão extraída por regex do bloco frontmatter, sem biblioteca YAML. Se o banco estiver corrompido/bloqueado, reporta o que conseguir sem falhar.","efeitos":"nenhum (somente leitura). Apenas SELECT em sqlite_master e contagem da tabela company; nenhuma postagem em GL/gl_entry, SLE ou mudança de status.","precondicoes":"Nenhuma obrigatória — funciona mesmo sem banco, sem skills e sem a lib compartilhada (PyPika é opcional). Para contar empresas e validar tabelas, o banco precisa existir em --db-path."},{"group":"Guia de Onboarding","objetivo":"Recomenda a próxima etapa de instalação com base no estado atual, organizando as 29 skills em tiers (Foundation, Core Accounting, Supply Chain, Operations, Extended, Regional, Integrations, Web Dashboard) e indicando o comando clawhub install a executar.","acoes":[{"nome":"install-guide","desc":"Calcula o status de cada tier (complete/partial/not_started) a partir das skills instaladas, identifica o primeiro tier incompleto, monta a recomendação e o comando de instalação correspondente, além do percentual de progresso."}],"entradas":"--action install-guide; --db-path (opcional, padrão ~/.openclaw/erpclaw/data.sqlite).","saidas":"JSON com status, current_tier, next_recommendation (texto), install_command (comando clawhub sugerido), progress ('X of Y skills installed (Z%)'), database_exists, company_count e tiers (lista com name/skills/installed/missing/status/install_cmd).","regras":"Tier é 'complete' se nada falta, 'not_started' se nada instalado, 'partial' caso intermediário. Se nada instalado, recomenda Tier 1 (Foundation). Se há tiers incompletos, recomenda o primeiro: quando 'partial', sugere instalar apenas as skills faltantes (clawhub install <faltantes>); quando 'not_started', sugere o install_cmd completo do tier. Se tudo instalado, retorna 'All tiers complete' sem comando.","efeitos":"nenhum (somente leitura). Lê apenas existência do banco e contagem de empresas via get_db_info; nenhuma escrita.","precondicoes":"Nenhuma obrigatória. Os diretórios das skills são lidos de ~/clawd/skills e o banco de --db-path apenas para enriquecer a saída (database_exists/company_count)."},{"group":"Geração de Dados de Demo","objetivo":"Popula um conjunto completo de dados de demonstração ponta a ponta para uma empresa, orquestrando subprocessos das demais skills, de modo a permitir testar relatórios e fluxos com lançamentos reais. Idempotente por empresa.","acoes":[{"nome":"seed-demo-data","desc":"Cria/usa uma empresa e semeia em fases: defaults, plano de contas US GAAP, anos fiscais 2025/2026, naming series, centros de custo, 3 armazéns, 25 itens (15 RAW + 10 FG), 10 clientes, 8 fornecedores, estoque inicial, 5 lançamentos contábeis, 5 SO+SI, 3 PO+PR+PI, 5 pagamentos, 3 BOMs + 2 ordens de produção, RH/folha, CRM, ativos, suporte e projetos."}],"entradas":"--action seed-demo-data; --db-path (opcional); --company-id (opcional — usa empresa existente em vez de criar 'Stark Manufacturing Inc.'). Demais flags são fixas no código (USD, United States, datas 2025/2026).","saidas":"JSON com status ('ok' se sem erros, 'partial' se houve falhas), message, company_id e summary (contagens por entidade: customers, suppliers, items, warehouses, stock_entries, journal_entries, sales/purchase orders+invoices, payments, boms, work_orders, employees, leads, assets, etc.). Em falhas parciais inclui errors[] e error_count.","regras":"Idempotente: se a empresa-alvo já existe e tem clientes (customer_count>0), retorna sem semear novamente. Com --company-id inexistente, retorna erro. Sem --company-id, procura 'Stark Manufacturing Inc%'; em caso de falha na criação, faz fallback para a empresa mais antiga existente. Documentos transacionais seguem o ciclo create→submit (estoque, JE, SO/SI, PO/PR/PI, pagamentos são submetidos). Cada passo é resiliente: duplicatas (UNIQUE) são puladas com lookup do registro existente, e erros isolados não abortam o lote — são acumulados em errors[].","efeitos":"EFEITOS REAIS extensos via subprocessos das skills: submete stock entries (gera stock_ledger_entry / SLE de estoque inicial), submete journal entries, sales invoices e purchase invoices (geram gl_entry no Razão), submete pagamentos (gera payment_ledger_entry e quitação de faturas via allocations), cria/altera status de documentos (SO/PO/PR submetidos), além de mestres (empresa, contas, itens, clientes/fornecedores) e dados de RH/folha/CRM/ativos/suporte/projetos. Auditoria é registrada pelas próprias skills chamadas.","precondicoes":"As skills referenciadas precisam estar instaladas (setup, gl, inventory, selling, buying, journals, payments, manufacturing, hr, payroll, crm, assets, support, projects) — caso contrário o passo correspondente falha e entra em errors[]. Requer a lib compartilhada/PyPika para as consultas de idempotência e lookup de contas. Depende do plano de contas US GAAP (números de conta como 1111, 1121, 4110, 5110) para mapear os IDs usados nos lançamentos."},{"group":"Setup Web Dashboard","objetivo":"Ponto de configuração do dashboard web. Nesta versão a ação foi removida desta skill de fundação e movida para o addon externo erpclaw-os-engine; o código aqui apenas devolve um erro estruturado de migração.","acoes":[{"nome":"setup-web-dashboard","desc":"Stub de migração (_setup_web_dashboard_moved_stub): retorna JSON de erro informando que a ação foi renomeada para 'os-setup-web-dashboard' no addon erpclaw-os-engine e sai com código 1. Não executa nenhum trabalho."}],"entradas":"--action setup-web-dashboard; flags ainda declaradas no parser mas não utilizadas pelo stub: --domain, --ssl/--no-ssl, --skip-build, --db-path.","saidas":"JSON de erro com status='error', error (mensagem de migração), missing_addon='erpclaw-os-engine', old_action='setup-web-dashboard', new_action='os-setup-web-dashboard', note (esclarece que o addon é tooling externo não empacotado neste fork air-gapped) e since_version='4.0.0'. Encerra com exit 1.","regras":"Sempre retorna o mesmo erro de migração, independentemente das flags. A implementação original (clone do erpclaw-web, npm install/build, venv da API, deploy/setup.sh, configuração de nginx + Let's Encrypt com sudo) foi removida por ter sido sinalizada como alto risco (VirusTotal Code Insight) e isolada no addon opcional, conforme o plano CLAWHUB_FIX_C_PLAN_2026-05-04 D6.","efeitos":"nenhum (somente retorna erro). Não clona repositório, não roda npm/build, não cria venv, não executa setup.sh e não toca em nginx/SSL nesta versão — todos esses efeitos foram deslocados para o addon externo.","precondicoes":"Nenhuma. Para de fato configurar o dashboard seria necessário instalar o addon externo erpclaw-os-engine e invocar 'os-setup-web-dashboard', que não está empacotado neste fork."}]},"os":{"module":"os","display":"OS / Runtime (Fundação ERPClaw)","functionalities":[{"group":"Validação contra a Constituição","objetivo":"Valida um módulo contra a Constituição do ERPClaw (21 artigos), combinando análise estática (artigos 1-8, 10-12, 19-21) e execução de testes em sandbox (artigo 9), para garantir conformidade antes de instalar/operar o módulo.","acoes":[{"nome":"validate-module","desc":"Roteia a validação de um módulo; conforme --validation-type executa estática, runtime ou ambas (full) e mede duration_ms."},{"nome":"validate_module_static","desc":"Roda os 14 checadores estáticos de artigo (prefixo de tabela, Money=TEXT, PK UUID, FKs, no cross-module/GL writes, formato de resposta, testes existem, security scan, SKILL.md, naming, escopo de modificação, proveniência, isolamento de feature) e agrega pass/fail."},{"nome":"validate_module_runtime","desc":"Executa pytest no diretório tests/ do módulo (subprocess, timeout 120s) e parseia a contagem de passed/failed para validar o artigo 9 (Tests Pass)."}],"entradas":"--module-path (obrigatório, diretório do módulo); --validation-type (static|runtime|full, default full); --db-path (opcional, banco de teste exportado como ERPCLAW_DB_PATH para o pytest).","saidas":"JSON via ok() com result (pass|fail), module_name, module_path, articles (mapa número->pass/fail/skip), violations[], skipped[], validation_type e duration_ms. No modo full inclui bloco runtime{} e fixa articles[9] como pass/fail. O runtime traz tests_run/passed/failed e output (últimos 2000 chars).","regras":"Estática cobre artigos 1-8,10-12,19-21; runtime cobre o 9. Resultado geral é fail se qualquer artigo crítico falhar. Checadores retornam skip quando faltam init_db.py/scripts/SKILL.md ou quando é módulo core. severity e bypass_policy (never/tier2/tier3) são metadados informativos — não há lógica de bypass no runtime. Caminho inexistente gera err.","efeitos":"Estática é somente leitura (lê init_db.py, SKILL.md, .py via AST e regex). Runtime tem efeito colateral real: dispara subprocess pytest que executa os testes do módulo; se --db-path for informado, os testes podem escrever nesse banco de teste (ERPCLAW_DB_PATH). Não posta em gl_entry nem stock_ledger_entry diretamente.","precondicoes":"Diretório do módulo existente com init_db.py e/ou SKILL.md; para runtime, diretório tests/ com testes pytest e pytest instalado. src_root é auto-detectado (pasta source/) para registro de propriedade de tabelas usado nos artigos 4 e 5."},{"group":"Artigos","objetivo":"Expõe os 21 artigos da Constituição (regras de conformidade dos módulos) para consulta, com filtro por tipo de enforcement (estático vs runtime).","acoes":[{"nome":"list-articles","desc":"Lista os artigos da Constituição; com --article-type filtra entre todos, somente estáticos (1-8,10-12,19-21) ou somente runtime (9,13-18)."},{"nome":"get_static_articles","desc":"Retorna apenas os artigos com enforcement='static'."},{"nome":"get_runtime_articles","desc":"Retorna apenas os artigos com enforcement='runtime'."}],"entradas":"--article-type (all|static|runtime, default all).","saidas":"JSON via ok() com articles[] (cada um: number, name, description, enforcement, severity, bypass_policy) e count.","regras":"Os artigos são uma constante estática (ARTICLES) definida em constitution.py. static = artigos verificados por análise; runtime = artigos 13-18 enforçados por triggers/APIs de banco mais o 9 (testes em sandbox). bypass_policy assume never/tier2/tier3 conforme o artigo.","efeitos":"Nenhum (somente leitura).","precondicoes":"Nenhuma — não depende de banco, empresa ou módulo."},{"group":"Registro de Tabelas","objetivo":"Constrói o registro de propriedade de tabelas (qual módulo é dono de cada tabela) varrendo os init_db.py de todos os módulos e o init_schema.py do core, base para as regras anti cross-module/GL writes.","acoes":[{"nome":"build-table-registry","desc":"Constrói e exibe o registro de propriedade, agrupando as tabelas por módulo para leitura."},{"nome":"build_table_ownership_registry","desc":"Varre init_schema.py do core (dono='erpclaw') e todos os init_db.py sob src_root, extraindo nomes de tabela via regex e mapeando tabela->módulo (nome derivado do diretório)."}],"entradas":"--src-root (obrigatório, raiz source/ contendo os módulos).","saidas":"JSON via ok() com total_tables, total_modules, registry (mapa tabela->módulo) e by_module (mapa módulo->lista de tabelas).","regras":"Tabelas do core ficam atribuídas a 'erpclaw' (via erpclaw/scripts/erpclaw-setup/init_schema.py). Para os demais módulos, o dono é o nome derivado do diretório do init_db.py. Diretórios __pycache__/.git são ignorados e o init_schema do core não é recontado. Caminho inexistente gera err.","efeitos":"Nenhum (somente leitura de arquivos do filesystem).","precondicoes":"src_root existente apontando para a árvore source/ com os módulos e, idealmente, o init_schema.py do core para mapear as tabelas centrais."},{"group":"Plano de Migração","objetivo":"Gera um plano de migração de schema (padrão Infrastructure-as-Code) comparando o init_db.py declarado de um módulo com o banco vivo, validando o módulo e registrando a migração como 'planned'.","acoes":[{"nome":"schema-plan","desc":"Handler CLI que invoca plan_migration e anexa duration_ms ao resultado."},{"nome":"plan_migration","desc":"Faz o diff (diff_schema), checa conflitos cross-module, gera DDL só para novas tabelas (generate_create_ddl), roda validação estática e insere o registro de migração."},{"nome":"diff_schema","desc":"Compara o schema vivo (sqlite_master/PRAGMA) com o declarado, retornando new_tables, dropped_tables, new_columns, dropped_columns, type_changes e matching_tables."},{"nome":"ensure_migration_table","desc":"Cria a tabela erpclaw_schema_migration se não existir (efeito DDL idempotente)."}],"entradas":"--module-path (obrigatório, contém init_db.py); --db-path (opcional, default ~/.openclaw/erpclaw/data.sqlite); --src-root (opcional, para checagem de propriedade/conflitos).","saidas":"dict com result (planned|no_changes|blocked|error), migration_id, module_name, new_tables, new_columns, ddl_count, ddl_statements, validation_passed/validation_result e duration_ms.","regras":"Só new_tables e new_columns são acionáveis; dropped_tables são ignoradas (tabelas da fundação não declaradas). A IA pode CRIAR tabelas mas nunca ALTER/DROP de tabelas de outro módulo — havendo src_root, conflitos de propriedade retornam result='blocked'. Ciclo de vida inicia em status 'planned'. Sem mudanças acionáveis retorna 'no_changes'. Sem init_db.py retorna error.","efeitos":"Efeito colateral real no banco: cria a tabela erpclaw_schema_migration (se ausente) e INSERE uma linha com status 'planned', guardando ddl_statements e o snapshot do schema anterior (previous_schema). Não cria as tabelas-alvo ainda, não posta em GL nem em SLE.","precondicoes":"Banco SQLite acessível; módulo com init_db.py válido; para detectar conflitos cross-module, src_root com o registro de propriedade de tabelas."},{"group":"Aplicar/Reverter Migrações","objetivo":"Aplica uma migração planejada executando o DDL dentro de uma transação, ou reverte uma migração aplicada removendo as tabelas criadas após salvar backup dos dados; ambos atualizam o status no registro de migração.","acoes":[{"nome":"schema-apply","desc":"Handler CLI que invoca apply_migration por migration_id e anexa duration_ms."},{"nome":"apply_migration","desc":"Carrega a migração 'planned', executa os DDL em uma transação, rastreia as tabelas criadas e atualiza o status para 'applied' (ou 'failed' em erro de SQL)."},{"nome":"schema-rollback","desc":"Handler CLI que invoca rollback_migration por migration_id e anexa duration_ms."},{"nome":"rollback_migration","desc":"Para migrações tipo 'create', faz backup das linhas em tabelas _backup, dá DROP nas tabelas criadas e atualiza o status para 'rolled_back'."}],"entradas":"--migration-id (obrigatório, UUID da migração); --db-path (opcional, default ~/.openclaw/erpclaw/data.sqlite); applied_by (opcional na função, default 'system').","saidas":"apply: dict com result (applied|error), migration_id, module_name, tables_created[], ddl_executed, duration_ms. rollback: dict com result (rolled_back|error), tables_dropped[], backups_created[] (original, backup, rows), duration_ms.","regras":"apply exige status 'planned' (senão erro); falha de DDL faz rollback da transação e marca status 'failed'. rollback exige status 'applied'; só trata migration_type='create'. Backup só é gerado para tabelas com linhas (row_count>0), nomeado tabela_backup_<8charsId>. Ciclo de vida: planned -> applied -> rolled_back, ou planned -> failed.","efeitos":"Efeitos colaterais reais de DDL: apply executa CREATE TABLE/INDEX e altera o status da linha em erpclaw_schema_migration. rollback cria tabelas _backup (CREATE TABLE AS SELECT), executa DROP TABLE das tabelas criadas e muda o status. Tudo dentro de transação. Não posta diretamente em gl_entry/stock_ledger_entry; o impacto é estrutural no schema.","precondicoes":"Banco acessível com a tabela erpclaw_schema_migration e uma migração no status correto (planned para apply, applied para rollback). O DDL armazenado deve ser válido."},{"group":"Detecção de Drift","objetivo":"Detecta drift de schema — modificações manuais no banco que divergem do schema declarado no init_db.py do módulo — listando tabelas/colunas/tipos fora de sincronia, sem alterar nada.","acoes":[{"nome":"schema-drift","desc":"Handler CLI que chama detect_drift e monta o resultado com contagem e duração."},{"nome":"detect_drift","desc":"Faz o diff entre banco e init_db.py e classifica as divergências em extra_table, missing_column, extra_column e type_mismatch."}],"entradas":"--module-path (obrigatório, contém init_db.py); --db-path (opcional, default ~/.openclaw/erpclaw/data.sqlite).","saidas":"dict com result (drift_detected|no_drift), findings[] (type, table, column quando aplicável, details), finding_count, module_path e duration_ms.","regras":"Tabelas presentes no banco mas ausentes no init_db.py só viram finding (extra_table) se usarem o prefixo do módulo (derivado do nome do diretório), evitando falsos positivos de outros módulos. Colunas declaradas e ausentes = missing_column; colunas extras no banco = extra_column; diferença de tipo = type_mismatch. Sem init_db.py retorna lista vazia (no_drift).","efeitos":"Nenhum (somente leitura: consulta sqlite_master/PRAGMA e lê init_db.py; não escreve no banco).","precondicoes":"Banco SQLite acessível e módulo com init_db.py para servir de schema declarado de referência."}]}};
